INSERT INTO Category VALUES('cmotsbfyf0015gnmm84gw192b','asset_type','ast-20260506-7928-dwdq','Nhà cửa, vật kiến trúc','#6366f1','bi-building','Là tài sản cố định của doanh nghiệp được hình thành sau quá trình thi công xây dựng như: Trụ sở làm việc, nhà kho, hàng rào, tháp nước, sân bãi, các công trình trang trí cho nhà cửa, đường xá, cầu cống, đường sắt, đường băng sân bay, cầu tàu, cầu cảng, ụ triền đà (ụ để phục vụ việc hạ thủy tàu).',3,1,NULL,'cmnfv9wvn00bd8okb7uzfg7k3',1778055468424,1780658899171);
