INSERT INTO InventoryItem VALUES('cmoiqcoxj00i0i47puu0iaqcj','SJ-BC-TL0111S','Bồn cầu thông minh đa chức năng SJ-TL0111S','hang-hoa','Seajong','TL0111S','','','cmoiqcoxc00hji47p30jfpai5','cái',0.0,0.0,0.0,24600000.0,NULL,'Đặc điểm nổi bật Bồn cầu thông minh full chức năng SJ-TL0111F được thiết kế kiểu dáng hiện đại, sang trọng và tinh tế. Với những đường nét thẳng khỏe khoắn kết hợp viền bo tròn mềm mại, đem lại cho không gian phòng tắm nhà bạn thêm phần hiện đại và thanh lịch. Thiết kế thông minh: tối giản những góc cạnh, giúp dễ dàng vệ sinh. Hệ thống xả tự động tiết kiệm nước, thân thiện với môi trường Ứng dụng công nghệ Eco-X hai cửa xả xoáy siêu sạch, cuốn trôi mọi vết bẩn Công nghệ tráng men sứ cao cấp giúp ngăn chặn hình thành có vệt ố vàng và giữ cho bồn cầu luôn sáng bóng Chiều cao phù hợp với đa số người dùng Việt Hệ thống tự động hoàn toàn giúp người dùng không phải động tay Hệ thống làm sạch, khử khuẩn, hút mùi tự động giúp cho không gian phòng luôn thơm tho, sạch sẽ. Mô tả chức năng thông minh Cảm biến tự động đóng/mở nắp bồn cầu khi người dùng đến gần Sưởi ấm bệ ngồi ngay tức khắc Diệt khuẩn bằng tia cực tím Xả nước tự động Vòi phun nước với 3 chế độ làm sạch: làm sạch phía sau, làm sạch dành cho phụ nữ và làm sạch vùng nhạy cảm Màn hình hiển thị hiện đại rõ ràng nội dung tiện lợi sử dụng Vật liệu chống cháy. Điều khiển bồn cầu từ xa Tích hợp nút vặn xả trong trường hợp mất điện Tự động khử trùng vòi rửa, tráng bề mặt trước và sau khi sử dụng, hạn chế việc lây nhiễm chéo các bệnh truyền nhiễm Tấm chắn bọt chống bắn, hạn chế vi khuẩn trong khi sử dụng Tự động điều chỉnh nhiệt độ gió sấy. Nút thao tác vặn chỉnh tốc độ vòi phun làm sạch Chống rò rỉ điện Cơ chế lọc, khử mùi kép tự động Ánh sáng ban đêm, hỗ trợ người già đi vệ sinh Lớp men sứ cao cấp dễ dàng làm sạch Công nghệ chống nước IPX4 theo tiêu chuẩn Hoa Kỳ Tiết kiệm nước tối đa','het-hang',3881,NULL,NULL,1777387039543,1782621407354,'https://seajong.com/wp-content/uploads/2024/03/TL0111S.webp',NULL,