INSERT INTO InventoryItem VALUES('cmoiqef7b00nqi47po3kk2xhj','SJ-TL-TL8050SUMG-TỦ-MÀU-15331','Tủ lavabo Seajong Flutter Ruby SJ-TL8050SUMG-WD80','hang-hoa','Seajong','TL8050SUMG','Tủ lavabo mặt sứ kết hợp máy giặt mini','Màu trắng','cmoit63u3001di4nul0lbrqko','cái',0.0,0.0,0.0,38500000.0,NULL,'Phong cách nội thất phù hợp Với màu trắng sang trọng và thiết kế gọn gàng, SJ-TL8050SUMG-WD80 dễ dàng kết hợp với nhiều phong cách: Phong cách Modernism: Mang lại cảm giác sang trọng và tiện nghi Phong cách Minimalism: Giữ sự gọn gàng, tinh tế và hài hòa Phong cách Bắc Âu: Tạo không gian thanh thoát, ấm áp và trang nhã Phong cách Hàn Quốc: tạo không gian tươi mới, quý phái. Liên hệ mua hàng chính hãng tại Seajong – Thương hiệu thiết bị vệ sinh và nhà bếp cao cấp, cam kết mang đến sản phẩm chất lượng cùng dịch vụ tư vấn và chăm sóc khách hàng chuyên nghiệp.','het-hang',15331,NULL,NULL,1777387120247,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-TL8050SUMG-WD80.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef7e00nui47pghm4ai96','SJ-TL-TL6050SUV-MÀU','Tủ lavabo phòng tắm SJ-TL6050SUV2-GD06','hang-hoa','Seajong','TL6050SUV','','Màu xám titan','cmoit63u3001di4nul0lbrqko','cái',0.0,0.0,0.0,17000000.0,NULL,'Mục Lục Toggle Tuyệt Tác Không Gian Tủ Lavabo Phòng Tắm SJ-TL6050SUV2-GD06 Nhôm Nguyên Khối 1. Kỷ Nguyên Mới Của tủ chậu rửa mặt Và bộ tủ chậu Từ Nhôm Nguyên Khối 2. Công Nghệ PVD Đỉnh Cao Trên tủ nhôm phòng tắm Và tủ lavabo nhôm 3. Hệ Thống Điện Tử Tiên Tiến Cho tủ chậu cao cấp Và tủ bồn rửa 4. Phụ Kiện bồn rửa tay Và chậu rửa mặt Tiêu Chuẩn Châu Á 5. Cam Kết Chất Lượng tủ vệ sinh Và chậu lavabo Từ Nhà Sản Xuất Tuyệt Tác Không Gian Tủ Lavabo Phòng Tắm SJ-TL6050SUV2-GD06 Nhôm Nguyên Khối Chào quý vị, dưới góc nhìn của một kỹ sư và chuyên gia tư vấn thiết bị vệ sinh cao cấp với nhiều năm kinh nghiệm, tôi nhận thấy điểm yếu cốt tử của không gian phòng tắm chính là độ ẩm bão hòa phá hủy kết cấu nội thất. Sự chuyển dịch từ vật liệu gỗ công nghiệp sang kim loại là xu thế tất yếu. Hôm nay, chúng ta sẽ cùng bóc tách các đặc tính kỹ thuật vượt trội của siêu phẩm tủ lavabo phòng tắm SJ-TL6050SUV2-GD06. Đây là hệ sinh thái lưu trữ hoàn mỹ, đánh dấu bước đột phá ngoạn mục của thương hiệu Seajong trong công nghệ chế tác hợp kim nhôm. 1. Kỷ Nguyên Mới Của tủ chậu rửa mặt Và bộ tủ chậu Từ Nhôm Nguyên Khối Để tạo ra một tủ lavabo nhôm nguyên khối đúng nghĩa, vật liệu đầu vào quyết định 80% chất lượng. Khác biệt hoàn toàn với các dòng sản phẩm pha tạp trên thị trường, tủ lavabo phòng tắm SJ-TL6050SUV2-GD06 được đúc ép từ nhôm nguyên chất lên tới 95%. Với độ dày phôi nhôm đạt chuẩn 1.2mm, sản phẩm mang lại kết cấu cơ học cực kỳ vững chắc, chống chịu lực va đập biến dạng hoàn hảo. Đây là nền tảng tối quan trọng để tạo nên một thiết kế tủ chậu phòng tắm có khả năng nâng đỡ mặt đá và hệ thống sứ vệ sinh nặng nề phía trên mà không bị xệ cánh hay võng lún theo thời gian. 2. Công Nghệ PVD Đỉnh Cao Trên tủ nhôm phòng tắm Và tủ lavabo nhôm Trong ngành luyện kim, PVD (Physical Vapor Deposition) là công nghệ mạ chân không tiên tiến bậc nhất. Bề mặt của tủ lavabo phòng tắm SJ-TL6050SUV2-GD06 được xử lý qua buồng mạ PVD, tạo ra lớp màng bảo vệ siêu cứng. Công nghệ này giúp chiếc bộ tủ chậu rửa ','het-hang',12938,NULL,NULL,1777387120250,1782621407354,'https://seajong.com/wp-content/uploads/2025/07/SJ-TL6050SUV1-GD06-1-1.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef7y00obi47pj3etoibj','SJ-PK-PK0005D-CHR','Mắc áo 5 móc tròn cao cấp Seajong SJ-PK0005D-SR','hang-hoa','Seajong','PK0005D','','Chrome','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,960000.0,NULL,'Mắc áo 5 móc tròn cao cấp Seajong SJ-PK0005D-SR được thiết kế dành cho những ai mong muốn sự tiện lợi, bền chắc và thẩm mỹ trong sinh hoạt hằng ngày. Với kích thước 370x35x25mm, sản phẩm có thiết kế nhỏ gọn nhưng vẫn cung cấp không gian treo rộng rãi, giúp người dùng sắp xếp đồ dùng một cách ngăn nắp. Đặc biệt, khả năng chịu tải đến 20kg mang lại sự yên tâm khi treo nhiều vật dụng cùng lúc. Mục Lục Toggle Mắc áo 5 móc Seajong chất liệu là gì? Công nghệ Seajong ứng dụng vào sản phẩm là gì? Tạm kết Mắc áo 5 móc Seajong chất liệu là gì? Toàn bộ sản phẩm được chế tác từ Inox SUS304 cao cấp, nổi tiếng với độ bền chắc, khả năng chống gỉ sét và chống ăn mòn vượt trội. Nhờ chất liệu này, mắc áo Seajong không chỉ duy trì được sự chắc chắn trong môi trường ẩm ướt như phòng tắm mà còn giữ được vẻ sáng bóng lâu dài. Đây là yếu tố quan trọng giúp sản phẩm luôn bền đẹp và an toàn khi sử dụng lâu năm. Công nghệ Seajong ứng dụng vào sản phẩm là gì? Điểm nổi bật của SJ-PK0005D-SR là được xử lý bằng công nghệ Đánh bóng Laser (Laser Polishing), mang đến bề mặt sáng bóng, nhẵn mịn và tinh tế. Bề mặt này hạn chế bám bẩn, dễ lau chùi, giúp sản phẩm luôn sạch đẹp và góp phần nâng tầm thẩm mỹ cho không gian sống. Sản phẩm được hoàn thiện bằng công nghệ Hàn không dấu vết, giúp các mối nối liền mạch, chắc chắn mà không để lộ khuyết điểm. Kỹ thuật này vừa tăng độ bền vừa đảm bảo tính thẩm mỹ, mang đến cho người dùng một phụ kiện hoàn thiện cả về công năng lẫn thiết kế. Thiết kế 5 móc tròn chắc chắn giúp người dùng treo nhiều vật dụng khác nhau như áo khoác, khăn tắm, túi xách hay phụ kiện gia đình. Sự đa dạng và tiện ích này giúp không gian trở nên gọn gàng, ngăn nắp, đồng thời mang đến sự tiện lợi trong sinh hoạt hằng ngày. Trong xu hướng nội thất hiện đại, những chi tiết nhỏ gọn nhưng đa năng ngày càng được ưu tiên. Mắc áo 5 móc tròn Seajong không chỉ là vật dụng treo đồ đơn thuần mà còn là điểm nhấn tinh tế, dễ dàng hòa hợp với nhiều không gian: phòng tắm, phòng ngủ, phòng thay đồ hay ban ','het-hang',13807,NULL,NULL,1777387120270,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/SJ-PK0005D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8000ofi47p38sj8jqt','SJ-SC-SA0171-MẠ','Sen cây âm tường Smart hiển thị nhiệt độ cao cấp SJ-SA0171','hang-hoa','Seajong','SA0171','','mạ PVD & mạ Chrome','cmoiqcoxb00hgi47pryg6n57p','cái',0.0,0.0,0.0,57500000.0,NULL,'Sen cây âm tường Smart hiển thị nhiệt độ cao cấp SJ-SA0171 là mẫu sản phẩm mang chất liệu cao cấp đồng thau 61A, mang lại vẻ đẹp tinh tế, sang trọng cho phòng tắm của bạn. Với trải nghiệm tắm ổn định cùng các tính năng tiện lợi, sản phẩm này sẽ mang lại cho quý khách sự thư giãn tuyệt hảo. Hiện Seajong có 2 mẫu: *Mẫu 1: Sen cây âm tường Smart hiển thị nhiệt độ mạ PVD cao cấp SJ-SA0171-GR *Mẫu 2: Sen cây âm tường Smart hiển thị nhiệt độ mạ Chrome cao cấp SJ-SA0171-SR Mục Lục Toggle Công nghệ & Tính năng nổi bật Bộ sản phẩm bao gồm Các câu hỏi thường gặp Tại sao nên chọn sen cây âm trần SJ-SA0212 tại Seajong? Công nghệ & Tính năng nổi bật Hiển thị nhiệt độ thời gian thực: Công nghệ thông minh giúp bạn dễ dàng theo dõi nhiệt độ nước trong suốt quá trình sử dụng, tránh tình trạng nước quá nóng hoặc quá lạnh, bảo vệ an toàn cho người sử dụng. – Bát sen vuông phun thác nước: Tính năng phun thác nước độc đáo mang lại cảm giác thư giãn như tắm dưới thác nước, giúp làm sạch cơ thể hiệu quả. – Tay sen mạnh mẽ: Tay sen có một chế độ phun nước cực mạnh, phù hợp cho những người muốn có trải nghiệm tắm xả mạnh mẽ. – Van điều chỉnh đa chức năng: Điều chỉnh dễ dàng âm lượng nước và chuyển đổi giữa chế độ tắm thác nước và tay sen, giúp bạn thay đổi theo nhu cầu sử dụng. – Công nghệ mạ 5 lớp: Bao gồm đồng, nikel và chrome (hoặc mạ PVD xám), giúp tăng cường độ bền, khả năng chống oxy hóa, trầy xước và giữ cho bề mặt luôn sáng bóng. Bộ sản phẩm bao gồm Thân sen chính Nắp trang trí thân sen Nắp trang trí cần sen trần Cần cấp nước cho bát sen trần Bát sen trần Tay sen Dây dẫn Cút nước chịu nhiệt Cài tay sen nhỏ Các câu hỏi thường gặp 1. Sản phẩm có lắp được cho mọi loại tường không? Không. Sản phẩm chỉ phù hợp lắp trên tường gạch, bê tông. Tường giả như thạch cao không đủ tải trọng. 2. Có cần sử dụng máy bơm tăng áp không? Khuyến khích sử dụng nếu áp lực nước thấp hơn 3kg/cm² để đảm bảo hiệu suất tối ưu. 3. Vệ sinh và bảo trì như thế nào? Bề mặt mạ PVD dễ lau sạch, núm silicon chống bám ','het-hang',13243,NULL,NULL,1777387120273,1782621407354,'https://seajong.com/wp-content/uploads/2025/07/SJ-SC0171-GR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8100oii47pprr0a81k','SJ-PK-PK0666C-13415','Bộ phụ kiện 5 Món mạ PVD cao cấp SJ-PK0666C-GR','hang-hoa','Seajong','PK0666C','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,8000000.0,NULL,'Bộ phụ kiện 5 món mạ PVD cao cấp Seajong SJ-PK0666C-SR là lựa chọn lý tưởng cho những ai mong muốn một phòng tắm tiện nghi, sang trọng và đồng bộ. Mỗi chi tiết đều được thiết kế tinh xảo, mang lại sự tiện lợi và thẩm mỹ cho không gian sống.Bộ sản phẩm bao gồm: Vắt khăn giàn mạ PVD xám, Thanh vắt khăn đơn mạ PVD xám, Kệ góc nan nhỏ một tầng mạ PVD xám, Lô giấy hở mạ PVD xám Móc treo khăn đơn mạ PVD xám Mục Lục Toggle Tổng quan về công nghệ của Bộ phụ kiện 5 món mạ PVD cao cấp SJ-PK0666C-GR Xu hướng thiết kế và tiện ích sử dụng Tạm kết Tổng quan về công nghệ của Bộ phụ kiện 5 món mạ PVD cao cấp SJ-PK0666C-GR Toàn bộ bộ phụ kiện được sản xuất từ Inox 304 cao cấp, loại vật liệu nổi tiếng với độ bền vượt trội, khả năng chống gỉ sét và chống ăn mòn hiệu quả. Nhờ sử dụng chất liệu này, sản phẩm vẫn duy trì được độ chắc chắn và vẻ sáng bóng ngay cả trong môi trường ẩm ướt của phòng tắm. Đây chính là nền tảng giúp bộ phụ kiện Seajong được đánh giá cao bởi những khách hàng đề cao sự bền vững và an toàn. Toàn bộ bộ phụ kiện được sản xuất từ Inox 304 cao cấp, loại vật liệu nổi tiếng với độ bền vượt trội, khả năng chống gỉ sét và chống ăn mòn hiệu quả. Nhờ sử dụng chất liệu này, sản phẩm vẫn duy trì được độ chắc chắn và vẻ sáng bóng ngay cả trong môi trường ẩm ướt của phòng tắm. Đây chính là nền tảng giúp bộ phụ kiện Seajong được đánh giá cao bởi những khách hàng đề cao sự bền vững và an toàn. Bộ phụ kiện được hoàn thiện bằng công nghệ Đánh bóng Laser (Laser Polishing), mang lại bề mặt mịn, sáng bóng và hạn chế bám bẩn. Lớp mạ PVD xám hiện đại không chỉ tạo nên vẻ ngoài sang trọng mà còn dễ dàng kết hợp với nhiều phong cách nội thất khác nhau. Nhờ đó, sản phẩm vừa có giá trị thẩm mỹ cao, vừa thuận tiện trong việc lau chùi, vệ sinh hằng ngày. Điểm đặc biệt của Bộ phụ kiện 5 món mạ PVD cao cấp Seajong SJ-PK0666C-SR là ứng dụng công nghệ Hàn không dấu vết, giúp các mối nối liền mạch, chắc chắn và không để lộ chi tiết thừa. Nhờ vậy, sản phẩm vừa bền bỉ, vừa mang tính thẩm mỹ cao, kh','het-hang',13415,NULL,NULL,1777387120274,1782621407354,'https://seajong.com/wp-content/uploads/2025/07/SJ-PK0666C-GR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8600oni47p9qozm791','SJ-HH-PK2666D-CHR','Vắt khăn đơn Seajong SJ-PK2666D-SR','hang-hoa','Seajong','PK2666D','','Chrome','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,1150000.0,NULL,'Thanh vắt khăn SJ-PK2666D-SR được thiết kế tối giản, phù hợp cho nhiều không gian phòng tắm khác nhau. Với kích thước 600x25x75mm, sản phẩm nhỏ gọn nhưng vẫn đủ rộng để treo khăn tắm, khăn mặt hay các vật dụng thường ngày, mang đến sự tiện lợi và ngăn nắp cho không gian sống. Mục Lục Toggle Vắt khăn đơn mang chất liệu gì? Công nghệ ứng dụng vào sản phẩm gồm? Tạm kết Vắt khăn đơn mang chất liệu gì? Sản phẩm được chế tác từ Inox 304 cao cấp, loại vật liệu nổi tiếng với khả năng chống gỉ sét, chống ăn mòn và chịu lực tốt. Đây là yếu tố quan trọng giúp vắt khăn đơn Seajong không chỉ bền bỉ trong môi trường ẩm ướt mà còn giữ được vẻ đẹp sáng bóng sau nhiều năm sử dụng. Công nghệ ứng dụng vào sản phẩm gồm? Điểm khác biệt của Thanh vắt khăn SJ-PK2666D-SR chính là công nghệ Đánh bóng Laser (Laser Polishing), giúp bề mặt sản phẩm trở nên mịn màng, sáng bóng và tinh tế hơn. Nhờ lớp xử lý này, sản phẩm hạn chế bám bẩn, dễ vệ sinh và luôn duy trì vẻ ngoài sang trọng, góp phần nâng tầm đẳng cấp phòng tắm. Seajong ứng dụng công nghệ Hàn không dấu vết cho mẫu vắt khăn đơn này. Các mối nối được xử lý tinh xảo, liền mạch, không để lộ khuyết điểm. Nhờ đó, sản phẩm không chỉ chắc chắn mà còn đạt tính thẩm mỹ cao, phù hợp với phong cách phòng tắm hiện đại. Với kích thước 600x25x75mm, sản phẩm mang lại sự linh hoạt cho người dùng. Thiết kế đơn giản, gọn nhẹ nhưng tinh tế, dễ dàng lắp đặt ở nhiều vị trí khác nhau mà không chiếm nhiều diện tích. Lớp mạ Chrome sáng bóng còn giúp sản phẩm dễ dàng kết hợp với các thiết bị vệ sinh khác trong phòng tắm. Tạm kết Thanh Vắt khăn SJ-PK2666D-SR là lựa chọn lý tưởng cho những ai yêu thích sự đơn giản nhưng tinh tế. Sự kết hợp giữa Inox 304 cao cấp, Đánh bóng Laser và Hàn không dấu vết đã tạo nên một sản phẩm bền bỉ, đẹp mắt và tiện dụng. Đừng bỏ lỡ cơ hội sở hữu SJ-PK2666D-SR với mức giá ưu đãi chỉ có tại Showroom Seajong tại Tòa nhà CT3 Cầu Diễn, Phường Phú Diễn, TP. Hà Nội. Sản phẩm cao cấp, bền đẹp cùng chính sách bảo hành rõ ràng sẽ mang lại sự ','het-hang',13450,NULL,NULL,1777387120278,1782621407354,'https://seajong.com/wp-content/uploads/2025/07/SJ-PK2666D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8700oqi47pu734abqb','SJ-PK-PK3666D-13427','Kệ góc SJ-PK3666D-SR nan nhỏ một tầng mạ Chrome cao cấp','hang-hoa','Seajong','PK3666D','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,1250000.0,NULL,'Kệ góc SJ-PK3666D-SR là giải pháp tối ưu cho những phòng tắm hiện đại muốn tiết kiệm diện tích mà vẫn đảm bảo tính thẩm mỹ. Với thiết kế nhỏ gọn, kích thước 230x230x60mm, sản phẩm dễ dàng lắp đặt ở góc tường, giúp tận dụng không gian một cách thông minh và gọn gàng. Mục Lục Toggle Chất liệu của Kệ góc SJ-PK3666D-SR sử dụng là gì? Seajong đã sử dụng công nghệ gì cho kệ góc? Tạm kết Chất liệu của Kệ góc SJ-PK3666D-SR sử dụng là gì? Sản phẩm được chế tác từ Inox 304 cao cấp, loại vật liệu nổi bật với khả năng chống gỉ sét, chống ăn mòn và chịu lực tốt. Nhờ đó, kệ góc Seajong luôn bền chắc trong môi trường ẩm ướt, hạn chế cong vênh và duy trì vẻ sáng bóng trong suốt thời gian sử dụng. Seajong đã sử dụng công nghệ gì cho kệ góc? Điểm nổi bật của Kệ góc SJ-PK3666D-SR là được xử lý bằng công nghệ Đánh bóng Laser (Laser Polishing), tạo nên bề mặt mịn, sáng bóng và sang trọng. Lớp mạ Chrome cao cấp hạn chế bụi bẩn bám dính, giúp việc lau chùi trở nên nhanh chóng, giữ cho sản phẩm luôn sạch đẹp như mới. Seajong ứng dụng kỹ thuật Hàn không dấu vết trên toàn bộ sản phẩm, mang lại sự liền mạch và tinh tế trong từng chi tiết. Các mối nối được gia công tỉ mỉ, vừa chắc chắn, vừa tăng thêm tính thẩm mỹ, giúp sản phẩm trở thành điểm nhấn sang trọng trong không gian phòng tắm. Với kích thước 230x230x60mm, kệ góc nan một tầng phù hợp để đựng chai dầu gội, sữa tắm hay các vật dụng nhỏ gọn khác. Thiết kế nan thoáng giúp nước dễ dàng thoát, hạn chế ẩm mốc và giữ sản phẩm luôn khô ráo, vệ sinh. Tạm kết Kệ góc SJ-PK3666D-SR mang đến sự kết hợp hoàn hảo giữa chất liệu bền bỉ, công nghệ tiên tiến và thiết kế thông minh. Đây là sản phẩm không chỉ giúp phòng tắm gọn gàng hơn mà còn nâng tầm phong cách sống hiện đại. Liên hệ ngay với Seajong qua Hotline: 1900.633.862 để được báo giá ưu đãi chi tiết (nếu có) và hỗ trợ đặt hàng nhanh chóng. Sở hữu ngay kệ góc nan nhỏ một tầng mạ Chrome cao cấp Kệ góc SJ-PK3666D-SR để biến không gian phòng tắm của bạn trở nên gọn gàng và sang trọng hơn mỗi ngày.','het-hang',13427,NULL,NULL,1777387120279,1782621407354,'https://seajong.com/wp-content/uploads/2025/07/SJ-PK3666D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8800oti47pei4e6buk','SJ-HH-PK4666D-13428','LÔ GIẤY INOX SUS304 SJ-PK4666D-SR','hang-hoa','Seajong','PK4666D','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,890000.0,NULL,'Mục Lục Toggle Lô giấy vệ sinh SJ-PK4666D-SR – Phụ kiện phòng tắm cao cấp từ Seajong 1. Lô giấy vệ sinh thiết kế tối giản, dễ sử dụng 2. Hộp giấy vệ sinh từ inox 304 POSCO Hàn Quốc 3. Lô giấy inox 304 hoàn thiện bằng công nghệ đánh bóng 8K 4. Phụ kiện nhà tắm ứng dụng công nghệ hàn không giấu vết 5. Hộp giấy nhà vệ sinh phù hợp nhiều không gian Lô giấy vệ sinh SJ-PK4666D-SR – Phụ kiện phòng tắm cao cấp từ Seajong Trong một phòng tắm hiện đại, những chi tiết nhỏ như lô giấy, thanh treo hay móc phụ kiện đều góp phần tạo nên trải nghiệm sử dụng trọn vẹn. Lô giấy vệ sinh SJ-PK4666D-SR được Seajong phát triển theo định hướng tối giản, chắc chắn và bền đẹp, phù hợp với các không gian phòng tắm gia đình, khách sạn, resort hoặc showroom cao cấp. Sản phẩm sở hữu thiết kế hở tinh gọn, giúp người dùng dễ dàng thay cuộn giấy, thao tác nhanh và thuận tiện trong quá trình sử dụng hằng ngày. Với kích thước 200mm x 117mm x 80mm, Lô giấy vệ sinh SJ-PK4666D-SR có tỷ lệ cân đối, không chiếm nhiều diện tích nhưng vẫn tạo được điểm nhấn sang trọng trên mảng tường phòng tắm. 1. Lô giấy vệ sinh thiết kế tối giản, dễ sử dụng Điểm mạnh của mẫu lô giấy này nằm ở kiểu dáng gọn, thoáng và hiện đại. Thiết kế dạng hở giúp hạn chế sự cồng kềnh thường thấy ở các mẫu hộp giấy kín, đồng thời mang lại cảm giác nhẹ mắt, phù hợp với xu hướng phòng tắm tối giản hiện nay. Từng đường nét của Lô giấy vệ sinh SJ-PK4666D-SR được xử lý vuông vắn, liền mạch, dễ phối cùng các phụ kiện mạ chrome khác như thanh vắt khăn, móc áo, kệ góc hoặc bộ xịt vệ sinh. Đây là lựa chọn phù hợp cho những công trình cần sự đồng bộ về thẩm mỹ và độ hoàn thiện. 2. Hộp giấy vệ sinh từ inox 304 POSCO Hàn Quốc Seajong sử dụng inox 304 POSCO Hàn Quốc cho sản phẩm nhằm đảm bảo độ bền trong môi trường phòng tắm thường xuyên tiếp xúc với hơi nước. Chất liệu inox 304 có khả năng chống gỉ, chống ăn mòn tốt, giúp sản phẩm giữ được sự chắc chắn và vẻ sáng đẹp trong quá trình sử dụng lâu dài. Với vai trò là nhà sản xuất, Seajong chú trọng khô','het-hang',13428,NULL,NULL,1777387120281,1782621407354,'https://seajong.com/wp-content/uploads/2025/07/SJ-PK4666D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8h00p1i47powugztgw','SJ-PK-PK0004D-CHR','Mắc áo 4 móc SJ-PK0004D-SR Seajong Hàn Quốc','hang-hoa','Seajong','PK0004D','','Chrome','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,790000.0,NULL,'Mắc áo 4 móc tròn cao cấp Seajong SJ-PK0004D-SR là lựa chọn hoàn hảo cho những ai mong muốn sự gọn gàng, ngăn nắp và tiện nghi trong sinh hoạt hằng ngày. Với kích thước 290x35x25mm, sản phẩm được thiết kế nhỏ gọn nhưng vẫn đảm bảo không gian treo rộng rãi, kết hợp cùng khả năng chịu tải lên đến 15kg. Đây là giải pháp tối ưu để treo nhiều vật dụng như khăn, áo khoác, túi xách hay phụ kiện trong gia đình. Mục Lục Toggle Mắc áo 4 móc tròn cao cấp sử dụng chất liệu gì? Công nghệ sản phẩm SJ-PK0004D-SR có gì đặc biệt? Tạm kết Mắc áo 4 móc tròn cao cấp sử dụng chất liệu gì? Sản phẩm được chế tác từ Inox SUS304 cao cấp, loại vật liệu nổi tiếng với độ bền vượt trội, khả năng chống gỉ sét và chống ăn mòn tốt. Nhờ đó, mắc áo Seajong luôn duy trì được độ chắc chắn và sáng bóng, ngay cả khi sử dụng trong môi trường ẩm ướt như phòng tắm hay ban công. Đây là yếu tố then chốt giúp sản phẩm chinh phục cả những khách hàng khó tính nhất. Công nghệ sản phẩm SJ-PK0004D-SR có gì đặc biệt? Điểm nhấn nổi bật của SJ-PK0004D-SR chính là công nghệ Đánh bóng Laser (Laser Polishing), mang đến bề mặt sáng mịn, bóng đẹp và dễ dàng vệ sinh. Công nghệ này không chỉ nâng cao tính thẩm mỹ mà còn giúp sản phẩm giữ được vẻ đẹp tinh tế, hạn chế bám bẩn, tiết kiệm thời gian lau chùi. Sản phẩm được hoàn thiện bằng công nghệ Hàn không dấu vết, giúp các mối nối liền mạch, chắc chắn và không để lộ khuyết điểm. Điều này vừa đảm bảo độ bền cao, vừa mang lại sự tinh tế, phù hợp với nhiều phong cách nội thất hiện đại. Trong xu hướng sống hiện đại, các sản phẩm tối giản nhưng đa năng ngày càng được ưa chuộng. Mắc áo 4 móc tròn Seajong không chỉ giúp giữ cho không gian gọn gàng mà còn thể hiện gu thẩm mỹ tinh tế của gia chủ. Với kiểu dáng đơn giản, sản phẩm dễ dàng kết hợp trong phòng tắm, phòng ngủ, ban công hay sau cửa ra vào. Thiết kế 4 móc tròn chắc chắn cho phép treo cùng lúc nhiều vật dụng khác nhau, đáp ứng nhu cầu đa dạng của gia đình. Từ khăn tắm, áo khoác đến các phụ kiện nhỏ, tất cả đều được sắp xếp gọ','het-hang',13806,NULL,NULL,1777387120289,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/moc-ao-SJ-PK0004D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8j00p5i47pqeh85yhd','SJ-HH-PK5666D-15711','Móc treo đơn Mạ Chrome cao cấp Seajong SJ-PK5666D-SR','hang-hoa','Seajong','PK5666D','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,620000.0,NULL,'Móc treo khăn đơn mạ Chrome cao cấp Seajong SJ-PK5666D-SR sở hữu thiết kế nhỏ gọn chỉ 50x25mm, lý tưởng để treo khăn tay, khăn mặt, quần áo hoặc các vật dụng nhỏ trong phòng tắm. Dù có kích thước khiêm tốn, sản phẩm vẫn thể hiện sự chắc chắn và tinh tế trong từng chi tiết, giúp không gian luôn gọn gàng, ngăn nắp và toát lên vẻ sang trọng đặc trưng của thương hiệu Seajong. Móc treo Seajong ứng dụng công nghệ gì? Móc treo khăn đơn Seajong SJ-PK5666D-SR được chế tác với công nghệ Đánh bóng Laser (Laser Polishing) tiên tiến, giúp bề mặt sáng bóng, mịn màng và mang lại vẻ sang trọng đặc trưng. Nhờ lớp hoàn thiện này, sản phẩm hạn chế tối đa bụi bẩn bám dính, dễ dàng vệ sinh và giữ được độ mới lâu dài, phù hợp với nhiều phong cách phòng tắm hiện đại. Bên cạnh đó, sản phẩm còn ứng dụng kỹ thuật Hàn không dấu vết, tạo nên cấu trúc liền mạch, tinh tế và bền chắc. Mỗi chi tiết đều được gia công tỉ mỉ, giúp móc treo không chỉ đảm bảo độ chắc chắn khi sử dụng mà còn nâng tầm tính thẩm mỹ cho toàn bộ không gian. Trong xu hướng thiết kế nội thất hiện đại, những phụ kiện nhỏ gọn nhưng đa năng như móc treo Seajong ngày càng được ưa chuộng. Với thiết kế tinh giản, kiểu dáng thanh thoát và tính ứng dụng cao, sản phẩm dễ dàng kết hợp hài hòa trong mọi phong cách – từ tối giản đến sang trọng. Tạm kết Móc treo khăn đơn mạ Chrome cao cấp Seajong SJ-PK5666D-SR là chi tiết tuy nhỏ nhưng góp phần lớn vào sự hoàn thiện của phòng tắm tiện nghi và đẳng cấp. Được làm từ Inox 304 cao cấp, kết hợp công nghệ Đánh bóng Laser cùng Hàn không dấu vết tinh xảo, sản phẩm không chỉ bền bỉ mà còn thể hiện gu thẩm mỹ tinh tế của người sở hữu. Một chi tiết nhỏ – một khác biệt lớn. Hãy đến Showroom Seajong tại Tòa nhà CT3 Cầu Diễn, Phường Phú Diễn, TP. Hà Nội để trải nghiệm trực tiếp sản phẩm và nhận tư vấn từ đội ngũ chuyên viên có 5+ năm kinh nghiệm. ⇒Xem thêm các phụ kiện mắc áo khác của Seajong ngay⇒','het-hang',15711,NULL,NULL,1777387120292,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-PK5666D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8k00p8i47p1psjnvgo','SJ-LB-VL0006B-TRẮ-14976','Vòi Lavabo SJ-VL0006B-WR1 Mạ PVD Trắng sứ','hang-hoa','Seajong','VL0006B','','Trắng +Vàng','cmoiqcoxp00igi47peur5b8e8','cái',0.0,0.0,0.0,5950000.0,NULL,'Vòi lavabo cao cấp mạ sứ Seajong SJ-VL0006B-WR là lựa chọn dành cho những không gian phòng tắm theo phong cách tinh tế – sang trọng – hiện đại . Sản phẩm sở hữu thiết kế thanh thoát, sắc trắng mạ sứ nổi bật, phù hợp với các mẫu chậu lavabo cao cấp, tủ lavabo hiện đại và những không gian phòng tắm đề cao tính thẩm mỹ. Thân vòi được chế tạo từ đồng 61% , mang lại kết cấu chắc chắn, khả năng chịu áp lực nước tốt và độ bền cao trong quá trình sử dụng lâu dài. Theo thông số trên website Seajong, sản phẩm sử dụng công nghệ đúc trọng lực phân tách chì , giúp nâng cao độ an toàn cho nguồn nước, thân thiện hơn với sức khỏe người dùng và môi trường. Bên trong sản phẩm Vòi lavabo cao cấp mạ sứ Seajong sử dụng van lõi Ceramic Sedal nhập khẩu từ Tây Ban Nha , giúp thao tác đóng mở nhẹ, điều chỉnh nước ổn định, hạn chế rò rỉ và tăng tuổi thọ vận hành. Đây là chi tiết quan trọng tạo nên sự khác biệt giữa một chiếc vòi lavabo thông thường và một sản phẩm cao cấp sử dụng bền bỉ theo thời gian. Bề mặt thân vòi được xử lý bằng công nghệ mạ 5 lớp kết hợp phủ sứ nano , tạo hiệu ứng sáng bóng, sang trọng, hạn chế bám bẩn, dễ vệ sinh và giữ được vẻ đẹp tinh tế trong môi trường phòng tắm ẩm ướt. Vòi lavabo cao cấp mạ sứ Seajong với lớp hoàn thiện này không chỉ nâng cao tính thẩm mỹ mà còn góp phần bảo vệ thân vòi khỏi oxy hóa và xỉn màu. Đầu vòi phun ứng dụng công nghệ Warasoft tạo bọt , giúp dòng nước mềm hơn, êm hơn và hạn chế bắn nước khi sử dụng. Nhờ đó, mỗi thao tác rửa tay, rửa mặt trở nên nhẹ nhàng, sạch sẽ và thoải mái hơn. Với thời gian bảo hành 5 năm , vòi lavabo cao cấp mạ sứ Seajong SJ-VL0006B-WR không chỉ là một thiết bị cấp nước, mà còn là điểm nhấn thẩm mỹ cho phòng tắm hiện đại, thể hiện đúng tinh thần thương hiệu Seajong: tinh tế trong thiết kế, hiện đại trong công nghệ và bền bỉ trong chất lượng .','het-hang',14976,NULL,NULL,1777387120293,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-VL0006B-WR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8m00pbi47pzeheckcm','SJ-PK-PK1312D','Kệ góc phòng tắm hai tầng cao cấp Seajong SJ-PK1312D-SR','hang-hoa','Seajong','PK1312D','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,2000000.0,NULL,'Phòng tắm hiện đại không chỉ đòi hỏi thiết kế đẹp mắt mà còn cần những phụ kiện bền bỉ, tiện lợi. Trong đó, kệ góc là một trong những chi tiết thường bị xem nhẹ nhưng lại có vai trò lớn trong việc giữ không gian gọn gàng, khoa học. Seajong SJ-PK1312D-SR là mẫu kệ góc hai tầng cao cấp, được thiết kế tinh tế và ứng dụng công nghệ sản xuất tiên tiến, mang lại sự hài lòng cho những khách hàng khó tính nhất. Mục Lục Toggle Chất liệu và công nghệ sản xuất vượt trội Điểm khác biệt trong thiết kế Tạm kết Chất liệu và công nghệ sản xuất vượt trội Kệ được chế tác từ Inox SUS 304, dòng thép không gỉ nổi tiếng về khả năng chống ăn mòn và độ bền cao trong môi trường ẩm ướt. Nhờ vậy, SJ-PK1312D-SR giữ được sự sáng bóng lâu dài, hạn chế hoen gỉ và dễ dàng vệ sinh. Đây là lựa chọn an toàn và xứng đáng cho phòng tắm của gia đình. Bề mặt sản phẩm được xử lý bằng công nghệ đánh bóng Laser (Laser Polishing), tạo nên độ sáng mịn và sang trọng hơn hẳn so với phương pháp đánh bóng truyền thống. Kết hợp với cấu tạo hàn không dấu vết, các khớp nối gần như liền mạch, vừa chắc chắn vừa tinh tế, giúp kệ không chỉ bền mà còn đẹp trong từng chi tiết. Điểm khác biệt trong thiết kế Điểm khác biệt tiếp theo của kệ Seajong SJ-PK1312D-SR là khả năng chịu tải lên tới 20kg. Người dùng có thể thoải mái đặt dầu gội, sữa tắm, mỹ phẩm hoặc phụ kiện vệ sinh mà không lo cong vênh hay mất ổn định. Với kích thước 277 × 376 × 198.7mm, kệ được tối ưu để vừa vặn trong mọi góc tường phòng tắm. Thiết kế hai tầng thông minh cho phép sắp xếp đồ dùng gọn gàng, dễ lấy và phân loại rõ ràng, tạo sự tiện lợi trong sinh hoạt hàng ngày. Tạm kết Kệ góc phòng tắm hai tầng Seajong SJ-PK1312D-SR hội tụ đủ các yếu tố: chất liệu Inox SUS 304 bền bỉ, bề mặt đánh bóng Laser hiện đại, hàn không dấu vết tinh tế, chịu tải 20kg và kích thước chuẩn. Đây không chỉ là phụ kiện lưu trữ đơn thuần mà còn là chi tiết góp phần nâng tầm phong cách phòng tắm, mang lại sự tiện nghi và thẩm mỹ cho không gian sống. Nếu bạn đang tìm một sản phẩm vừa','het-hang',13824,NULL,NULL,1777387120294,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/SJ-PK1312D-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8n00pei47pso2adp2j','SJ-LB-LB2125B-SỨ','Chậu Lavabo sứ cao cấp Seajong SJ-LB2125B','hang-hoa','Seajong','LB2125B','','Sứ trắng','cmoiqef8m00pci47po9syqv9u','cái',0.0,0.0,0.0,2550000.0,NULL,'Chậu Lavabo sứ cao cấp dương bàn Seajong SJ-LB2125B là sự kết hợp hoàn hảo giữa tính thẩm mỹ và công nghệ hiện đại. Được chế tạo từ chất liệu sứ cao cấp và công nghệ sản xuất tiên tiến, lavabo này dễ dàng vệ sinh và bền bỉ theo thời gian, là lựa chọn lý tưởng cho những không gian phòng tắm sang trọng và hiện đại. Mục Lục Toggle Sản phẩm ứng dụng công nghệ Phù hợp với đối tượng và phong cách phòng tắm nào? Một số câu hỏi về chậu lavabo dương bàn Seajong SJ-LB2125B: Tại sao nên mua sản phẩm Chậu lavabo dương bàn SJ-LB2125B tại Seajong? Sản phẩm ứng dụng công nghệ – Công nghệ Nano-Ceramic: Tăng độ cứng lên 40%, chống nứt vỡ và chịu nhiệt lên đến 300°C, giúp sản phẩm bền bỉ và lâu dài. – Công nghệ Lò nung HPF (High Pressure Firing): Tiết kiệm 30% năng lượng, độ hút nước &lt;=0,5%, chống thấm hoàn hảo. – Công nghệ Lead-Free Glaze (Men không chì): An toàn cho sức khỏe, kháng khuẩn tới 99,9%, giúp bảo vệ người sử dụng. – Công nghệ Plasma: Tạo bề mặt siêu mịn, tăng độ bám dính men, giúp chống bám bẩn và giữ bề mặt luôn sáng bóng. – Công nghệ Zero Waste (Quy trình sản xuất khép kín): Tái chế 100% phế liệu và nước thải, giảm 65% CO₂, bảo vệ môi trường. Phù hợp với đối tượng và phong cách phòng tắm nào? Đối tượng sử dụng: Phù hợp với các gia đình muốn tiết kiệm không gian và sử dụng sản phẩm bền bỉ cho phòng tắm. Ngoài ra, Chậu lavabo dương bàn Seajong còn phù hợp để sử dụng trong khách sạn, khu nghỉ dưỡng cao cấp, mang lại sự sang trọng và dễ dàng bảo trì. Phong cách phòng tắm: – Phong cách hiện đại (Modern): Lavabo này có thiết kế tối giản, phù hợp với không gian phòng tắm hiện đại. – Phong cách tối giản (Minimalism): Màu sắc trắng sáng giúp tạo cảm giác rộng rãi và dễ dàng kết hợp với phong cách tối giản. – Phong cách sang trọng (Luxury): Độ bền cao và thiết kế đẹp mắt giúp sản phẩm này trở thành điểm nhấn trong phòng tắm cao cấp. Một số câu hỏi về chậu lavabo dương bàn Seajong SJ-LB2125B: Lắp đặt chậu lavabo dương bàn Seajong SJ-LB2125B có khó không? Lavabo Seajong SJ-LB21','het-hang',14260,NULL,NULL,1777387120296,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/SJ-LB2125B.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8q00pii47p3njhgk1v','SJ-LB-2114LD','Chậu Lavabo sứ dáng vuông cao cấp Seajong SJ-2114LD','hang-hoa','Seajong','2114LD','','','cmoiqef8m00pci47po9syqv9u','cái',0.0,0.0,0.0,2800000.0,NULL,'⇒Xem thêm các mẫu chậu Lavabo khác của Seajong ngay⇒','het-hang',14266,NULL,NULL,1777387120298,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/SJ-LB2114-50.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8r00pli47p9b6loqbi','SJ-LB-LB2126-TRẮ','Chậu Lavabo sứ treo tường cao cấp Seajong SJ-LB2126','hang-hoa','Seajong','LB2126','','Trắng sứ','cmoiqef8m00pci47po9syqv9u','cái',0.0,0.0,0.0,4500000.0,NULL,'Chậu lavabo Seajong SJ-LB2126 có thiết kế tối giản, tinh tế, tiết kiệm không gian và mang lại vẻ đẹp sang trọng cho phòng tắm. Được làm từ chất liệu sứ cao cấp và công nghệ sản xuất tiên tiến, lavabo này đảm bảo độ bền vượt trội, dễ dàng vệ sinh và an toàn cho sức khỏe người sử dụng. Tính năng công nghệ Hỗn hợp Nano-Ceramic với hạt SiO₂ và ZrO₂ tăng độ cứng lên 40%, giúp chậu chống nứt vỡ, chịu nhiệt tới 300°C và bề mặt siêu mịn Ra ≤ 0.1 μm ngăn cặn bám, hạn chế vi khuẩn tích tụ. Lớp men không chứa chì Pb và Cadmium Cd, đạt chứng nhận an toàn NSF/ANSI 51 (Mỹ), kết hợp ion bạc Ag⁺ kháng khuẩn trên 99.9% theo JIS Z 2801, ngăn vi khuẩn, nấm mốc và duy trì độ bóng sáng bóng, bền đẹp ngay cả sau 50.000 lần chà rửa. Thiết kế bằng công nghệ CAD/CAM/CAE với phân tích lực FEA và gia công CNC 5 trục chính xác đến ±0.01 mm mang đến độ dốc đáy chậu 2.5° ±0.2°, thoát nước nhanh, không bị đọng nước. Công nghệ nung HPF ở nhiệt độ 1280–1350°C giúp hạt sứ liên kết bền chắc, tiết kiệm 30% năng lượng so với nung truyền thống và đạt độ hút nước ≤ 0.5% theo tiêu chuẩn ISO 10545-3, đảm bảo chống thấm tuyệt đối và giữ màu sắc đồng nhất từ lõi đến bề mặt. Bề mặt được xử lý bằng công nghệ Plasma ion hóa Ar/O₂ giúp men bám chắc gấp 3 lần, loại bỏ nguy cơ bong tróc, tạo bề mặt siêu phẳng chống bám bẩn, giữ chậu luôn sáng bóng và dễ vệ sinh. Sản xuất theo quy trình khép kín Zero Waste với việc tái chế 100% phế liệu sứ 100% phế liệu sứ và nước thải qua hệ thống lọc RO, giảm 65% CO₂ so với sản xuất truyền thống. Nguyên liệu sinh thái từ vỏ sò và cát biển giúp sản phẩm đạt chứng nhận Green Label Singapore và Cradle to Cradle Certified®, thân thiện môi trường và đảm bảo an toàn tuyệt đối cho sức khỏe người dùng. Phong cách phòng tắm phù hợp Với thiết kế sang trọng, độ bền cao cùng gam màu trắng sứ thanh lịch, lavabo Seajong SJ-LB2126 có thể dễ dàng hòa hợp với nhiều phong cách phòng tắm khác nhau, từ hiện đại cho đến sang trọng: Phong cách hiện đại (Modern): Đường nét tinh gọn, kiểu dáng tối giản ','het-hang',14276,NULL,NULL,1777387120299,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/T2126.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8s00poi47po1igybnb','SJ-LB-LB2134-TRẮ','Chậu Lavabo sứ treo tường cao cấp Seajong SJ-LB2134','hang-hoa','Seajong','LB2134','','Trắng sứ','cmoiqef8m00pci47po9syqv9u','cái',0.0,0.0,0.0,4500000.0,NULL,'Mang phong cách tối giản nhưng không kém phần tinh tế, chậu lavabo sứ treo tường Seajong SJ-LB2134 là giải pháp hoàn hảo để tối ưu không gian và nâng tầm thẩm mỹ cho phòng tắm. Được sản xuất từ sứ cao cấp và ứng dụng những công nghệ tiên tiến hàng đầu, sản phẩm mang đến độ bền vượt trội, khả năng vệ sinh dễ dàng và sự an toàn tuyệt đối cho sức khỏe người dùng. Mục Lục Toggle Tính năng công nghệ Phong cách phòng tắm phù hợp Liên hệ mua hàng chính hãng tại Seajong Tính năng công nghệ Hỗn hợp Nano-Ceramic với hạt SiO₂ và ZrO₂ kích thước siêu nhỏ giúp tăng độ cứng bề mặt lên 40%, chống nứt vỡ khi va đập, chịu được nhiệt độ lên tới 300°C mà không biến dạng. Bề mặt siêu mịn Ra ≤ 0.1 μm hạn chế cặn bám, ngăn ngừa vi khuẩn tích tụ, đảm bảo an toàn trong suốt quá trình sử dụng. Công nghệ nung HPF, nung trong lò áp suất cao 50–100 bar ở nhiệt độ 1280–1350°C giúp các hạt sứ liên kết đồng nhất và bền chắc hơn đồng thời tiết kiệm đến 30% năng lượng so với nung truyền thống, vừa đạt độ hút nước ≤ 0.5% theo tiêu chuẩn ISO 10545-3, vừa đảm bảo chống thấm tuyệt đối với màu sắc đồng đều từ trong ra ngoài. Sử dụng lớp men thủy tinh phi kim loại hoàn toàn không chứa chì Pb và Cadmium Cd đạt chứng nhận an toàn NSF/ANSI 51 của Mỹ. Lớp men không chứa chì Pb và Cadmium Cd, đạt chứng nhận NSF/ANSI 51 (Mỹ) về an toàn khi tiếp xúc với thực phẩm. Công nghệ phủ men tích hợp ion bạc Ag⁺ mang lại hiệu quả kháng khuẩn trên 99.9% (theo tiêu chuẩn JIS Z 2801), ngăn vi khuẩn, nấm mốc và giữ độ bóng sáng bền đẹp ngay cả sau 50.000 lần chà rửa. Bề mặt được xử lý bằng công nghệ Plasma hiện đại, trước khi phủ men, bề mặt chậu được xử lý bằng plasma ion hóa Ar/O₂ giúp tăng độ bám dính của men gấp 3 lần, loại bỏ nguy cơ bong tróc, đồng thời tạo nên bề mặt siêu phẳng, hạn chế bám bẩn và dễ dàng vệ sinh. Thiết kế bằng công nghệ CAD/CAM/CAE, nhờ phân tích lực bằng phần mềm FEA và gia công CNC 5 trục với độ chính xác ±0.01 mm, chậu đạt độ dốc đáy chuẩn 2.5° ± 0.2°, đảm bảo nước thoát nhanh chóng, không để lại ','het-hang',14289,NULL,NULL,1777387120300,1782621407354,'https://seajong.com/wp-content/uploads/2025/08/SJ-LB2134-5.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8t00pri47pp94xmiyp','SJ-TL-TL929-BE','Tủ Lavabo PVC cao cấp Seajong SJ-TL929','hang-hoa','Seajong','TL929','','Be','cmoit63u3001di4nul0lbrqko','cái',0.0,0.0,0.0,8500000.0,NULL,'Tủ lavabo Seajong SJ-TL929 là sự kết hợp hoàn hảo giữa thiết kế tinh tế, sang trọng và chất liệu PVC cao cấp, mang đến vẻ đẹp hiện đại, bền bỉ cùng khả năng chống chịu tuyệt vời trong mọi điều kiện phòng tắm. Gam màu be nhẹ nhàng cùng kiểu dáng thông minh giúp sản phẩm dễ dàng trở thành điểm nhấn, nâng tầm không gian sống của bạn. Mục Lục Toggle Tính năng công nghệ nổi bật Phong cách phòng tắm phù hợp Liên hệ mua hàng chính hãng tại Seajong Tính năng công nghệ nổi bật Chất liệu PVC Foam cao cấp có khả năng chống cháy, chống thấm nước, đảm bảo độ bền lâu dài, bảo vệ không gian phòng tắm khỏi ảnh hưởng của độ ẩm. Khả năng chịu nhiệt vượt trội từ -30°C đến 150°C, thích hợp với mọi điều kiện môi trường trong phòng tắm. Sử dụng công nghệ hiện đại với lớp phủ Nano Alumina tạo bề mặt siêu cứng, chống trầy xước cấp độ 9H, duy trì vẻ đẹp bền lâu. Trang bị gương LED công nghệ chip Samsung, tiết kiệm đến 80% năng lượng so với đèn thường, ánh sáng CRI ≥ 90 bảo vệ mắt, với 3 chế độ tùy chỉnh (trắng – ấm – trung tính), tuổi thọ lên đến 50.000 giờ. Bề mặt được xử lý bằng ion bạc Ag+, mang đến khả năng kháng khuẩn tối ưu, ngăn ngừa vi khuẩn phát triển, an toàn tuyệt đối cho sức khỏe. Phong cách phòng tắm phù hợp Với thiết kế tối giản nhưng sang trọng, tủ lavabo Seajong SJ-TL929 có thể dễ dàng hòa hợp với nhiều phong cách phòng tắm khác nhau: Phong cách Hiện đại (Modern): Đường nét thanh thoát, tinh tế làm nổi bật không gian phòng tắm hiện đại. Phong cách Tối giản (Minimalism): Gam màu be nhẹ nhàng mang đến cảm giác gọn gàng, thanh lịch, phù hợp lối sống tinh gọn. Phong cách Sang trọng (Luxury): Vẻ đẹp tinh tế kết hợp độ bền vượt trội giúp tủ lavabo trở thành điểm nhấn đẳng cấp cho phòng tắm cao cấp. Liên hệ mua hàng chính hãng tại Seajong Với thiết kế sang trọng, công nghệ tiên tiến và chất lượng đáng tin cậy, tủ lavabo Seajong SJ-TL929 chắc chắn sẽ là lựa chọn hoàn hảo cho không gian phòng tắm của bạn. Mua ngay để trải nghiệm không gian sống sang trọng và tiện nghi.','het-hang',14414,NULL,NULL,1777387120302,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-TL929-1.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef8x00pwi47p984gffto','SJ-LB-VL6002B-MẠ','Vòi Lavabo Seajong SJ-VL6002B-SR','hang-hoa','Seajong','VL6002B','','Mạ Chrome','cmoiqcoxp00igi47peur5b8e8','cái',0.0,0.0,0.0,3400000.0,NULL,'Vòi lavabo mạ chrome cao cấp Seajong SJ-VL6002B-SR được thiết kế để dung hòa giữa công năng và tính thẩm mỹ, mang đến giải pháp hoàn hảo cho không gian phòng tắm hiện đại. Với chất liệu đồng nguyên chất kết hợp công nghệ mạ Chrome tiên tiến, sản phẩm đảm bảo sự bền bỉ, an toàn và tiện nghi trong suốt quá trình sử dụng. Tính năng công nghệ nổi bật Thân vòi bằng đồng nguyên chất ≥ 61% nhập khẩu từ Ý, hàm lượng chì chỉ 0,1%, thấp hơn nhiều so với mức khuyến nghị 0,25% của WHO, đảm bảo an toàn tuyệt đối cho sức khỏe người dùng. Van lõi Sedal cao cấp được thử nghiệm với hơn 500.000 lần đóng mở, van Ceramic chống mài mòn, chịu nhiệt tốt, kết hợp gioăng chống rò rỉ nước và giảm rung ồn, mang lại trải nghiệm sử dụng êm ái, mượt mà. Xử lý bề mặt bằng công nghệ CNC kết hợp robot đánh bóng tự động đạt chuẩn châu Âu với độ nhám Ra ≤ 0.2 µm và độ bóng Gloss ≥ 85 GU mang lại bề mặt sáng bóng, đồng đều và sang trọng. Công nghệ mạ 5 lớp có khả năng chống ăn mòn, tăng độ bám, chống trầy xước và bong tróc, giữ cho màu bền đẹp theo thời gian. Quy trình mạ đạt chuẩn DIN EN 248 và vượt qua kiểm nghiệm Salt Spray Test 24h theo ASTM B117, chứng minh khả năng chống ăn mòn, chống gỉ sét và bền màu.','het-hang',14594,NULL,NULL,1777387120306,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-VL6002B-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9200q2i47p3h0ycuqq','SJ-LB-VL0801B-MẠ','Vòi Lavabo mạ PVD cao cấp Seajong SJ-VL0801B','hang-hoa','Seajong','VL0801B','','Mạ Chrome 1 dáng thấp | Mạ Chrome 2 dáng cao','cmoiqcoxp00igi47peur5b8e8','cái',0.0,0.0,0.0,4480000.0,NULL,'','het-hang',14897,NULL,NULL,1777387120311,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-VL0801B-GR1.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9400q6i47pyf0o1o6t','SJ-LB-VL6031B-MẠ','Vòi Lavabo mạ Chrome cao cấp Seajong SJ-VL6031B-SR','hang-hoa','Seajong','VL6031B','','Mạ Chrome','cmoiqcoxp00igi47peur5b8e8','cái',0.0,0.0,0.0,3250000.0,NULL,'Mục Lục Toggle Vòi lavabo SJ-VL6031b-SR. Thiết kế mạ Chrome hiện đại cho không gian lavabo cao cấp 1. Vòi lavabo mạ chrome, lựa chọn sáng sạch và dễ phối nội thất 2. Vòi lavabo nóng lạnh vận hành êm nhờ lõi Sedal Tây Ban Nha 3. Vòi lavabo cao cấp với thân đồng 61% và công nghệ phân tách chì 4. Vòi lavabo mạ chrome cao cấp Seajong cho phòng tắm hiện đại 5. Vòi lavabo đồng 61% lõi Sedal đáng đầu tư cho sử dụng lâu dài Vòi lavabo SJ-VL6031b-SR. Thiết kế mạ Chrome hiện đại cho không gian lavabo cao cấp Trong một phòng tắm hiện đại, khu vực lavabo không chỉ là nơi rửa tay, rửa mặt hằng ngày mà còn là điểm nhấn thể hiện chất lượng hoàn thiện của cả không gian. Vòi lavabo sj-vl6031b-sr là cách gọi tìm kiếm mà nhiều khách hàng có thể sử dụng khi tìm một mẫu vòi lavabo Seajong dáng hiện đại, bề mặt mạ chrome sáng bóng và chất lượng vận hành ổn định. Dựa trên dòng sản phẩm SJ-VL6031B-SR của Seajong, mẫu vòi này phù hợp với những phòng tắm cần sự tinh tế, sạch sẽ và bền bỉ. Thiết kế vuông vắn, thân vòi cân đối, tay gạt phẳng và bề mặt chrome sáng giúp vòi lavabo âm tường sj-vl6031b-sr dễ dàng phối với chậu lavabo đặt bàn, chậu âm bàn, tủ lavabo hiện đại hoặc gương LED cao cấp. 1. Vòi lavabo mạ chrome, lựa chọn sáng sạch và dễ phối nội thất Một trong những ưu điểm nổi bật của vòi lavabo sj-vl6031b-sr là bề mặt mạ chrome. Lớp chrome mang lại cảm giác sáng, sạch, hiện đại và phù hợp với hầu hết phong cách phòng tắm hiện nay. Với những không gian sử dụng gạch trắng, gạch xám, đá vân mây hoặc tủ lavabo màu gỗ, vòi mạ chrome giúp tổng thể trở nên cân bằng và sang hơn. Ở góc độ sử dụng thực tế, bề mặt sáng bóng cũng giúp người dùng dễ quan sát vết bẩn, cặn nước để vệ sinh kịp thời. Khi được bảo dưỡng đúng cách, vòi lavabo sj-vl6031b-sr sẽ giữ được vẻ ngoài chỉn chu, phù hợp với các gia đình yêu cầu cao về độ sạch và tính thẩm mỹ. 2. Vòi lavabo nóng lạnh vận hành êm nhờ lõi Sedal Tây Ban Nha Một chiếc vòi lavabo tốt không chỉ đẹp ở lớp vỏ bên ngoài. Trải nghiệm đóng mở, điều chỉnh nướ','het-hang',14949,NULL,NULL,1777387120313,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-VL6031B-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9600q9i47pclul911c','SJ-LB-VL0213B-MẠ','Vòi Lavabo mạ Chrome cao cấp Seajong SJ-VL0213B','hang-hoa','Seajong','VL0213B','','Mạ Chrome','cmoiqcoxp00igi47peur5b8e8','cái',0.0,0.0,0.0,3700000.0,NULL,'Thông tin mua hàng tại Seajong Hotline: 1900.633.862 Website: https://seajong.com/ DSSP: https://seajong.com/voi-lavabo/ Fanpage: https://facebook.com/seajong.official/ Seajong – Showroom Chính: Sảnh Tòa nhà CT3 Cầu Diễn,Phường Phúc Diễn, Hà Nội Seajong – Showroom Mạnh Cường: 148 Đại Mỗ, Phường Đại Mỗ, TP. Hà Nội Seajong – Showroom Đại Nam: 359 Phúc Diễn, Phường Xuân Phương, TP. Hà Nội Seajong – Showroom Tuấn Hòa: 78 Nguyễn Sỹ Sách, Hưng Phúc, TP Vinh, Nghệ An','het-hang',14957,NULL,NULL,1777387120314,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-VL0213B-SR1.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9f00qhi47pqejqwlie','SJ-LB-VL0905','Vòi Lavabo âm tường SJ-VL0905-SR Seajong Hàn Quốc','hang-hoa','Seajong','VL0905','','','cmoiqcoxp00igi47peur5b8e8','cái',0.0,0.0,0.0,8600000.0,NULL,'Mục Lục Toggle VÒI LAVABO ÂM TƯỜNG SJ-VL0905-SR GIẢI PHÁP KIẾN TRÚC ĐẲNG CẤP VÀ SANG TRỌNG 1. Khai phá không gian phòng tắm với vòi lavabo âm tường cao cấp 2. Kỹ nghệ luyện kim an toàn và trái tim cơ khí bền bỉ của vòi lavabo âm tường sj-vl0905-sr 3. Trải nghiệm người dùng thông minh và giải pháp thi công toàn diện VÒI LAVABO ÂM TƯỜNG SJ-VL0905-SR GIẢI PHÁP KIẾN TRÚC ĐẲNG CẤP VÀ SANG TRỌNG Trong thiết kế kiến trúc phòng tắm hạng sang hiện nay, xu hướng tối giản và giải phóng bề mặt đang trở thành thước đo của sự tinh tế. Nắm bắt trọn vẹn tư duy thiết kế đó, thương hiệu Seajong đã cho ra đời mã sản phẩm vòi lavabo âm tường sj-vl0905-sr . Được định vị là dòng sản phẩm phân khúc thượng lưu, thiết bị sở hữu giải pháp lắp đặt ẩn sâu vào cấu trúc tường bê tông, mang lại vẻ đẹp gọn gàng, thanh thoát và mở ra một cuộc cách mạng về không gian cho khu vực bàn chậu rửa mặt của gia đình bạn. 1. Khai phá không gian phòng tắm với vòi lavabo âm tường cao cấp Điểm cộng đắt giá nhất của dòng vòi lavabo âm tường cao cấp này chính là khả năng tối ưu hóa diện tích mặt bàn đá. Khác với dòng vòi đặt bàn truyền thống dễ bám cặn nước và ố vàng tại chân vòi, phần củ vòi và hộp kỹ thuật của mã sản phẩm này được chôn âm hoàn toàn phía sau lớp gạch ốp tường. Bề mặt hoàn thiện bên ngoài chỉ để lộ đầu vòi xả kéo dài độc đáo và tay gạt điều khiển thanh lịch. Đặc biệt, sản phẩm sở hữu bề mặt sáng bạc bóng bẩy. Đây là dòng vòi chậu âm tường mạ chrome 5 lớp chuyên sâu (gồm đồng, nikel đa tầng và chrome ngoại vi), tạo hiệu ứng phản quang rực rỡ như gương kính, mang lại diện mạo tinh khôi, thách thức mọi tác nhân gây oxy hóa hay xỉn màu trong môi trường ẩm ướt. 2. Kỹ nghệ luyện kim an toàn và trái tim cơ khí bền bỉ của vòi lavabo âm tường sj-vl0905-sr Do đặc thù lắp đặt âm cố định vào kết cấu tường, việc lựa chọn chất lượng vật liệu luôn được đặt lên hàng đầu nhằm tránh rủi ro rò rỉ ngầm. Thiết bị vòi lavabo âm tường sj-vl0905-sr được đúc nguyên khối từ phôi đồng cao cấp theo tiêu chuẩn Italia với hàm','het-hang',14980,NULL,NULL,1777387120323,1782621407354,'https://seajong.com/wp-content/uploads/2025/09/SJ-VL0905-GS.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9g00qki47pif3i117w','SJ-HH-TN5199B','Bồn tiểu nam cao cấp Seajong SJ-TN5199B','hang-hoa','Seajong','TN5199B','','','cmoit63ts0015i4nuzkilzk64','cái',0.0,0.0,0.0,8900000.0,NULL,'Bồn tiểu nam Seajong SJ-TN5199B là dòng sản phẩm cao cấp với thiết kế treo tường gọn gàng, hiện đại với lớp men Nano kháng khuẩn tiên tiến, vừa đảm bảo tiện nghi và vệ sinh tối đa, vừa tôn lên vẻ sang trọng cho không gian phòng tắm. Tính năng công nghệ nổi bật Bồn tiểu nam SJ-TN5199B được thiết kế treo tường chắc chắn, tối ưu diện tích và mang lại sự ngăn nắp, phù hợp với mọi không gian phòng tắm. Hệ thống xả nước thủ công tiện dụng, sử dụng phương thức xả nhấn nút truyền thống với cơ chế vận hành đơn giản, bền bỉ và dễ sử dụng. Lượng nước xả mỗi lần chỉ từ 4–5 lít, đảm bảo khả năng làm sạch hiệu quả mà vẫn tiết kiệm chi phí. Thân bồn được làm từ sứ cao cấp phủ lớp men Nano siêu mịn, sáng bóng, giúp chống bám bẩn, hạn chế ố vàng và ngăn ngừa vi khuẩn phát triển. Đồng thời, lớp men chống trầy xước và duy trì độ trắng sáng lâu dài, thích hợp với môi trường ẩm ướt. Trang bị bộ lọc chống mùi inox ngăn mùi hôi quay ngược từ hệ thống thoát nước, đồng thời giúp nhà vệ sinh luôn khô thoáng và dễ chịu. ⇒Xem thêm các mẫu bồn tiểu nam khác của Seajong ngay⇒','het-hang',15400,NULL,NULL,1777387120325,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-TN5199B.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9h00qni47p0umtqbnr','SJ-HH-TN5032S','Bồn tiểu nam cảm ứng Seajong SJ-TN5032S','hang-hoa','Seajong','TN5032S','','','cmoit63ts0015i4nuzkilzk64','cái',0.0,0.0,0.0,9300000.0,NULL,'Bồn tiểu nam Seajong SJ-TN5032S là giải pháp hiện đại dành cho không gian vệ sinh công cộng và gia đình, nơi đề cao sự tiện nghi, vệ sinh và tính thẩm mỹ. Với thiết kế treo tường gọn gàng, cảm biến tự động thông minh cùng lớp men Nano kháng khuẩn, sản phẩm không chỉ tối ưu trải nghiệm sử dụng mà còn góp phần nâng tầm đẳng cấp cho không gian. Tính năng công nghệ nổi bật Ứng dụng cảm biến hồng ngoại hiện đại với phạm vi phát hiện đến 600–650mm, bồn tiểu tự động xả nước sau khi sử dụng mà không cần chạm tay. Cơ chế vận hành hoàn toàn tự động giúp đảm bảo vệ sinh tối đa, tiện lợi và an toàn trong mọi không gian. Hệ thống cảm biến cho phép bồn tiểu xả trước khi sử dụng để giữ bề mặt sạch sẽ và tự động xả sau khi người dùng rời đi. Ngoài ra, thiết bị còn định kỳ xả nước mỗi 2 giờ, ngăn ngừa cặn vôi bám vào van và đường ống, duy trì hiệu quả vận hành lâu dài. Trang bị bộ lọc chống mùi thép không gỉ, ngăn mùi hôi từ hệ thống thoát nước quay ngược trở lại. Đồng thời, đường thoát nước được thiết kế tối ưu giúp hạn chế tắc nghẽn và giữ nhà vệ sinh luôn khô thoáng. Bề mặt bồn tiểu được phủ men Nano 3 lớp siêu mịn, sáng bóng và kháng khuẩn hiệu quả, hạn chế bám bẩn, ngăn ngừa ố vàng, chống trầy xước và duy trì độ trắng sáng bền đẹp theo thời gian, đồng thời đảm bảo kết cấu chắc chắn, chống nứt vỡ trong môi trường ẩm ướt. Hai phương thức thoát nước linh hoạt hỗ trợ cả xả tường (thoát nước phía sau, kết nối âm tường) và xả sàn (thoát nước trực tiếp xuống sàn), đáp ứng đa dạng điều kiện lắp đặt thực tế. Lượng nước xả chỉ 4–5 lít/lần, được thiết kế dạng xả tràn giúp làm sạch hiệu quả mà vẫn tiết kiệm chi phí sử dụng. ⇒Xem thêm các mẫu bồn tiểu nam khác của Seajong ngay⇒','het-hang',15234,NULL,NULL,1777387120326,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-TN5032S.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9o00qsi47pehhv7s0t','SJ-BT-SB0602-MẠ','SEN BỒN TẮM SEAJONG SJ-SB0602','hang-hoa','Seajong','SB0602','','Mạ Chrome, Mạ PVD, Mạ Vàng','cmoiqcox700h7i47ph6mzei4q','cái',0.0,0.0,0.0,23600000.0,NULL,'Mục Lục Toggle Sen bồn tắm sj-sb0602 giải pháp sen tắm bồn cao cấp cho phòng tắm hiện đại 1 Sen bồn tắm cao cấp với bề mặt mạ 5 lớp bền đẹp 2 Van lõi Sedal giúp vận hành ổn định 3 Dây sen EPDM bọc inox SUS304 linh hoạt 3 Ưu điểm và nhược điểm sen bồn tắm sj-sb0602 4 Có nên chọn sen bồn tắm sj-sb0602? Sen bồn tắm sj-sb0602 giải pháp sen tắm bồn cao cấp cho phòng tắm hiện đại Sen bồn tắm sj-sb0602 là mẫu sen tắm bồn cao cấp của Seajong, được phát triển cho những không gian phòng tắm cần sự đồng bộ giữa thẩm mỹ, độ bền và trải nghiệm sử dụng an toàn. Sản phẩm phù hợp với bồn tắm đặt sàn, bồn tắm âm sàn hoặc các phòng tắm cao cấp theo phong cách khách sạn, biệt thự và căn hộ hiện đại. Điểm đáng chú ý của Sen bồn tắm sj-sb0602 nằm ở cấu trúc vật liệu. Thân chính sử dụng đồng 61%, kết hợp các chi tiết SUS304 và ABS chất lượng cao. Đồng là vật liệu quan trọng trong các dòng sen bồn tắm cao cấp vì có khả năng chịu áp tốt, ổn định khi tiếp xúc thường xuyên với nước nóng lạnh và giúp tăng tuổi thọ sản phẩm. Công nghệ đúc trọng lực kết hợp phân tách chì giúp kiểm soát tốt hơn độ an toàn của nguồn nước, với hàm lượng Pb khoảng 0,01%, thấp hơn nhiều so với mức khuyến cáo 0,25%. 1 Sen bồn tắm cao cấp với bề mặt mạ 5 lớp bền đẹp Sen bồn tắm sj-sb0602 được xử lý bề mặt bằng công nghệ mạ 5 lớp cao cấp. Lớp mạ giúp tăng khả năng chống oxy hóa, hạn chế xỉn màu và giữ độ sáng bóng trong môi trường phòng tắm có độ ẩm cao. Sản phẩm có nhiều lựa chọn hoàn thiện như mạ Chrome, mạ PVD và mạ vàng, phù hợp với nhiều phong cách thiết kế nội thất khác nhau. 2 Van lõi Sedal giúp vận hành ổn định Một trong những yếu tố quyết định chất lượng của sen tắm nóng lạnh là lõi trộn. Sen bồn tắm sj-sb0602 sử dụng lõi trộn Sedal Tây Ban Nha, giúp thao tác đóng mở nhẹ, điều chỉnh nóng lạnh chính xác và hạn chế hiện tượng rò rỉ sau thời gian dài sử dụng. Đây là điểm rất quan trọng với các sản phẩm sen bồn tắm có tần suất sử dụng thường xuyên. 3 Dây sen EPDM bọc inox SUS304 linh hoạt Dây sen của sản phẩm sử d','het-hang',15405,NULL,NULL,1777387120332,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-SB0602-CR.webp',NULL,NULL,NULL);
