INSERT INTO InventoryItem VALUES('cmoiqef9t00r0i47p45zj5nwc','SJ-BT-BT005CM','Bồn tắm Acrylic mờ cao cấp Seajong SJ-BT005CM','hang-hoa','Seajong','BT005CM','','','cmoiqcox700h7i47ph6mzei4q','cái',0.0,0.0,0.0,38000000.0,NULL,'⇒Xem thêm các mẫu bồn tắm khác của Seajong ngay⇒','het-hang',15426,NULL,NULL,1777387120337,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-BT005CM-1.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9u00r3i47p93wuhly1','SJ-SC-SC0071B-CHR','Sen cây tắm đứng Seajong SJ-SC0071B-SR','hang-hoa','Seajong','SC0071B','','Chrome','cmoiqcoxb00hgi47pryg6n57p','cái',8.0,0.0,550000.0,16000000.0,NULL,'Sen cây truyền thống cao cấp Seajong SJ-SC0071B-SR Sen cây truyền thống cao cấp SEAJONG là dòng sản phẩm được thiết kế dành cho những không gian phòng tắm hiện đại, sang trọng và yêu cầu cao về độ bền, độ an toàn cũng như trải nghiệm sử dụng hằng ngày. Với kiểu dáng thanh lịch, bề mặt mạ Chrome sáng bóng và kết cấu chắc chắn, sản phẩm không chỉ đáp ứng nhu cầu tắm rửa cơ bản mà còn góp phần nâng tầm thẩm mỹ cho toàn bộ không gian phòng tắm. Thân củ sen được chế tác từ đồng Italia 61% , cho khả năng chịu lực, chịu áp lực nước tốt và duy trì độ ổn định lâu dài trong môi trường ẩm ướt. Cần sen cây sử dụng inox SUS304 Posco Hàn Quốc , giúp hạn chế han gỉ, chống ăn mòn và tăng độ bền cho toàn bộ hệ thống sen. Bề mặt sản phẩm được hoàn thiện bằng công nghệ mạ Chrome 5 lớp , tạo độ sáng bóng, dễ vệ sinh, chống bong tróc và giữ vẻ đẹp sang trọng trong quá trình sử dụng. Điểm mạnh quan trọng của sản phẩm nằm ở công nghệ sản xuất an toàn. Thân củ được đúc áp lực thấp phân tách chì , kiểm soát hàm lượng chì ở mức 0,025% Pb , giúp hạn chế nguy cơ thôi nhiễm kim loại nặng vào nguồn nước, an toàn hơn cho sức khỏe người dùng và thân thiện hơn với môi trường. Sản phẩm Sen cây truyền thống cao cấp SEAJONG sử dụng van lõi Sedal Tây Ban Nha , cho khả năng đóng mở êm ái, điều chỉnh nóng lạnh chính xác, hạn chế rò rỉ và nâng cao tuổi thọ vận hành. Theo thông số trên website, mẫu SJ-SC0102B-SR có chiều cao tổng thể 1400mm, dây sen lõi EPDM bọc inox SUS304 dài 1500mm, bát sen trần nhập khẩu Hàn Quốc và lõi trộn SEDAL Tây Ban Nha. Ngoài ra, sản phẩm ứng dụng công nghệ Wartesoft , giúp dòng nước phun ra mềm mại, đều và dễ chịu hơn khi tiếp xúc với da. Hệ thống tắm mưa kết hợp tay sen linh hoạt mang lại trải nghiệm thư giãn thoải mái, phù hợp cho gia đình, căn hộ cao cấp, khách sạn, showroom và các công trình phòng tắm hiện đại. Sen cây truyền thống cao cấp SEAJONG hoàn toàn là một lựa chọn thay thế tốt nhất cho sen cây toto, sen cây inax, sen cây viglace, sen cây enic và sen cây grohe','con-hang',15655,NULL,NULL,1777387120339,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-071C.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9v00r6i47ptk3iwt0b','SJ-HH-NL0041B-MẠ','Sen tắm nóng lạnh cao cấp Seajong SJ-NL0041B-SR','hang-hoa','Seajong','NL0041B','','Mạ Chrome','cmoit63vb0029i4nu7om7n1n0','cái',0.0,0.0,0.0,4600000.0,NULL,'Được thiết kế để đáp ứng cả công năng lẫn thẩm mỹ, sen tắm Seajong SJ-NL0041B-SR mang đến giải pháp tối ưu cho không gian phòng tắm. Với chất liệu đồng nguyên chất, công nghệ mạ 5 lớp, sản phẩm đảm bảo sự bền bỉ, tiện nghi và an toàn trong suốt quá trình sử dụng. Tính năng công nghệ Chất liệu bằng đồng nguyên chất ≥ 61% nhập khẩu từ Ý, hàm lượng chì là 0,1% hơn nhiều so với ngưỡng 0,25% do WHO khuyến nghị, an toàn tuyệt đối cho sức khỏe. Công nghệ mạ 5 lớp (Cu-Ni-Ni-Cr-Cr) có khả năng chống ăn mòn, tăng độ bám, chống trầy xước và bong tróc, bền màu vượt trội. Toàn bộ quy trình mạ đạt chuẩn DIN EN 248 và vượt qua kiểm nghiệm Salt Spray Test 24h theo ASTM B117, chứng minh khả năng kháng ăn mòn, chống gỉ sét, không bong tróc, không đổi màu trong mọi điều kiện môi trường. Van lõi sứ cao cấp Sedal vượt qua bài test đóng mở 500.000 lần, tương đương hơn 30 năm sử dụng. Gioăng đi kèm hạn chế rung chấn, ngăn rò rỉ nước và không gây tiếng ồn, mang đến trải nghiệm sử dụng mượt mà và êm ái. Xử lý bề mặt bằng công nghệ CNC kết hợp robot đánh bóng tự động cho bề mặt đồng đều, đạt độ bóng gương theo tiêu chuẩn châu Âu với độ nhám Ra ≤ 0.2 µm và độ bóng Gloss ≥ 85 GU. Phần kết Seajong không chỉ mang đến một sản phẩm sen tắm nóng lạnh cao cấp mà còn là cam kết về chất lượng, sự an toàn và độ bền lâu dài. Liên hệ ngay Seajong để được hỗ trợ tư vấn chi tiết và trải nghiệm sự khác biệt.','het-hang',15664,NULL,NULL,1777387120340,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-NL0041B-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9w00r9i47pzyxsu1eb','SJ-HH-NL0039B-MẠ','Sen tắm nóng lạnh cao cấp Seajong SJ-NL0039B-SR','hang-hoa','Seajong','NL0039B','','Mạ Chrome','cmoit63vb0029i4nu7om7n1n0','cái',0.0,0.0,0.0,5100000.0,NULL,'Seajong mang đến sen tắm nóng lạnh cao cấp SJ-NL0039B-SR được chế tác từ chất liệu đồng nguyên chất kết hợp công nghệ mạ 5 lớp tiên tiến, vừa đảm bảo tính thẩm mỹ, vừa mang lại sự an toàn, bền bỉ và tiện nghi vượt trội trong quá trình sử dụng. Tính năng công nghệ Sử dụng đồng nguyên chất ≥ 61% nhập khẩu trực tiếp từ Ý, hàm lượng chì chỉ 0,1%, thấp hơn nhiều so với ngưỡng 0,25% do WHO khuyến nghị, đảm bảo an toàn tuyệt đối cho sức khỏe người dùng. Công nghệ mạ 5 lớp (Cu-Ni-Ni-Cr-Cr) có khả năng chống ăn mòn, tăng độ bám, chống trầy xước và bong tróc, giữ màu bền đẹp theo thời gian. Quy trình mạ đạt chuẩn DIN EN 248 và vượt qua kiểm nghiệm Salt Spray Test 24h theo ASTM B117, chứng minh khả năng chống ăn mòn, chống gỉ sét, không bong tróc và không đổi màu ngay cả trong môi trường có độ ẩm cao. Van lõi sứ Sedal cao cấp bền bỉ với hơn 500.000 lần đóng mở, tương đương hơn 30 năm sử dụng. Gioăng đi kèm giảm rung, ngăn rò rỉ nước và không gây tiếng ồn, mang đến trải nghiệm dùng mượt mà và êm ái. Bề mặt sáng bóng chuẩn châu Âu, được xử lý bằng CNC và robot đánh bóng tự động, đạt độ nhám Ra ≤ 0.2 µm và độ bóng Gloss ≥ 85 GU, cho vẻ ngoài tinh tế và sang trọng.','het-hang',15665,NULL,NULL,1777387120341,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-NL0039B-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9x00rci47pjzyhe7b9','SJ-SC-SC0097B-CHR','Sen cây tắm đứng mạ PVD cao cấp Seajong SJ-SC0097B-GR','hang-hoa','Seajong','SC0097B','','Chrome','cmoiqcoxb00hgi47pryg6n57p','cái',0.0,0.0,0.0,28500000.0,NULL,'','het-hang',18336,NULL,NULL,1777387120342,1782621407354,'https://seajong.com/wp-content/uploads/2026/04/SJ-SC0097B-GR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqef9z00rfi47pwp9kpsvj','SJ-SC-SC0096B-MẠ','Sen cây tắm đứng Seajong SJ-SC0096B-SR','hang-hoa','Seajong','SC0096B','','Mạ Chrome','cmoiqcoxb00hgi47pryg6n57p','cái',0.0,0.0,0.0,6800000.0,NULL,'Mẫu sen cây đồng truyền thống Seajong SJ-SC0096B-SR được chế tác từ đồng nguyên chất và hoàn thiện bằng công nghệ mạ 5 lớp tiên tiến. Sản phẩm không chỉ mang đến vẻ đẹp sang trọng, bền bỉ mà còn đảm bảo độ an toàn cao, giúp phòng tắm trở nên tiện nghi và hiện đại hơn. Tính năng công nghệ nổi bật Hệ thống khóa van nhiệt độ thông minh Thermostatic Cartridge đạt chuẩn EN111 châu Âu, duy trì nhiệt độ nước ổn định trong khoảng 38–40°C, ngăn ngừa tình trạng sốc nhiệt và bảo vệ an toàn cho trẻ nhỏ, người cao tuổi cũng như những người có làn da nhạy cảm. Thân sen bằng đồng nguyên chất ≥ 61% nhập khẩu từ Ý, hàm lượng chì chỉ 0,01% – thấp hơn 25 lần so với khuyến nghị của WHO. Ống dẫn nước làm từ inox SUS304 mạ Chrome 5 lớp giúp chống oxy hóa, chống ăn mòn và duy trì vẻ sáng bóng lâu dài. Bát sen trần và tay sen tắm bằng nhựa ABS cao cấp, bề mặt mạ Chrome sáng bóng, trọng lượng nhẹ, dễ cầm nắm. Tay sen được thiết kế với 3 chế độ phun linh hoạt (phun thường, massage, phun kết hợp) mang đến trải nghiệm thư giãn tối đa. Dây sen lõi EPDM bọc inox SUS304 – vật liệu cao cấp giúp dây sen có độ dẻo dai, chống xoắn, chịu lực tốt và kháng hóa chất, đảm bảo độ bền vượt trội ngay cả khi tiếp xúc thường xuyên với nước nóng và chất tẩy rửa. Bề mặt sản phẩm được xử lý bằng công nghệ mạ 5 lớp gồm 1,8 µm Nikel và 0,85 µm Chrome, đạt độ sáng bóng đạt chuẩn châu Âu với độ nhám Ra ≤ 0,2 µm cùng độ bóng Gloss ≥ 85 GU có khả năng chống trầy xước, chống bong tróc và bền màu trong mọi điều kiện môi trường. Bộ phụ kiện đồng bộ đi kèm bao gồm bát sen trần & tay sen ABS, dây sen inox dài 1,5m, ống thẳng và cong SUS304, chân sen inox, giá đỡ trượt tay sen, khay đựng xà bông và đầy đủ phụ kiện lắp đặt, mang lại sự tiện lợi và thẩm mỹ khi sử dụng.','het-hang',15677,NULL,NULL,1777387120343,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-SC0096B-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqefa000rii47pqoknv88d','SJ-SC-SC0102V','Sen cây tắm đứng Seajong SJ-SC0102V-SR','hang-hoa','Seajong','SC0102V','','','cmoiqcoxb00hgi47pryg6n57p','cái',0.0,0.0,0.0,9950000.0,NULL,'Sen cây tắm đứng Seajong SJ-SC0102V-SR- Tinh tế- Hiện đại- Bền bỉ Sen cây tắm đứng Seajong được thiết kế dành cho những không gian phòng tắm theo phong cách tinh tế – hiện đại – bền bỉ . Sản phẩm kết hợp giữa kiểu dáng thanh lịch, chất liệu cao cấp và trải nghiệm sử dụng ổn định, mang đến cảm giác tắm thoải mái, mạnh mẽ nhưng vẫn êm dịu trong từng dòng nước. Phần thân củ sen sử dụng đồng hàm lượng 61% , cho kết cấu chắc chắn, chịu áp lực nước tốt và hạn chế oxy hóa trong môi trường ẩm ướt. Bề mặt thân củ sen cây cao cấp được mạ 5 lớp , giúp sản phẩm có độ sáng bóng sang trọng, tăng khả năng chống bong tróc, chống xỉn màu và giữ vẻ đẹp bền lâu theo thời gian. Điểm cốt lõi tạo nên độ bền vận hành của sen cây tắm đứng Seajong nằm ở van lõi Ceramic Sedal từ Tây Ban Nha . Đây là bộ phận quan trọng giúp thao tác đóng mở nước nhẹ, điều chỉnh nóng lạnh chính xác, hạn chế rò rỉ và duy trì sự ổn định trong quá trình sử dụng lâu dài. Phần cần sen cây hàn quốc sử dụng inox SUS304 của POSCO , có khả năng chống gỉ tốt, chịu nước thường xuyên và giữ form chắc chắn. Đây là lựa chọn vật liệu phù hợp với điều kiện khí hậu nóng ẩm tại Việt Nam, đặc biệt trong các không gian phòng tắm sử dụng hằng ngày. Bát sen tắm được ứng dụng công nghệ Watersoft tạo bọt , giúp dòng nước phun ra mềm hơn, dày hơn và tạo cảm giác thư giãn khi tắm. Hệ thống núm sen mạ chrome với lõi công nghệ độc quyền hỗ trợ chống tắc, chống xiên tia, giúp tia nước đều, ổn định và dễ vệ sinh sau thời gian sử dụng. Với chế độ bảo hành 5 năm , sen cây tắm đứng truyền thống Seajong không chỉ là một thiết bị phòng tắm thông thường, mà là giải pháp nâng cấp trải nghiệm sống: đẹp hơn, bền hơn và an tâm hơn cho mỗi gia đình.','het-hang',15683,NULL,NULL,1777387120345,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-SC0102V-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqefa300rmi47pku1iztow','SJ-VB-VB011-15693','Vòi bếp ống dây mềm cao cấp Seajong SJ-VB011-BR','hang-hoa','Seajong','VB011','','','cmoiqef5x00kwi47ph8liz7l2','cái',0.0,0.0,0.0,10000000.0,NULL,'Vòi bếp Seajong SJ-VB011-BR là sự kết hợp tinh tế giữa thiết kế sang trọng, chất liệu bền bỉ và công nghệ tiên tiến, mang đến trải nghiệm tiện nghi vượt trội. Đây là lựa chọn lý tưởng cho những gia đình muốn nâng cấp không gian bếp, vừa đáp ứng công năng hiện đại vừa toát lên vẻ đẹp tinh tế, đẳng cấp. Tính năng công nghệ nổi bật Dây rút linh hoạt 80cm với đầu vòi 3 chế độ dễ dàng điều chỉnh giữa dòng chảy thường, phun xoè và phun mạnh, đáp ứng đa dạng nhu cầu trong nấu nướng và vệ sinh bếp. Thân vòi được đúc từ đồng nguyên chất ≥ 61% nhập khẩu từ Ý, có khả năng chống ăn mòn vượt trội, đảm bảo an toàn tuyệt đối cho sức khỏe người dùng. Van lõi trộn Sedal cao cấp vượt qua thử nghiệm trên 500.000 lần đóng/mở, tương đương hơn 30 năm sử dụng. Gioăng đi kèm giúp hạn chế rung chấn, chống rò rỉ nước, mang lại sự êm ái và mượt mà khi vận hành. Bề mặt xử lý công nghệ CNC và robot đánh bóng tự động, đạt độ nhám Ra ≤ 0.2 µm và độ bóng Gloss ≥ 85 GU, mang lại vẻ sáng bóng đạt chuẩn châu Âu. Quy trình mạ chuẩn DIN EN 248, vượt qua kiểm nghiệm Salt Spray Test 24h (ASTM B117), đảm bảo khả năng chống gỉ sét, chống bong tróc, chống trầy xước và giữ màu bền đẹp ngay cả trong môi trường ẩm ướt. Phần kết Với thiết kế sang trọng, công nghệ hiện đại và độ bền đạt chuẩn quốc tế, vòi bếp Seajong SJ-VB011-BR không chỉ là một thiết bị nhà bếp mà còn là điểm nhấn nâng tầm không gian sống. Liên hệ ngay để được hỗ trợ tư vấn chi tiết và sở hữu sản phẩm chính hãng cùng chính sách bảo hành uy tín. ⇒Xem thêm các mẫu vòi bếp khác của Seajong ngay⇒','het-hang',15693,NULL,NULL,1777387120347,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-VB011-BR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqefa400rpi47pclu2s6em','SJ-VB-VB010','Vòi bếp dây rút cao cấp Seajong SJ-VB010-SR','hang-hoa','Seajong','VB010','','','cmoiqef5x00kwi47ph8liz7l2','cái',0.0,0.0,0.0,8000000.0,NULL,'Vòi bếp Seajong SJ-VB010-SR mang đến sự hòa quyện hoàn hảo giữa thiết kế sang trọng, chất liệu cao cấp và công nghệ hiện đại. Sản phẩm không chỉ đáp ứng tối đa nhu cầu sử dụng hằng ngày mà còn tôn lên vẻ tinh tế, đẳng cấp cho không gian bếp – lựa chọn lý tưởng cho những ai đề cao chất lượng và thẩm mỹ. Tính năng công nghệ nổi bật Dây rút linh hoạt dài 80cm cùng đầu vòi 3 chế độ (dòng chảy thường, phun xoè, phun mạnh) giúp điều chỉnh dễ dàng, đáp ứng mọi nhu cầu nấu nướng và vệ sinh. Thân vòi đúc từ đồng nguyên chất ≥61% nhập khẩu Ý, chống ăn mòn tối ưu và an toàn tuyệt đối cho sức khỏe. Van lõi trộn Sedal cao cấp vượt qua hơn 500.000 lần đóng/mở – tương đương 30 năm sử dụng, kết hợp gioăng giảm rung, chống rò rỉ, vận hành êm ái, bền bỉ. Bề mặt được gia công bằng công nghệ CNC và robot đánh bóng tự động, đạt độ bóng chuẩn châu Âu (Ra ≤ 0.2 µm, Gloss ≥ 85 GU). Toàn bộ lớp mạ tuân theo tiêu chuẩn DIN EN 248, vượt qua kiểm nghiệm Salt Spray Test 24h (ASTM B117), đảm bảo chống gỉ sét, bong tróc, trầy xước và giữ màu sáng đẹp lâu dài ngay cả trong môi trường ẩm cao. Phần kết Vòi bếp Seajong SJ-VB010-SR kết hợp thiết kế sang trọng và công nghệ hiện đại, trở thành điểm nhấn tinh tế cho không gian bếp. Liên hệ ngay để nhận tư vấn và sở hữu sản phẩm chính hãng cùng bảo hành uy tín. ⇒Xem thêm các mẫu vòi bếp khác của Seajong ngay⇒','het-hang',15690,NULL,NULL,1777387120348,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-VB010-SR.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmoiqefa900rvi47pi0hgaxcb','SJ-VB-PK0106-15753','Bộ vòi xịt vệ sinh Seajong SJ-PK0106-SR','hang-hoa','Seajong','PK0106','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,600000.0,NULL,'Mục Lục Toggle Vòi xịt vệ sinh sj-pk0106-sr bộ vòi xịt cao cấp cho phòng tắm hiện đại 1. Thiết kế cao cấp từ nhựa ABS nguyên chất 2. Công nghệ Aril tự làm sạch sau mỗi lần sử dụng 3. Bề mặt mạ 3 lớp sáng bóng, bền đẹp 4. Núm phun silicon đàn hồi, bền bỉ 5. Dây xịt 2 lớp chắc chắn, chịu áp cao 6. Phun nước khỏe ngay cả khi áp lực nước yếu 7. Tiêu chuẩn chất lượng và bảo hành 3 năm Vòi xịt vệ sinh sj-pk0106-sr bộ vòi xịt cao cấp cho phòng tắm hiện đại Trong phòng tắm hiện đại, vòi xịt vệ sinh không chỉ là phụ kiện đi kèm bồn cầu mà còn là thiết bị ảnh hưởng trực tiếp đến sự tiện nghi, vệ sinh và trải nghiệm sử dụng hằng ngày. Vòi xịt vệ sinh sj-pk0106-sr của Seajong được phát triển theo hướng bền bỉ, dễ sử dụng và phù hợp với nhiều điều kiện áp lực nước tại gia đình Việt Nam. 1. Thiết kế cao cấp từ nhựa ABS nguyên chất Vòi xịt vệ sinh sj-pk0106-sr sử dụng đầu xịt bằng nhựa ABS nguyên chất, cho trọng lượng nhẹ nhưng vẫn đảm bảo độ cứng cáp cần thiết. Chất liệu ABS có ưu điểm là dễ tạo hình, bề mặt đẹp, cầm chắc tay và phù hợp với môi trường phòng tắm thường xuyên tiếp xúc với nước, hơi ẩm và hóa chất vệ sinh nhẹ. Thiết kế đầu xịt gọn, hiện đại, dễ thao tác trong nhiều tư thế sử dụng. Đây là điểm quan trọng vì vòi xịt vệ sinh là sản phẩm được sử dụng hằng ngày với tần suất cao. Một thiết kế tốt phải cho cảm giác cầm chắc, bấm nhẹ, phản hồi nhanh và không gây mỏi tay khi dùng lâu. 2. Công nghệ Aril tự làm sạch sau mỗi lần sử dụng Điểm nổi bật của vòi xịt vệ sinh sj-pk0106-sr là tính năng độc quyền tự làm sạch sau mỗi lần sử dụng với công nghệ Aril. Công nghệ này giúp hạn chế cặn bẩn bám lại ở vùng đầu phun, hỗ trợ duy trì dòng nước ổn định và giữ cho đầu xịt sạch sẽ hơn trong quá trình sử dụng lâu dài. Với sản phẩm dùng trong khu vực nhà vệ sinh, khả năng tự làm sạch là lợi thế thực tế. Người dùng không chỉ cần một vòi xịt mạnh mà còn cần sản phẩm sạch, ít bám cặn, dễ bảo trì và giữ được hiệu quả phun nước theo thời gian. 3. Bề mặt mạ 3 lớp sáng bóng, bền đẹp Bề mặt của ','het-hang',15753,NULL,NULL,1777387120354,1782621407354,'https://seajong.com/wp-content/uploads/2025/10/SJ-PK0106-SR-2.webp',NULL,NULL,NULL);
