INSERT INTO InventoryItem VALUES('cmoiqefb600tui47pfc216rkf','SJ-HH-G1032P','Ga thoát sàn SUS304 cao cấp SJ-G1032P','hang-hoa','Seajong','G1032P','','','cmoiqefcg00vci47pfpuzyvsj','cái',0.0,0.0,0.0,780000.0,NULL,'Ga thoát sàn SJ-G1032P là phiên bản nâng cấp với bề mặt mạ titan cao cấp, kết hợp thiết kế cắt đá âm sàn giúp “ẩn” hoàn toàn ga thoát nước, mang lại tổng thể liền mạch, sang trọng và đậm chất kiến trúc hiện đại. Ga thoát sàn SJ-G1032P với lớp phủ titan đen và thiết kế cắt đá cho phép đặt trực tiếp vật liệu sàn lên bề mặt nắp, giúp ga thoát sàn “biến mất” trong tổng thể. Đây là xu hướng thiết kế phổ biến trong các công trình cao cấp, nơi mọi chi tiết đều được tối ưu để đạt sự tinh gọn và đồng nhất. Ga thoát sàn SUS304 cao cấp SJ-G1032P- Tổng quan về sản phẩm','het-hang',16302,NULL,NULL,1777387120387,1782621407354,'https://seajong.com/wp-content/uploads/2025/11/SJ-G1032P.webp',NULL,NULL,NULL);
