INSERT INTO InventoryItem VALUES('cmqx9hboe00208oei7pqqaj0l','SJ-HH-8146H','Chậu bếp cao cấp hai hố lệch lắp âm SJ-8146H','hang-hoa','Seajong','8146H','','','cmoiqef5100j2i47pn6f3dkqw','cái',0.0,0.0,0.0,0.0,NULL,'Chậu bếp SJ-8146H với kích thước 810x460x230mm, chất liệu inox 304 cao cấp, thiết kế hai hố lệch tiện dụng, hoàn thiện bề mặt Brushed Hairline, mang đến sự tiện nghi và sang trọng cho không gian bếp của bạn. Tìm hiểu ngay Tính năng công nghệ Chất liệu inox 304 cao cấp: Chống gỉ sét, bền bỉ và an toàn cho sức khỏe người dùng. Dễ dàng lắp đặt: Hỗ trợ lắp đặt âm bàn, tạo sự liền mạch và gọn gàng cho không gian bếp. Hoàn thiện bề mặt Brushed Hairline: Tạo vẻ đẹp tinh tế, dễ dàng vệ sinh và chống bám bẩn. Phủ sơn chống gỉ, chống ồn bên ngoài: Giảm thiểu tiếng ồn khi sử dụng và tăng độ bền cho sản phẩm. Độ dày 4+1.2mm: Đảm bảo độ cứng cáp và khả năng chịu lực tốt. Công nghệ hàn tự liền, bo tròn góc: Tạo thiết kế liền mạch, tinh tế và dễ dàng vệ sinh. Kích thước lỗ xả 114mm: Thoát nước nhanh chóng, ngăn ngừa tắc nghẽn Phụ kiện kèm theo: Bộ xả, rổ cao cấp, chậu nhỏ Trọng lượng: 17kg Bảo hành: 15 năm ⇒Xem thêm các mẫu bồn rửa chén khác của Seajong ngay⇒','het-hang',9026,NULL,NULL,1782619259487,1782621407354,'https://seajong.com/wp-content/uploads/2024/12/SJ-8146H-6.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmqx9hbon002i8oeizmojsngu','SJ-HH-8245U','Chậu bếp hai hố cao cấp SJ-8245U','hang-hoa','Seajong','8245U','','','cmoiqef5100j2i47pn6f3dkqw','cái',0.0,0.0,0.0,0.0,NULL,'Chậu bếp SJ-8245U với kích thước 82x45x23cm, chất liệu inox SUS304 cao cấp, thiết kế hai hố rộng rãi, hoàn thiện bề mặt Brushed Hairline, mang đến sự tiện nghi và sang trọng cho không gian bếp của bạn. Tính năng công nghệ Chất liệu inox SUS304 cao cấp: Chống gỉ sét, bền bỉ và an toàn cho sức khỏe người dùng. Hoàn thiện bề mặt Brushed Hairline: Tạo vẻ đẹp tinh tế, dễ dàng vệ sinh và chống bám bẩn. Phủ sơn chống gỉ, chống ồn, chống bốc hơi bên ngoài: Giảm thiểu tiếng ồn khi sử dụng, ngăn chặn hiện tượng bốc hơi và tăng độ bền cho sản phẩm. Độ dày 4+1.2mm: Đảm bảo độ cứng cáp và khả năng chịu lực tốt. Công nghệ hàn tự liền, bo tròn góc siêu rộng: Tạo thiết kế liền mạch, tinh tế và dễ dàng vệ sinh. Kích thước lỗ xả 114mm: Thoát nước nhanh chóng, ngăn ngừa tắc nghẽn. Bảo hành: 15 năm Thông tin chính hãng Seajong Hotline: 1900.633.862 Website: https://seajong.com/ Fanpage: https://facebook.com/seajong.official/ Seajong – Showroom Chính: Sảnh Tòa nhà CT3 Cầu Diễn,Phường Phúc Diễn, Hà Nội Seajong – Showroom Mạnh Cường: 148 Đại Mỗ, Phường Đại Mỗ, TP. Hà Nội Seajong – Showroom Thiên Thuận: Thôn Mai Thành, phường Đông Kinh, tỉnh Lạng Sơn Seajong – Showroom Tuấn Hòa: 78 Nguyễn Sỹ Sách, Hưng Phúc, TP Vinh, Nghệ An ⇒Xem thêm các mẫu bồn rửa chén khác của Seajong ngay⇒','het-hang',9054,NULL,NULL,1782619259496,1782621407354,'https://seajong.com/wp-content/uploads/2024/12/SJ-8245U-6.webp',NULL,NULL,NULL);
INSERT INTO InventoryItem VALUES('cmqx9hbov00308oeiziyjq3sa','SJ-HH-6846GR','Chậu bếp một hố cao cấp SJ-6846GR','hang-hoa','Seajong','6846GR','','','cmoiqef5100j2i47pn6f3dkqw','cái',0.0,0.0,0.0,0.0,NULL,'Chậu bếp SJ-6846GR với kích thước 680x450x230mm, chất liệu inox 304 cao cấp, thiết kế một hố rộng rãi, hoàn thiện bề mặt phủ Nano kết hợp hạt chống xước (NE) và men chống bám bẩn (Anti-Fouling), mang đến sự tiện nghi và sang trọng cho không gian bếp của bạn. Tính năng công nghệ Chất liệu inox 304 cao cấp: Chống gỉ sét, bền bỉ và an toàn cho sức khỏe người dùng. Hoàn thiện bề mặt phủ Nano, hạt chống xước (NE) và men chống bám bẩn (Anti-Fouling): Tăng cường độ bền, chống trầy xước và dễ dàng vệ sinh. Phủ sơn chống gỉ, chống ồn bên ngoài: Giảm thiểu tiếng ồn khi sử dụng và tăng độ bền cho sản phẩm. Độ dày 3+1.0mm: Đảm bảo độ cứng cáp và khả năng chịu lực tốt. Công nghệ hàn tự liền, bo tròn góc: Tạo thiết kế liền mạch, tinh tế và dễ dàng vệ sinh. Kích thước lỗ xả 185mm: Thoát nước nhanh chóng, ngăn ngừa tắc nghẽn Bảo hành: 15 năm Thông tin chính hãng Seajong Hotline: 1900.633.862 Website: https://seajong.com/ Fanpage: https://facebook.com/seajong.official/ Seajong – Showroom Chính: Sảnh Tòa nhà CT3 Cầu Diễn,Phường Phúc Diễn, Hà Nội Seajong – Showroom Mạnh Cường: 148 Đại Mỗ, Phường Đại Mỗ, TP. Hà Nội Seajong – Showroom Thiên Thuận: Thôn Mai Thành, phường Đông Kinh, tỉnh Lạng Sơn Seajong – Showroom Tuấn Hòa: 78 Nguyễn Sỹ Sách, Hưng Phúc, TP Vinh, Nghệ An ⇒Xem thêm các mẫu bồn rửa chén khác của Seajong ngay⇒','het-hang',9085,NULL,NULL,1782619259504,1782621407354,'https://seajong.com/wp-content/uploads/2024/12/SJ-6846GR-1.webp',NULL,NULL,NULL);
