INSERT INTO SeajongProduct VALUES(9103,'chau-bep-mot-ho-sj-7645gs','https://seajong.com/chau-bep-oot-ho-sj-7645gs/','CHẬU BẾP MỘT HỐ – SJ-7645GS SEAJONG','Chậu bếp SJ-7645GS là sản phẩm cao cấp, mang lại sự tiện lợi, độ bền cao và thẩm mỹ sang trọng cho không gian bếp của bạn. Khám phá toàn bộ bên dưới ngay. Công nghệ có gì nổi bật? Được chế tạo từ inox 304, chậu SJ-7645GS có khả năng chống gỉ, chịu lực [&hellip;]','Chậu bếp SJ-7645GS là sản phẩm cao cấp, mang lại sự tiện lợi, độ bền cao và thẩm mỹ sang trọng cho không gian bếp của bạn. Khám phá toàn bộ bên dưới ngay. Công nghệ có gì nổi bật? Được chế tạo từ inox 304, chậu SJ-7645GS có khả năng chống gỉ, chịu lực và mài mòn rất tốt, không bị oxy hóa trong môi trường bếp ẩm ướt, giúp chậu giữ được vẻ đẹp và độ bền lâu dài. Hoàn thiện bề mặt NE và Men Anti-Fouling giúp chậu chống xước hiệu quả, giữ bề mặt luôn sáng bóng, chống bám bẩn giúp hạn chế vết bẩn và đảm bảo vệ sinh cho bếp. Phần bên ngoài của chậu được phủ lớp sơn chống gỉ, giúp bảo vệ bề mặt khỏi sự ăn mòn. Công nghệ chống ồn giúp giảm thiểu tiếng ồn khi nước chảy, mang lại không gian bếp yên tĩnh. Với độ dày 3+1.0 mm, chậu có khả năng chịu lực tốt, chống va đập và mài mòn hiệu quả. Công nghệ hàn tự liền giúp chậu có một kết cấu liền mạch, không có mối hàn lộ liễu, tạo nên thiết kế tinh tế, dễ dàng vệ sinh và bảo trì. Lỗ xả có kích thước lớn 185 mm giúp việc thoát nước diễn ra nhanh chóng, tránh tình trạng nước đọng, giúp bạn sử dụng chậu một cách hiệu quả. Chậu được trang bị bộ xả, rổ inox, chậu nhỏ, thớt gỗ và thớt inox cao cấp, tạo sự tiện lợi trong việc sử dụng hàng ngày. Thông tin chính hãng Seajong Seajong là thương hiệu hoạt động sản xuất và kinh doanh các sản phẩm gia dụng như thiết bị vệ sinh và thiết bị nhà bếp theo tiêu chuẩn công nghệ Hàn Quốc. Nếu bạn đang có nhu cầu và tìm kiếm nơi mua hàng chính hãng, hãy liên hệ với chúng tôi để được hỗ trợ và tư vấn tận tình nhất. Hotline: 1900.633.862 Website: https://seajong.com/ Fanpage: https://facebook.com/seajong.official/ Seajong – Showroom Chính: Sảnh Tòa nhà CT3 Cầu Diễn,Phường Phúc Diễn, Hà Nội Seajong – Showroom Mạnh Cường: 148 Đại Mỗ, Phường Đại Mỗ, TP. Hà Nội Seajong – Showroom Thiên Thuận: Thôn Mai Thành, phường Đông Kinh, tỉnh Lạng Sơn Seajong – Showroom Tuấn Hòa: 78 Nguyễn Sỹ Sách, Hưng Phúc, TP Vinh, Nghệ An ⇒Xem thêm các mẫu bồn rửa chén khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2024/12/SJ-7645GS-1.webp","https://seajong.com/wp-content/uploads/2024/12/bon-rua-chen-1-ho-cao-cap-sj-7645gs.webp","https://seajong.com/wp-content/uploads/2024/12/bon-rua-chen-1-ho-cao-cap-sj-7645gs-2.webp","https://seajong.com/wp-content/uploads/2024/12/bon-rua-chen-1-ho-cao-cap-sj-7645gs-3.webp"]','{"Kích thước (mm):":"760 x 450 x 240 (mm)","Kích thước đặt âm bàn (mm):":"720 x 410 (mm)","Kích thước đặt dương bàn(mm):":"730 x 420 (mm)","Chất liệu:":"SUS 304","Phiên bản":"Vân tổ ong","Phụ kiện đi kèm:":"Bộ xiphong thoát nước | Rổ | Chậu nhỏ | Thớt"}',7800000.0,1782618033000,1782619253303,NULL);
INSERT INTO SeajongProduct VALUES(9824,'den-dieu-hoa-cam-ung-cao-cap-seajong-sj-he881','https://seajong.com/den-dieu-hoa-cam-ung-cao-cap-seajong-sj-he881/','Đèn điều hòa cảm ứng cao cấp Seajong SJ-HE881','Đèn điều hòa cảm ứng cao cấp Seajong SJ-HE881 tích hợp sưởi ấm, thông gió, hút ẩm và chiếu sáng trong một thiết bị nhỏ gọn, giúp không gian luôn ấm áp, khô thoáng và an toàn. Công suất mạnh mẽ, thiết kế hiện đại, dễ dàng lắp đặt, mang lại trải nghiệm tiện nghi [&hellip;]','Đèn điều hòa cảm ứng cao cấp Seajong SJ-HE881 tích hợp sưởi ấm, thông gió, hút ẩm và chiếu sáng trong một thiết bị nhỏ gọn, giúp không gian luôn ấm áp, khô thoáng và an toàn. Công suất mạnh mẽ, thiết kế hiện đại, dễ dàng lắp đặt, mang lại trải nghiệm tiện nghi tối ưu. Mua ngay để trải nghiệm không gian sống tiện nghi, ấm áp và an toàn! Mục Lục Toggle Tính năng công nghệ của đèn điều hòa cảm ứng cao cấp Seajong SJ-HE881 Đối tượng sử dụng Sử dụng trong các điều kiện thời tiết Hướng dẫn cách lắp đặt đèn điều hòa phòng tắm Seajong Tính năng công nghệ của đèn điều hòa cảm ứng cao cấp Seajong SJ-HE881 Khử lọc không khí : Làm sạch không khí hiệu quả, bảo vệ sức khỏe người dùng. Làm sưởi ấm bằng Heat Pump (Công nghệ Inverter): Cung cấp nhiệt độ ổn định và tiết kiệm năng lượng với công nghệ Heat Pump tiên tiến. Chức năng quạt thông gió: Giúp lưu thông không khí, tạo không gian thoáng đãng và dễ chịu. Chức năng chiếu sáng: Đèn LED chiếu sáng mạnh mẽ giúp cung cấp ánh sáng cho không gian sử dụng. Chức năng hút ẩm (Dry Mode): Giảm độ ẩm trong không khí, tạo không gian khô ráo, ngăn ngừa nấm mốc. Chức năng chiếu sáng cảm ứng ban đêm: Tự động điều chỉnh ánh sáng nhẹ nhàng vào ban đêm, giúp dễ dàng sử dụng mà không làm chói mắt. Chức năng hút mùi hôi: Loại bỏ mùi hôi khó chịu, giữ không khí trong lành và sạch sẽ. Chức năng hẹn giờ tự tắt: Tiết kiệm năng lượng với tính năng tự động tắt sau khoảng thời gian cài đặt. Remote điều khiển từ xa: Điều chỉnh các chức năng một cách tiện lợi mà không cần di chuyển đến gần thiết bị. Màn hình LED hiển thị thông số nhiệt độ và thời gian: Cung cấp thông tin chi tiết về nhiệt độ và thời gian hoạt động của thiết bị. Hút ẩm bằng Rotor hấp thụ (Desiccant Dehumidifier): Hiệu quả hút ẩm, giữ không gian khô thoáng, ngăn ngừa sự phát triển của nấm mốc. Sưởi ấm bằng thành nhiệt gốm PTC: Cung cấp nhiệt độ ấm áp nhanh chóng và hiệu quả, tiết kiệm năng lượng. Đèn LED chiếu sáng (30.000 giờ) tích hợp công nghệ Plasma: Đèn LED với tuổi thọ dài, kết hợp công n','["https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE881-1.webp","https://seajong.com/wp-content/uploads/2025/02/seajong-viet-nam-SJ-HE881.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE881-4.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE881-2.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE881-3.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE881-5.webp","https://seajong.com/wp-content/uploads/2025/02/Den-dieu-hoa-SJ-bao-ve-suc-khoe.webp","https://seajong.com/wp-content/uploads/2025/02/BDK-SJ-HE881-HE882.webp"]','{"Mã sản phẩm:":"SJ-HE881","Kiểu dáng:":"Âm trần","Kích thước (mm):":"- Rộng: 30cm\r\n- Dài: 60cm\r\n- Sâu: 12cm","Chất liệu:":"Mặt đèn: Nhựa PC, bền chắc và dễ dàng vệ sinh.\r\nKhung đèn: Hợp kim nhôm, nhẹ và chắc chắn. \r\nHộp đèn: Nhựa ABS, bảo vệ các bộ phận bên trong. \r\nĐèn chiếu sáng: Đèn LED kết hợp tấm khuếch tán PS giúp ánh sáng đều và tiết kiệm điện năng.","Năm sản xuất":"2026","Tiện ích":"Sưởi ấm, hút ẩm, lọc không khí, chiếu sáng, hút mùi","Tổng công suất:":"- Sưởi ấm: 1350W. - Đèn LED chiếu sáng: 24W. - Làm khô/quạt mát: 40W. - Thông gió/hút âm: 40W (lưu lượng hút 170m³/h).","Phụ kiện đi kèm:":"- Hộp đèn - Nắp đèn - Khung đèn - Bộ ốc vít - Giá đỡ - Thanh đệm - Ống bạc - Bảng điều khiển","Động cơ":"Lõi đồng kép nhập khẩu từ Hàn Quốc, bền bỉ và hiệu suất cao"}',5400000.0,1778655121000,1782619251490,'https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE881-1.webp');
INSERT INTO SeajongProduct VALUES(9830,'den-dieu-hoa-cao-cap-seajong-sj-he882','https://seajong.com/den-dieu-hoa-cao-cap-seajong-sj-he882/','Đèn điều hòa cao cấp Seajong SJ-HE882','Đèn điều hòa cao cấp Seajong SJ-HE882 tích hợp sưởi ấm, thông gió, hút ẩm, quạt mát và chiếu sáng, mang lại không gian thoải mái, khô thoáng và ấm áp. Với công nghệ sưởi gốm PTC, sản phẩm đảm bảo hiệu suất làm nóng nhanh, an toàn và tiết kiệm điện năng. Tính năng [&hellip;]','Đèn điều hòa cao cấp Seajong SJ-HE882 tích hợp sưởi ấm, thông gió, hút ẩm, quạt mát và chiếu sáng, mang lại không gian thoải mái, khô thoáng và ấm áp. Với công nghệ sưởi gốm PTC, sản phẩm đảm bảo hiệu suất làm nóng nhanh, an toàn và tiết kiệm điện năng. Mục Lục Toggle Tính năng công nghệ đèn điều hòa cao cấp Seajong SJ-HE882 Đối tượng sử dụng Sử dụng trong điều kiện thời tiết nào? Hướng dẫn cách lắp đặt đèn điều hòa phòng tắm Seajong Tính năng công nghệ đèn điều hòa cao cấp Seajong SJ-HE882 Làm sưởi ấm bằng Heat Pump (Công nghệ Inverter): Cung cấp nhiệt độ ổn định và tiết kiệm năng lượng. Chế độ quạt thông gió: Giúp lưu thông không khí và giữ không gian luôn thông thoáng. Chế độ chiếu sáng: Đèn LED cung cấp ánh sáng mạnh mẽ và tiết kiệm năng lượng. Chức năng hút ẩm (Dry Mode): Giảm độ ẩm trong phòng, ngăn ngừa nấm mốc. Chức năng hút mùi hôi: Loại bỏ các mùi hôi khó chịu trong không gian. Chức năng hẹn giờ tự tắt: Tiết kiệm năng lượng với tính năng tự động tắt sau thời gian cài đặt. Chức năng tự tắt sau hai giờ chống quên: Tự động tắt sau hai giờ để đảm bảo tiết kiệm năng lượng. Remote điều khiển từ xa: Điều chỉnh các chức năng mà không cần phải di chuyển. Màn hình LED hiển thị thông số nhiệt độ và thời gian: Cung cấp thông tin chi tiết về nhiệt độ và thời gian hoạt động. Hút ẩm bằng Rotor hấp thụ (Desiccant Dehumidifier): Hút ẩm hiệu quả, tạo không gian khô ráo. Sưởi ấm bằng thành nhiệt gốm PTC: Cung cấp nhiệt nhanh chóng và an toàn. Lưu ý khi tắt sưởi, hệ thống quay sẽ chậm lại 30s để bảo vệ thành nhiệt được bền bỉ hơn. Đèn LED chiếu sáng (30.000 giờ): Công nghệ LED giúp tiết kiệm điện năng và đảm bảo tuổi thọ lâu dài. Đối tượng sử dụng Người mắc bệnh hô hấp: Hỗ trợ lọc không khí, khử mùi, giảm độ ẩm và giúp thở dễ dàng hơn. Trẻ em: Cung cấp không khí sạch sẽ và bảo vệ sức khỏe cho trẻ nhỏ. Phụ nữ mang thai: Đảm bảo môi trường an toàn và thoải mái cho mẹ và thai nhi. Người cao tuổi: Cải thiện chất lượng không khí, mang lại không gian sống thoải mái và dễ thở. Nhân ','["https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE882-1.webp","https://seajong.com/wp-content/uploads/2025/02/seajong-viet-nam-SJ-HE882.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE882-3.webp","https://seajong.com/wp-content/uploads/2025/02/Den-dieu-hoa-SJ-bao-ve-suc-khoe.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE882-2.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE882-4.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE882-5.webp","https://seajong.com/wp-content/uploads/2025/02/BDK-SJ-HE881-HE882.webp"]','{"Mã sản phẩm:":"SJ-HE882","Kiểu dáng:":"Âm trần","Kích thước (mm):":"- Rộng: 30cm\r\n- Dài: 60cm\r\n- Sâu: 12cm","Chất liệu:":"Động cơ: Lõi đồng kép nhập khẩu từ Hàn Quốc, bền bỉ và hiệu suất cao\r\nMặt đèn: Nhựa PC, bền chắc và dễ dàng vệ sinh\r\nKhung đèn: Hợp kim nhôm, nhẹ và chắc chắn\r\nHộp đèn: Nhựa ABS, bảo vệ các bộ phận bên trong\r\nĐèn chiếu sáng: Đèn LED kết hợp tấm khuếch tán PS giúp ánh sáng đều và tiết kiệm điện năng.","Tiện ích":"- Tổng công suất: 2800W.\r\n- Sưởi ấm: 1350W.\r\n- Đèn LED chiếu sáng: 24W.\r\n- Làm khô/quạt mát: 40W.\r\n- Thông gió/hút âm: 40W (lưu lượng hút 170m³/h).","Phụ kiện đi kèm:":"- Hộp đèn - Nắp đèn - Khung đèn - Bộ ốc vít - Giá đỡ - Thanh đệm - Ống bạc - Bảng điều khiển"}',5200000.0,1778655165000,1782619251625,'https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE882-1.webp');
INSERT INTO SeajongProduct VALUES(9838,'guong-led-co-khung-vien-seajong-sj-6080b','https://seajong.com/guong-led-co-khung-vien-seajong-sj-6080b/','Gương LED có khung viền 60&#215;80 Seajong SJ-6080B','Gương LED SJ-6080B với kích thước 60x80x2,5 cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu [&hellip;]','Gương LED SJ-6080B với kích thước 60x80x2,5 cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu Âu EN ISO 9227, đảm bảo độ bền và chất lượng phản chiếu vượt trội. Công nghệ tráng bạc 8 lớp giúp gương chống ố mép, chống oxy hóa, duy trì độ sáng bóng lâu dài. Công nghệ Rotech giúp gương chịu lực tốt, giảm nguy cơ vỡ khi va đập. Đèn Led 3 chế độ ánh sáng trắng 6500K, vàng 2700K và kết hợp 4500K, phù hợp với nhu cầu sử dụng và tạo không gian ấm cúng. Điều khiển các chức năng như bật/tắt đèn, điều chỉnh độ sáng và đổi màu ánh sáng một cách dễ dàng. Chống nước IP65 đảm bảo an toàn khi sử dụng trong môi trường ẩm ướt như phòng tắm. Đèn LED có tuổi thọ lên đến 10.000 giờ, tiết kiệm chi phí thay thế','["https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B-1.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B-2.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B-3.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B-5.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B-4.webp"]','{"Mã sản phẩm:":"SJ-6080B","Kích thước (mm):":"600 x 800 x 25 (mm)","Phiên bản":"Phôi Mirrox (Bỉ)","Công nghệ":"Công nghệ tráng bạc: 8 lớp","Tiện ích":"Chống vỡ va đập, chống oxy hóa Rotech","Nguồn điện":"220V – 5A","Dây LED":"180 chip LED/m, 3 chế độ sáng trắng 6500K, vàng 2700K, kết hợp 4500K","Đèn LED":"3 chế độ màu, công suất 35W, chống nước IP65, tuổi thọ 10.000 giờ","Điều khiển":"Cảm ứng chạm thông minh"}',1750000.0,1778300700000,1782200035166,'https://seajong.com/wp-content/uploads/2025/02/guong-led-ve-sinh-SJ-6080B.webp');
INSERT INTO SeajongProduct VALUES(9844,'guong-led-say-co-khung-vien-seajong-sj-6080bs','https://seajong.com/guong-led-say-co-khung-vien-seajong-sj-6080bs/','Gương LED sấy có khung viền 60&#215;80 Seajong SJ-6080BS','Gương LED SJ-6080BS với kích thước 60x80x2,5cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu Âu [&hellip;]','Gương LED SJ-6080BS với kích thước 60x80x2,5cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu Âu EN ISO 9227, đảm bảo độ bền và chất lượng phản chiếu vượt trội. Công nghệ tráng bạc 8 lớp giúp gương chống ố mép, chống oxy hóa, duy trì độ sáng bóng lâu dài. Công nghệ Rotech giúp gương chịu lực tốt, giảm nguy cơ vỡ khi va đập. Đèn LED 3 chế độ màu: ánh sáng trắng 6500K, vàng 2700K và kết hợp 4500K, phù hợp với nhu cầu sử dụng và tạo không gian ấm cúng. Điều khiển các chức năng như bật/tắt đèn, điều chỉnh độ sáng và đổi màu ánh sáng một cách dễ dàng chỉ với 1 chạm. Sản phẩm tích hợp tính năng khử sương mù và sấy gương, giúp mặt gương luôn sáng rõ ngay cả trong môi trường ẩm ướt. Chống nước IP65 đảm bảo an toàn khi sử dụng trong môi trường ẩm ướt như phòng tắm. Đèn LED có tuổi thọ lên đến 10.000 giờ, tiết kiệm chi phí thay thế.','["https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-1.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-6.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-4.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-5.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-2.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-3.webp"]','{"Mã sản phẩm:":"SJ-6080BS","Kích thước (mm):":"600 x 800 x 25 (mm)","Phiên bản":"Phôi Mirrox (Bỉ)","Công nghệ":"Chống vỡ va đập, chống oxy hóa Rotech","Nguồn điện":"220V – 5A","Dây LED":"180 chip LED/m, 3 chế độ sáng trắng 6500K, vàng 2700K, kết hợp 4500K","Đèn LED":"3 chế độ màu, công suất 35W, chống nước IP65, tuổi thọ 10.000 giờ","Điều khiển":"Cảm ứng chạm thông minh"}',2400000.0,1778300553000,1782200034644,'https://seajong.com/wp-content/uploads/2025/02/guong-led-phong-tam-SJ-6080BS-1.webp');
