INSERT INTO SeajongProduct VALUES(9856,'guong-led-say-co-khung-vien-60x100-sj-6010bs','https://seajong.com/guong-led-say-co-khung-vien-60x100-sj-6010bs/','Gương LED sấy có khung viền 60&#215;100 SJ-6010BS','Gương LED SJ-6010BS với kích thước 60x100x2,5cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu Âu [&hellip;]','Gương LED SJ-6010BS với kích thước 60x100x2,5cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu Âu EN ISO 9227, đảm bảo độ bền và chất lượng phản chiếu vượt trội. Công nghệ tráng bạc 8 lớp giúp gương chống ố mép, chống oxy hóa, duy trì độ sáng bóng lâu dài. Công nghệ Rotech giúp gương chịu lực tốt, giảm nguy cơ vỡ khi va đập. Đèn LED 3 chế độ màu: ánh sáng trắng 6500K, vàng 2700K và kết hợp 4500K, phù hợp với nhu cầu sử dụng và tạo không gian ấm cúng. Điều khiển các chức năng như bật/tắt đèn, điều chỉnh độ sáng và đổi màu ánh sáng một cách dễ dàng chỉ với 1 chạm. Sản phẩm tích hợp tính năng khử sương mù và sấy gương, giúp mặt gương luôn sáng rõ ngay cả trong môi trường ẩm ướt. Chống nước IP65 đảm bảo an toàn khi sử dụng trong môi trường ẩm ướt như phòng tắm. Đèn LED có tuổi thọ lên đến 10.000 giờ, tiết kiệm chi phí thay thế.','["https://seajong.com/wp-content/uploads/2025/02/guong-led-100x60-SJ-6010BS.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-100x60-SJ-6010BS-2.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-100x60-SJ-6010BS-3.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-100x60-SJ-6010BS-1.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-100x60-SJ-6010BS-5.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-100x60-SJ-6010BS-4.webp"]','