INSERT INTO SeajongProduct VALUES(9868,'guong-led-say-tron-co-khung-vien-sj-m60ls','https://seajong.com/guong-led-say-tron-co-khung-vien-sj-m60ls/','Gương LED sấy tròn phòng tắm cao cấp Seajong SJ-M60LS','Gương LED tròn SJ-M60LS với đường kính 60cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu [&hellip;]','Gương LED tròn SJ-M60LS với đường kính 60cm, phôi Mirrox Bỉ, tráng bạc 8 lớp, đèn LED 3 chế độ màu, cảm ứng chạm thông minh, khung nhôm xám dày 25mm, mang đến sự tiện nghi và thẩm mỹ cho phòng tắm. Tính năng công nghệ Sử dụng phôi Mirrox (Bỉ) đạt tiêu chuẩn Châu Âu EN ISO 9227, đảm bảo độ bền và chất lượng phản chiếu vượt trội. Công nghệ tráng bạc 8 lớp giúp gương chống ố mép, chống oxy hóa, duy trì độ sáng bóng lâu dài. Công nghệ Rotech giúp gương chịu lực tốt, giảm nguy cơ vỡ khi va đập. Đèn LED 3 chế độ màu: ánh sáng trắng 6500K, vàng 2700K và kết hợp 4500K, phù hợp với nhu cầu sử dụng và tạo không gian ấm cúng. Điều khiển các chức năng như bật/tắt đèn, điều chỉnh độ sáng và đổi màu ánh sáng một cách dễ dàng. Chống nước IP65 đảm bảo an toàn khi sử dụng trong môi trường ẩm ướt như phòng tắm. Sản phẩm tích hợp tính năng khử sương mù và sấy gương chỉ với một nút chạm. Đèn LED có tuổi thọ lên đến 10.000 giờ, tiết kiệm chi phí thay thế.','["https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS-2.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS-5.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS-4.webp","https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS-3.webp"]','{"Mã sản phẩm:":"SJ-M60LS","Kích thước (mm):":"Đường kính: 60cm","Chất liệu:":"Phôi gương:  Công nghệ tráng bạc: 8 lớp","Phiên bản":"Phôi Mirrox (Bỉ)","Công nghệ":"Công nghệ tráng bạc: 8 lớp","Tiện ích":"Chống vỡ va đập, chống oxy hóa Rotech","Nguồn điện":"220V – 5A","Dây LED":"180 chip LED/m, 3 chế độ sáng trắng 6500K, vàng 2700K, kết hợp 4500K","Đèn LED":"3 chế độ màu, công suất 35W, chống nước IP65, tuổi thọ 10.000 giờ","Điều khiển":"Cảm ứng chạm thông minh"}',5400000.0,1778300522000,1782200034921,'https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS-2.webp');
INSERT INTO SeajongProduct VALUES(9874,'bon-cau-thong-minh-seajong-sj-680d','https://seajong.com/bon-cau-thong-minh-seajong-sj-680d/','Bồn cầu thông minh Seajong SJ-680D','Bồn cầu Seajong SJ-680D tích hợp cảm biến tự động, vòi xịt đa chế độ, sấy khô khí ấm, đèn LED ban đêm và tia UV khử khuẩn. Thiết kế hiện đại mang lại sự tiện nghi và an toàn tuyệt đối. Tính năng công nghệ Cảm biến tự động thông minh: Tự động lật [&hellip;]','Bồn cầu Seajong SJ-680D tích hợp cảm biến tự động, vòi xịt đa chế độ, sấy khô khí ấm, đèn LED ban đêm và tia UV khử khuẩn. Thiết kế hiện đại mang lại sự tiện nghi và an toàn tuyệt đối. Tính năng công nghệ Cảm biến tự động thông minh: Tự động lật nắp khi có người đến. Cảm biến đá chân giúp kích hoạt xả nước mà không cần chạm tay. Hệ thống điều khiển tiện lợi: Điều khiển từ xa bằng remote. Nút xoay bên hông dễ dàng điều chỉnh các chức năng. Vòi xịt đa chế độ: Chế độ rửa sau, rửa phụ nữ, rửa massage. Tự động làm sạch vòi sau mỗi lần sử dụng. Công nghệ xả xoáy kết hợp xả phản lực: Tạo dòng chảy mạnh mẽ, loại bỏ vết bẩn hiệu quả mà vẫn tiết kiệm nước. Tiện ích vượt trội: Điều chỉnh áp lực nước, vị trí vòi rửa. Sấy khô khí ấm với 4 mức nhiệt độ (38°C – 45°C – 55°C). Màn hình LED hiển thị nhiệt độ nước, bệ ngồi. Đèn LED ban đêm giúp sử dụng dễ dàng trong điều kiện thiếu sáng. Tia UV khử khuẩn giúp diệt sạch vi khuẩn, đảm bảo vệ sinh. Chống rò rỉ điện, tiêu chuẩn chống nước IPX4. ⇒Xem thêm các mẫu bồn cầu khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/02/bon-cau-thong-minh-sj-680d.webp","https://seajong.com/wp-content/uploads/2025/02/ban-cau-SJ-680D-2.webp","https://seajong.com/wp-content/uploads/2025/02/ban-cau-SJ-680D-5.webp","https://seajong.com/wp-content/uploads/2025/02/ban-cau-SJ-680D-4.webp","https://seajong.com/wp-content/uploads/2025/02/ban-cau-SJ-680D-3.webp"]','{"Mã sản phẩm:":"SJ-680D","Kiểu dáng:":"Smart","Kích thước (mm):":"680 x 380 x 470 (mm)","Chất liệu:":"Chất liệu thân: Gốm sứ phủ men Nano Bạc kháng khuẩn / Nắp & Bệ ngồi: Nhựa ABS phủ Ion Bạc Ag, kháng khuẩn","Kiểu xả":"Xả xoáy kết hợp xả phản lực","Tải trọng tối đa":"300kg","Cảm biến đá chân":"Có","Tự động xả nước":"Có","Remote điều khiển từ xa":"Có","Nút xoay điều khiển bên hông":"Có","Tâm hố":"90-114mm","Khoảng cách tâm hố":"300mm","Nhiệt độ nước":"Normal – 34°C – 37°C – 40°C","Nhiệt độ bệ ngồi":"Normal – 34°C – 37°C – 40°C","Nhiệt độ sấy":"Normal –  38°C – 45°C – 55°C"}',19200000.0,1782290795000,1782619251619,'https://seajong.com/wp-content/uploads/2025/02/bon-cau-thong-minh-sj-680d.webp');
INSERT INTO SeajongProduct VALUES(9880,'bon-cau-thong-minh-seajong-sj-m8d','https://seajong.com/bon-cau-thong-minh-seajong-sj-m8d/','Bồn cầu thông minh Seajong SJ-M8D','Bồn cầu thông minh Seajong SJ-M8D tích hợp công nghệ cảm biến tự động, vòi xịt đa chế độ, sấy khô khí ấm, đèn LED ban đêm và tia UV khử khuẩn. Sản phẩm mang lại sự tiện nghi, vệ sinh tối ưu và an toàn tuyệt đối. Tính năng công nghệ của SJ-M8D Tự [&hellip;]','Bồn cầu thông minh Seajong SJ-M8D tích hợp công nghệ cảm biến tự động, vòi xịt đa chế độ, sấy khô khí ấm, đèn LED ban đêm và tia UV khử khuẩn. Sản phẩm mang lại sự tiện nghi, vệ sinh tối ưu và an toàn tuyệt đối. Tính năng công nghệ của SJ-M8D Tự động mở nắp và xả nước bằng cảm biến đá chân, mang lại sự tiện lợi và vệ sinh. Điều khiển dễ dàng qua remote hoặc nút xoay bên hông. Vòi xịt đa chế độ (rửa sau, rửa phụ nữ, rửa massage) với chức năng tự làm sạch. Hệ thống xả xoáy siêu mạnh kết hợp xả phản lực, hiệu quả và tiết kiệm nước. Điều chỉnh áp lực nước, vị trí vòi rửa và nhiệt độ sấy khô khí ấm (4 mức: 38°C – 45°C – 55°C). Màn hình LED hiển thị nhiệt độ nước và bệ ngồi; đèn LED ban đêm hỗ trợ trong điều kiện thiếu sáng. Tích hợp tia UV khử khuẩn, nắp đóng giảm chấn và lớp bọt chống bắn nước. Thiết kế chống rò rỉ, chống cháy nổ, đạt tiêu chuẩn chống nước IPX4. Hỗ trợ pin dự phòng và chức năng xả khi mất điện. ⇒Xem thêm các mẫu bồn cầu khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/02/SJ-M8D.webp"]','{"Mã sản phẩm:":"SJ-M8D","Kiểu dáng:":"Smart","Kích thước (mm):":"680 × 415 × 470 (mm)","Chất liệu:":"Chất liệu thân: Gốm sứ phủ men Nano Bạc kháng khuẩn / Nắp & bệ ngồi: Nhựa ABS phủ Ion Bạc Ag, kháng khuẩn","Kiểu xả":"Xả xoáy siêu mạnh kết hợp xả phản lực","Lượng xả":"5L","Tải trọng tối đa":"300kg","Cảm biến đá chân":"Có","Tự động xả nước":"Có","Remote điều khiển từ xa":"Có","Nút xoay điều khiển bên hông":"Có","Tâm hố":"90-114mm","Khoảng cách tâm hố":"300mm","Nhiệt độ nước":"Normal – 34°C – 37°C – 40°C","Nhiệt độ bệ ngồi":"Normal – 34°C – 37°C – 40°C","Nhiệt độ sấy":"Normal – 38°C – 45°C – 55°C","Nguồn điện":"220V"}',21600000.0,1782290635000,1782619251616,'https://seajong.com/wp-content/uploads/2025/02/SJ-M8D.webp');
INSERT INTO SeajongProduct VALUES(9888,'bon-tieu-nam-cam-ung-seajong-sj-6007t','https://seajong.com/bon-tieu-nam-cam-ung-seajong-sj-6007t/','Bồn tiểu nam cảm ứng Seajong SJ-6007T','Bồn tiểu nam Seajong SJ-6007T tích hợp cảm biến tự động xả nước, giúp sử dụng tiện lợi và vệ sinh hơn. Thiết kế treo tường tiết kiệm không gian, lớp men Nano Bạc chống bám bẩn và kháng khuẩn hiệu quả. Tính năng công nghệ Cảm biến tự động xả nước: Tích hợp cảm [&hellip;]','Bồn tiểu nam Seajong SJ-6007T tích hợp cảm biến tự động xả nước, giúp sử dụng tiện lợi và vệ sinh hơn. Thiết kế treo tường tiết kiệm không gian, lớp men Nano Bạc chống bám bẩn và kháng khuẩn hiệu quả. Tính năng công nghệ Cảm biến tự động xả nước: Tích hợp cảm biến hồng ngoại, tự động kích hoạt xả nước khi người dùng rời đi. Hệ thống xả mạnh mẽ: Xả thẳng nhanh chóng, tiết kiệm nước với mức điều chỉnh 2.5L ~ 5L/lần. Bề mặt chống bám bẩn: Lớp men Nano Bạc giúp chống vi khuẩn, hạn chế ố vàng, dễ dàng vệ sinh. Nắp phễu inox 304: Độ bền cao, chống oxy hóa, không bị han gỉ theo thời gian. Lắp đặt linh hoạt: Có thể xả tường hoặc xả sàn, phù hợp với nhiều không gian. Thiết kế treo tường chắc chắn: Giúp tiết kiệm diện tích, phù hợp với nhà vệ sinh hiện đại. ⇒Xem thêm các mẫu bồn tiểu nam khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/02/sj-tn6007t.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-cam-ung-seajong-sj-663-3.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-cam-ung-seajong-sj-663-2.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-cam-ung-seajong-sj-663-1.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-cam-ung-seajong-sj-663.webp"]','{"Mã sản phẩm:":"SJ-6007T","Kích thước (mm):":"(Dài x Rộng x Cao): 42 cm x 38 cm x 92 cm","Chất liệu:":"Gốm sứ phủ men Nano Bạc kháng khuẩn","Áp lực nước khuyến nghị":"0.07 ~ 0.75 MPa (0.7 – 7.6 kg/cm²)","Kiểu xả":"Xả thẳng mạnh mẽ, tiết kiệm nước","Lượng xả":"2.5L ~ 5L/lần (có thể điều chỉnh)","Nguồn điện":"DC 6V, sử dụng 4 pin AAA","Cảm biến":"Khoảng cách 650mm","Phương thức xả thải":"Xả tường hoặc xả sàn","Phương thức lắp đặt":"Treo tường chắc chắn"}',8400000.0,1778657611000,1782619251622,'https://seajong.com/wp-content/uploads/2025/02/sj-tn6007t.webp');
INSERT INTO SeajongProduct VALUES(9894,'bon-tieu-nam-seajong-sj-6008t','https://seajong.com/bon-tieu-nam-seajong-sj-6008t/','Bồn tiểu nam Seajong SJ-6008T','Bồn tiểu nam Seajong SJ-6008T với cảm biến tự động xả nước, hệ thống xả thẳng mạnh mẽ tiết kiệm nước và chất liệu gốm sứ phủ men Nano Bạc kháng khuẩn, mang đến trải nghiệm vệ sinh và tiện lợi tối ưu. Tính năng công nghệ Cảm biến tự động xả nước: Xả nước [&hellip;]','Bồn tiểu nam Seajong SJ-6008T với cảm biến tự động xả nước, hệ thống xả thẳng mạnh mẽ tiết kiệm nước và chất liệu gốm sứ phủ men Nano Bạc kháng khuẩn, mang đến trải nghiệm vệ sinh và tiện lợi tối ưu. Tính năng công nghệ Cảm biến tự động xả nước: Xả nước tự động khi người dùng rời đi, không cần chạm tay, đảm bảo vệ sinh. Hệ thống xả mạnh mẽ: Xả thẳng nhanh chóng, tiết kiệm nước, với lượng nước xả điều chỉnh từ 2.5L đến 5L. Chất liệu cao cấp: Thân bồn làm từ gốm sứ phủ men Nano Bạc kháng khuẩn, giúp chống bám bẩn và vi khuẩn. Cảm biến hồng ngoại: Được tích hợp trong nhựa ABS, giúp nhận diện người dùng trong phạm vi 650mm. Nắp phễu inox 304: Đảm bảo độ bền cao, chống oxy hóa và gỉ sét. Thiết kế tiện lợi: Xả tường hoặc xả sàn, phù hợp với nhiều loại không gian lắp đặt ⇒Xem thêm các mẫu bồn tiểu nam khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/02/SJ-6008T.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-seajong-sj-6007t.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-seajong-sj-6007t-1.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-seajong-sj-6007t-2.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-seajong-sj-6007t-4.webp"]','{"Mã sản phẩm:":"SJ-6008T","Kích thước (mm):":"(Dài x Rộng x Sâu): 343 x 307 x 697mm","Chất liệu:":"Gốm sứ phủ men Nano Bạc kháng khuẩn","Áp lực nước khuyến nghị":"0.07 ~ 0.75 MPa (0.7 – 7.6 kg/cm²)","Kiểu xả":"Xả thẳng mạnh mẽ, tiết kiệm nước","Lượng xả":"2.5L ~ 5L/lần (có thể điều chỉnh)","Nguồn điện":"DC 6V, sử dụng 4 pin AAA","Cảm biến":"Phạm vi 650mm","Phương thức xả thải":"Xả tường hoặc xả sàn","Phương thức lắp đặt":"Treo tường chắc chắn"}',4600000.0,1778657726000,1782619251613,'https://seajong.com/wp-content/uploads/2025/02/SJ-6008T.webp');
INSERT INTO SeajongProduct VALUES(9899,'bon-tieu-nam-seajong-sj-6009t','https://seajong.com/bon-tieu-nam-seajong-sj-6009t/','Bồn tiểu nam Seajong SJ-6009T','Bồn tiểu nam Seajong SJ-6009T với thiết kế hiện đại, sử dụng công nghệ xả thẳng mạnh mẽ giúp tiết kiệm nước hiệu quả. Chất liệu gốm sứ phủ men Nano Bạc kháng khuẩn, dễ dàng vệ sinh và bền bỉ theo thời gian. Tính năng công nghệ Phương pháp xả mạnh mẽ: Xả thẳng [&hellip;]','Bồn tiểu nam Seajong SJ-6009T với thiết kế hiện đại, sử dụng công nghệ xả thẳng mạnh mẽ giúp tiết kiệm nước hiệu quả. Chất liệu gốm sứ phủ men Nano Bạc kháng khuẩn, dễ dàng vệ sinh và bền bỉ theo thời gian. Tính năng công nghệ Phương pháp xả mạnh mẽ: Xả thẳng mạnh mẽ, tiết kiệm nước với lượng xả có thể điều chỉnh từ 2.5L đến 5L. Chất liệu cao cấp: Thân bồn làm từ gốm sứ phủ men Nano Bạc kháng khuẩn giúp chống bám bẩn và bảo vệ sức khỏe người dùng. Cảm biến hồng ngoại: Tích hợp trong nhựa ABS, giúp nhận diện và hoạt động xả chính xác. Nắp phễu inox 304: Chống gỉ sét, bền bỉ, mang lại tuổi thọ lâu dài cho sản phẩm. Lắp đặt linh hoạt: Có thể chọn xả tường hoặc xả sàn, phù hợp với không gian phòng tắm. ⇒Xem thêm các mẫu bồn tiểu nam khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/02/SJ-6009T.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-gia-re-seajong-sj-6008t-3.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-gia-re-seajong-sj-6008t-1.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-gia-re-seajong-sj-6008t-2.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-gia-re-seajong-sj-6008t-4.webp"]','{"Mã sản phẩm:":"SJ-6009T","Kích thước (mm):":"(Dài x Rộng x Sâu): 680 x 330 x 270mm.","Chất liệu:":"Gốm sứ phủ men Nano Bạc kháng khuẩn","Áp lực nước khuyến nghị":"0.07 ~ 0.75 MPa (0.7 – 7.6 kg/cm²)","Kiểu xả":"Xả thẳng mạnh, tiết kiệm nước","Lượng xả":"2.5L ~ 5L/lần (có thể điều chỉnh)","Phương thức xả thải":"Xả tường hoặc xả sàn","Phương thức lắp đặt":"Treo tường chắc chắn"}',2650000.0,1778657731000,1782619250660,'https://seajong.com/wp-content/uploads/2025/02/SJ-6009T.webp');
INSERT INTO SeajongProduct VALUES(9905,'bon-tieu-nam-seajong-sj-6012t','https://seajong.com/bon-tieu-nam-seajong-sj-6012t/','Bồn tiểu nam Seajong SJ-6012T','Bồn tiểu nam Seajong SJ-6012T với cảm biến tự động xả nước, thiết kế xả thẳng mạnh mẽ tiết kiệm nước. Chất liệu gốm sứ phủ men Nano Bạc kháng khuẩn giúp giữ bồn tiểu sạch sẽ và bền bỉ theo thời gian. Tính năng công nghệ Cảm biến tự động xả nước: Tự động [&hellip;]','Bồn tiểu nam Seajong SJ-6012T với cảm biến tự động xả nước, thiết kế xả thẳng mạnh mẽ tiết kiệm nước. Chất liệu gốm sứ phủ men Nano Bạc kháng khuẩn giúp giữ bồn tiểu sạch sẽ và bền bỉ theo thời gian. Tính năng công nghệ Cảm biến tự động xả nước: Tự động xả nước khi người dùng rời đi, giúp đảm bảo vệ sinh mà không cần chạm tay. Phương pháp xả mạnh mẽ: Xả thẳng mạnh mẽ, tiết kiệm nước với lượng xả có thể điều chỉnh từ 2.5L đến 5L. Chất liệu cao cấp: Thân bồn làm từ gốm sứ phủ men Nano Bạc kháng khuẩn giúp chống bám bẩn và bảo vệ sức khỏe người dùng. Cảm biến hồng ngoại: Khoảng cách cảm ứng lên đến 650mm, giúp nhận diện người dùng chính xác. Nắp phễu inox 304: Đảm bảo độ bền cao, chống gỉ sét và bền bỉ theo thời gian. Lắp đặt linh hoạt: Có thể xả tường hoặc xả sàn, phù hợp với nhiều không gian khác nhau. ⇒Xem thêm các mẫu bồn tiểu nam khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/02/SJ-6012T.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-chinh-hang-seajong-sj-6009t-1.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-chinh-hang-seajong-sj-6009t-2.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-chinh-hang-seajong-sj-6009t.webp","https://seajong.com/wp-content/uploads/2025/02/bon-tieu-nam-chinh-hang-seajong-sj-6009t-4.webp"]','{"Mã sản phẩm:":"SJ-6012T","Kích thước (mm):":"(Dài x Rộng x Sâu): 680 x 330 x 270mm","Chất liệu:":"Gốm sứ phủ men Nano Bạc kháng khuẩn","Áp lực nước khuyến nghị":"0.07 ~ 0.75 MPa (0.7 – 7.6 kg/cm²)","Kiểu xả":"Xả thẳng mạnh mẽ, tiết kiệm nước","Lượng xả":"2.5L ~ 5L/lần (có thể điều chỉnh","Nguồn điện":"DC 6V, sử dụng 4 pin AAA","Cảm biến":"Khoảng cách cảm ứng 650mm","Phương thức xả thải":"Xả tường hoặc xả sàn","Phương thức lắp đặt":"Treo tường chắc chắn"}',2950000.0,1778657742000,1782619250522,'https://seajong.com/wp-content/uploads/2025/02/SJ-6012T.webp');
INSERT INTO SeajongProduct VALUES(9922,'sen-cay-truyen-thong-seajong-sj-075c','https://seajong.com/sen-cay-truyen-thong-seajong-sj-075c/','Sen cây truyền thống Seajong SJ-SC0075B-SR','Sen cây truyền thống cao cấp , phù hợp phòng tắm hiện đại, sang trọng. Thân củ bằng đồng Italia 61% , chắc chắn, bền bỉ, chịu áp lực nước tốt. Cần sen bằng inox SUS304 Posco Hàn Quốc , chống han gỉ, chống ăn mòn. Mạ Chrome 5 lớp , sáng bóng, dễ vệ sinh, giữ vẻ đẹp lâu dài. Van lõi Sedal Tây Ban Nha , vận hành êm, điều chỉnh nóng lạnh chính xác. Đúc áp lực thấp phân tách chì 0,025% Pb , an toàn hơn cho nguồn nước và sức khỏe. Công nghệ Wartesoft , tạo dòng nước mềm mại, dễ chịu khi tắm. Cố định n','Sen cây truyền thống Seajong SJ-075C- Giải pháp không gian tắm hiện đại Sen cây truyền thống SEAJONG SJ-075C là dòng sen cây cao cấp được thiết kế dành cho những không gian phòng tắm hiện đại, sang trọng và đề cao sự an toàn trong quá trình sử dụng. Sản phẩm có tiện ích cố định nhiệt độ, tắm mưa và tắm thường , giúp người dùng dễ dàng tận hưởng trải nghiệm tắm thư giãn, ổn định và tiện nghi hằng ngày. Thân củ sen được chế tác từ đồng Italia 61% , mang lại kết cấu chắc chắn, khả năng chịu áp lực nước tốt và độ bền cao trong môi trường phòng tắm ẩm ướt. Cần sen cây sử dụng inox SUS304 Posco Hàn Quốc , giúp hạn chế han gỉ, chống ăn mòn và duy trì độ ổn định lâu dài. Bề mặt sản phẩm được hoàn thiện bằng công nghệ mạ Chrome 5 lớp , tạo độ sáng bóng sang trọng, dễ vệ sinh và giữ được vẻ đẹp bền bỉ theo thời gian. Điểm nổi bật của mẫu sen cây này là van lõi Sedal Tây Ban Nha , cho thao tác đóng mở êm, điều chỉnh nóng lạnh chính xác và hạn chế rò rỉ nước trong quá trình sử dụng. Trang sản phẩm cũng công bố lõi trộn SEDAL Tây Ban Nha, chiều cao tổng thể 1400mm, cấu trúc ống thẳng 800mm và ống cong 600mm. Sản phẩm được sản xuất bằng công nghệ đúc áp lực thấp phân tách chì , kiểm soát hàm lượng chì ở mức 0,025% Pb , giúp an toàn hơn cho nguồn nước sinh hoạt và sức khỏe người dùng. Công nghệ Wartesoft tạo dòng nước mềm mại, đều và dễ chịu khi tiếp xúc với da, mang lại cảm giác tắm thoải mái hơn so với các dòng nước phun mạnh, thô thông thường. Đặc biệt, chức năng cố định nhiệt độ giúp duy trì nhiệt độ nước ổn định, hạn chế tình trạng thay đổi nhiệt đột ngột và hỗ trợ chống bỏng hiệu quả, phù hợp với gia đình có trẻ nhỏ, người lớn tuổi hoặc người dùng cần sự an toàn cao khi tắm. Sản phẩm đạt chứng nhận ISO 9001:2015 , có nguồn gốc xuất xứ rõ ràng, thể hiện cam kết của SEAJONG về chất lượng, tiêu chuẩn sản xuất và sự minh bạch trong từng sản phẩm. Sen cây truyền thống SEAJONG SJ-SC0075B-SR hoàn toàn là lựa chọn thay thế hoàn hảo cho các dòng sen cây mà bạn chưa yên tâm về chất lư','["https://seajong.com/wp-content/uploads/2025/02/SJ-075C.webp","https://seajong.com/wp-content/uploads/2025/02/SC-SJ-075C-4.webp","https://seajong.com/wp-content/uploads/2025/02/SC-SJ-075C-3.webp","https://seajong.com/wp-content/uploads/2025/02/SC-SJ-075C-5.webp","https://seajong.com/wp-content/uploads/2025/03/SJ-075C-2.webp","https://seajong.com/wp-content/uploads/2025/03/van-loi-gom-sedal-seajong-1.webp"]','{"Mã sản phẩm:":"SJ-SC0075B-SR","Kiểu dáng:":"Classic","Kích thước (mm):":"1400mm","Chất liệu:":"Đồng Italia 61%","Bề mặt:":"Mạ Chrome 5 lớp","Công nghệ":"Chống bỏng","Áp lực nước khuyến nghị":"0.05 ~ 1.2 Mpa","Trọng lượng":"2800 gram","Lõi trộn":"SEDAL (Tây Ban Nha)","Điểm khác biệt":"0,01%Pb","Thời gian bảo hành":"5 năm"}',11500000.0,1782404937000,1782619250504,'https://seajong.com/wp-content/uploads/2025/02/SJ-075C.webp');
INSERT INTO SeajongProduct VALUES(9928,'sen-cay-truyen-thong-seajong-sj-0074b-sr','https://seajong.com/sen-cay-truyen-thong-seajong-sj-074c/','Sen cây tắm đứng Seajong SJ-SC0074B-SR','Đỉnh cao công nghệ và chất lượng cho phòng tắm thượng lưu: Sử dụng vật liệu Đồng A (61%) đúc áp lực thấp tinh khiết, phân tách chì an toàn cho sức khỏe. Thẩm mỹ đỉnh cao với lớp mạ 5 lớp siêu bền, thách thức mọi môi trường ẩm ướt. Trái tim là van lõi Sedal Tây Ban Nha cao cấp, đảm bảo không rò rỉ, vận hành mượt mà với hơn 500.000 lần sử dụng Trải nghiệm dòng nước êm ái, tiết kiệm vượt trội nhờ công nghệ tạo bọt WaterSoft cung cấp oxy tự nhiên','https://youtube.com/watch?v=iwutrxQO3go%3Ffeature%3Dshare Sen cây truyền thống SEAJONG SJ-SC0074B-SR Hàn Quốc Là dòng sen cây cao cấp mang phong cách tinh tế – hiện đại – bền bỉ , phù hợp với các không gian phòng tắm gia đình, căn hộ, showroom, khách sạn và công trình cao cấp. Thiết kế mạ Chrome sáng bóng giúp sản phẩm dễ phối hợp với nhiều phong cách nội thất, đồng thời tạo cảm giác sạch sẽ, sang trọng và hiện đại cho khu vực tắm. Sản phẩm được chế tác với thân củ bằng đồng Italia 61% , mang lại kết cấu chắc chắn, khả năng chịu áp lực nước tốt và độ bền ổn định trong môi trường ẩm ướt. Cần sen cây sử dụng inox SUS304 Posco Hàn Quốc , giúp hạn chế han gỉ, chống ăn mòn và duy trì độ bền lâu dài trong quá trình sử dụng. Bề mặt sen được hoàn thiện bằng công nghệ mạ Chrome 5 lớp , tạo độ sáng bóng cao, dễ vệ sinh, hạn chế oxy hóa và giữ được vẻ đẹp bền lâu. Đây là yếu tố quan trọng giúp sản phẩm vừa đáp ứng công năng sử dụng hằng ngày, vừa nâng tầm thẩm mỹ cho không gian phòng tắm. Về khả năng vận hành, sản phẩm Sen cây truyền thống SEAJONG SJ-SC0074B-SR sử dụng van lõi Sedal Tây Ban Nha , cho thao tác đóng mở nhẹ, điều chỉnh nóng lạnh chính xác, vận hành êm ái và hạn chế rò rỉ nước. Trang sản phẩm cũng công bố lõi trộn SEDAL Tây Ban Nha và thời gian bảo hành 5 năm cho model SJ-SC0074B-SR. Điểm khác biệt quan trọng của sen cây Sen cây truyền thống SEAJONG SJ-SC0074B-SR là công nghệ đúc áp lực thấp phân tách chì , kiểm soát hàm lượng chì ở mức 0,025% Pb , giúp sản phẩm an toàn hơn cho nguồn nước sinh hoạt và sức khỏe người dùng. Công nghệ này đặc biệt phù hợp với các gia đình quan tâm đến chất lượng vật liệu và tiêu chuẩn an toàn trong thiết bị phòng tắm. Ngoài ra, sản phẩm ứng dụng công nghệ Wartesoft , giúp dòng nước phun ra mềm mại, đều và dễ chịu khi tiếp xúc với da. Hệ thống tắm mưa kết hợp tay sen linh hoạt mang lại trải nghiệm thư giãn, tiện lợi và phù hợp với nhu cầu sử dụng của nhiều thành viên trong gia đình. Với thiết kế bền chắc, vật liệu cao cấp và trải nghi','["https://seajong.com/wp-content/uploads/2025/02/SJ-074C.webp","https://seajong.com/wp-content/uploads/2025/02/sen-cay-tam-truyen-thong-SJ-SC0074B-SR-12.webp","https://seajong.com/wp-content/uploads/2025/02/sen-cay-tam-truyen-thong-SJ-SC0074B-SR-3.webp","https://seajong.com/wp-content/uploads/2025/02/sen-cay-seajong-sj-0074b-sr-cong-nghe-ma-5-lop.png","https://seajong.com/wp-content/uploads/2025/02/sen-cay-seajong-sj-0074b-sr-bang-inox-sus304-posco-han-quoc.png","https://seajong.com/wp-content/uploads/2025/02/Sen-cay-truyen-thong-Seajong-SJ-SC0074B-SR-watesoft.png","https://seajong.com/wp-content/uploads/2025/02/Sen-cay-truyen-thong-Seajong-SJ-SC0074B-SR-day-sen-sus304.png","https://seajong.com/wp-content/uploads/2025/02/sen-cay-seajong-sj-0074b-sr-thong-so-kt.png","https://seajong.com/wp-content/uploads/2025/02/Sen-cay-truyen-thong-Seajong-SJ-SC0074B-SR-2.png","https://seajong.com/wp-content/uploads/2025/02/sen-cay-seajong-sj-sc0074b-sr-4.png"]','{"Mã sản phẩm:":"SJ-SC0074B-SR","Kiểu dáng:":"Classic","Kích thước (mm):":"1400mm","Chất liệu:":"Đồng Italia 61%","Bề mặt:":"Mạ Chrome 5 lớp","Tiện ích":"Tắm mưa","Áp lực nước khuyến nghị":"0.05 ~ 1.2 Mpa","Trọng lượng":"2400 gram","Thời gian bảo hành":"5 năm"}',10100000.0,1782366141000,1782619250551,'https://seajong.com/wp-content/uploads/2025/02/SJ-074C.webp');
INSERT INTO SeajongProduct VALUES(9959,'den-dieu-hoa-cao-cap-seajong-sj-he883','https://seajong.com/den-dieu-hoa-cao-cap-seajong-sj-he883/','Đèn điều hòa cao cấp Seajong – SJ-HE883','Đèn điều hòa cao cấp Seajong – SJ-HE883 không chỉ mang đến sự ấm áp mà còn bảo vệ sức khỏe với công nghệ lọc không khí Plasma tiên tiến. Giữ cho không gian luôn thông thoáng, trong lành, an toàn. Khám phá thêm tính năng và thông số kỹ thuật ngay. Tính năng công [&hellip;]','Đèn điều hòa cao cấp Seajong – SJ-HE883 không chỉ mang đến sự ấm áp mà còn bảo vệ sức khỏe với công nghệ lọc không khí Plasma tiên tiến. Giữ cho không gian luôn thông thoáng, trong lành, an toàn. Khám phá thêm tính năng và thông số kỹ thuật ngay. Mục Lục Toggle Tính năng công nghệ Đối tượng sử dụng Sử dụng trong điều kiện thời tiết: Hướng dẫn cách lắp đặt đèn điều hòa phòng tắm Seajong Tính năng công nghệ Cấp không khí tươi: Sử dụng công nghệ Plasma giúp cung cấp không khí trong lành, tươi mát và phòng tránh được các vi khuẩn gây bệnh. Sưởi ấm bằng Heat Pump (Công nghệ Inverter): Sưởi ấm hiệu quả, tiết kiệm năng lượng và ổn định nhiệt độ. Chế độ quạt thông gió: Giúp lưu thông không khí, tạo không gian thoáng đãng. Chế độ chiếu sáng: Cung cấp ánh sáng với công nghệ LED tiết kiệm năng lượng. Chức năng hút ẩm (Dry Mode): Giảm độ ẩm trong không khí, ngăn ngừa nấm mốc. Chức năng hút mùi hôi: Loại bỏ mùi hôi trong không gian, mang lại không khí dễ chịu. Chức năng hẹn giờ tự tắt: Tiết kiệm năng lượng với tính năng tự động tắt sau thời gian cài đặt. Remote điều khiển từ xa: Dễ dàng điều chỉnh các chức năng mà không cần phải di chuyển. Màn hình LED hiển thị thông số nhiệt độ và thời gian: Cung cấp thông tin chi tiết về nhiệt độ và thời gian hoạt động. Hút ẩm bằng Rotor hấp thụ (Desiccant Dehumidifier): Hiệu quả hút ẩm, giữ không gian khô ráo. Sưởi ấm bằng thành nhiệt gốm PTC: Nhanh chóng làm ấm không khí một cách an toàn và hiệu quả. Đèn LED chiếu sáng (30.000 giờ): Công nghệ LED giúp tiết kiệm điện năng và đảm bảo tuổi thọ lâu dài. Đối tượng sử dụng Người mắc bệnh hô hấp: Hỗ trợ khử mùi, lọc không khí, giảm độ ẩm, giúp thở dễ dàng. Trẻ nhỏ: Cung cấp không khí trong lành, bảo vệ sức khỏe trẻ em. Phụ nữ mang thai: Tạo môi trường thoải mái, an toàn cho sức khỏe mẹ và bé. Người già: Cải thiện chất lượng không khí, giúp sống thoải mái và dễ thở hơn. Người làm việc trong môi trường văn phòng: Cung cấp không gian làm việc trong lành, giảm căng thẳng, và nâng cao hiệu quả công việc','["https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE883-1.webp","https://seajong.com/wp-content/uploads/2025/02/seajong-viet-nam-SJ-HE883-1.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE883-3.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE883-4.webp","https://seajong.com/wp-content/uploads/2025/02/BVSK-SJ-HE883-1.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE883-2.webp","https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE883-5.webp","https://seajong.com/wp-content/uploads/2025/02/BDK-Seajong-HE883-6.webp"]','{"Mã sản phẩm:":"SJ-HE883","Kiểu dáng:":"Âm trần","Kích thước (mm):":"- Rộng: 30cm\r\n- Dài: 60cm\r\n- Sâu: 12cm","Chất liệu:":"Mặt đèn: Nhựa PC – Chống cháy, bền bỉ \r\nKhung đèn: Hợp kim nhôm – Chống ăn mòn, tản nhiệt hiệu quả. \r\nHộp đèn: Nhựa ABS – Chống cháy, chịu lực tốt. \r\nĐộng cơ: Lõi kép đồng – Vận hành êm ái, bền bỉ.","Công nghệ":"Công nghệ Plasma","Tiện ích":"- Tổng công suất: 2600W.\r\n- Sưởi ấm: 1350W.\r\n- Đèn LED chiếu sáng: 24W.\r\n- Làm khô/quạt mát: 40W.\r\n- Thông gió/hút âm: 40W (lưu lượng hút 170m³/h).","Phụ kiện đi kèm:":"- Hộp đèn - Nắp đèn - Khung đèn - Bộ ốc vít - Giá đỡ - Thanh đệm - Ống bạc - Bảng điều khiển"}',5800000.0,1778655179000,1782619251352,'https://seajong.com/wp-content/uploads/2025/02/DDH-Seajong-HE883-1.webp');
INSERT INTO SeajongProduct VALUES(9967,'guong-phong-tam-sj-gs0060-sr','https://seajong.com/guong-phong-tam-sj-gs0060-sr/','Gương phòng tắm SJ-GS0060-SR Seajong Hàn Quốc','Giải Mã Công Nghệ Gương phòng tắm SJ-GS0060-SR Hà Quốc Sự nâng tầm của một kiến trúc nội thất đương đại luôn bắt đầu từ những chi tiết tinh xảo nhất. Trong hệ sinh thái thiết bị phòng tắm, chiếc gương không đơn thuần là vật dụng phản chiếu mà đã trở thành trung tâm [&hellip;]','Mục Lục Toggle Giải Mã Công Nghệ Gương phòng tắm SJ-GS0060-SR Hà Quốc 1. Tiêu Chuẩn Phôi gương tráng bạc Nhập Khẩu Châu Âu 2. Hệ Thống Điện Tử Chuẩn Xác Trên kính soi đèn led Khung Viền Inox Posco Trên gương đèn viền Và gương đèn hắt 3. Khởi Tạo không gian spa Bằng kiếng lavabo Và gương bo góc 4. Kiểm Soát Chất Lượng thiết bị vệ sinh cao cấp Và phụ kiện nhà tắm thông minh Giải Mã Công Nghệ Gương phòng tắm SJ-GS0060-SR Hà Quốc Sự nâng tầm của một kiến trúc nội thất đương đại luôn bắt đầu từ những chi tiết tinh xảo nhất. Trong hệ sinh thái thiết bị phòng tắm, chiếc gương không đơn thuần là vật dụng phản chiếu mà đã trở thành trung tâm công nghệ điều phối ánh sáng và cảm xúc. Hôm nay, chúng ta sẽ đi sâu bóc tách từng lớp vật liệu, hệ thống vi mạch điện tử và quy trình chế tác khắt khe đã tạo nên danh tiếng của Gương phòng tắm SJ-GS0060-SR, một siêu phẩm đến từ thương hiệu Seajong. Bài viết này sẽ phác họa rõ nét lý do vì sao sản phẩm này lại thiết lập một chuẩn mực mới trên thị trường kim khí và thiết bị vệ sinh. 1. Tiêu Chuẩn Phôi gương tráng bạc Nhập Khẩu Châu Âu Cốt lõi của mọi thiết bị phản chiếu nằm ở chất lượng phôi kính. Mẫu Gương phòng tắm SJ-GS0060-SR sử dụng 100% phôi kính Bỉ 5 ly cao cấp nhập khẩu trực tiếp từ Châu Âu. Áp dụng dây chuyền sản xuất kính phẳng tân tiến nhất hiện nay, sản phẩm sở hữu bề mặt gương tráng bạc 5 ly nhập khẩu với 3 lớp phủ siêu bền (gồm lớp bạc tinh khiết, lớp bảo vệ không chứa đồng Copper-free và lớp sơn màng Epoxy). Nhờ công nghệ tráng bạc 3 lớp cao cấp đạt chuẩn Châu Âu này, Gương phòng tắm SJ-GS0060-SR sở hữu khả năng kháng lại sự ăn mòn cực cao. Người dùng sẽ không bao giờ phải lo lắng về hiện tượng thâm kim hay ố viền thường thấy trên các sản phẩm gia công giá rẻ khi tiếp xúc với môi trường độ ẩm bão hòa. Đây cũng chính là cách chọn gương phòng tắm bền đẹp mà các kỹ sư luôn tư vấn cho chủ đầu tư. 2. Hệ Thống Điện Tử Chuẩn Xác Trên kính soi đèn led Vượt ra khỏi giới hạn của một mặt phẳng phản chiếu, Gương phòng tắm SJ-GS0060-SR ','["https://seajong.com/wp-content/uploads/2025/02/SJ-M60L.webp","https://seajong.com/wp-content/uploads/2025/02/guong-phong-tam-sjsg0060-sr.png","https://seajong.com/wp-content/uploads/2025/02/guong-phong-tam-ban-ve-kt.png","https://seajong.com/wp-content/uploads/2025/02/guong-led-gia-re-SJ-6060BS-4.webp","https://seajong.com/wp-content/uploads/2025/02/guong-phong-tam-tron.png","https://seajong.com/wp-content/uploads/2025/02/guong-phong-tam-cao-cap.png","https://seajong.com/wp-content/uploads/2025/02/guong-phong-tam-seajong-1.png","https://seajong.com/wp-content/uploads/2025/02/guong-phong-tam-tron-seajong.png"]','{"Mã sản phẩm:":"SJ-GS0060-SR","Kích thước (mm):":"Đường kính 60cm","Công nghệ":"Tráng bạc 3 lớp","Tiện ích":"Led + sấy cảm ứng","Nguồn điện":"220V – 5A","Dây LED":"Hàn Quốc","Điều khiển":"Cảm ứng một chạm","Thời gian bảo hành":"5 năm"}',4200000.0,1782214796000,1782619250645,'https://seajong.com/wp-content/uploads/2025/02/SJ-M60L.webp');
INSERT INTO SeajongProduct VALUES(11179,'tu-lavabo-pvc-foam-cao-cap-sj-tl0003','https://seajong.com/tu-lavabo-pvc-foam-cao-cap-sj-tl0003/','Tủ lavabo PVC Foam cao cấp SJ-TL0003','Tủ lavabo cao cấp SJ-TL0003 với chất liệu PVC Foam cao cấp, chống nước và chống cháy, kết hợp mặt đá nhân tạo chống xước và bám bẩn, mang lại không gian phòng tắm hiện đại và tiện lợi. Thiết kế tủ liền khối với ngăn kéo tiện dụng, kèm chậu sứ liền vành chống bám [&hellip;]','Tủ lavabo cao cấp SJ-TL0003 với chất liệu PVC Foam cao cấp, chống nước và chống cháy, kết hợp mặt đá nhân tạo chống xước và bám bẩn, mang lại không gian phòng tắm hiện đại và tiện lợi. Thiết kế tủ liền khối với ngăn kéo tiện dụng, kèm chậu sứ liền vành chống bám bẩn, bảo vệ sức khỏe người dùng. Tính năng công nghệ Tủ lavabo PVC Foam cao cấp SJ-TL0003 | Kích thước 100&#215;50 (cm) Tủ lavabo PVC Foam cao cấp SJ-TL0003 | Kích thước 80&#215;50 (cm) Chống nước và cháy, đảm bảo độ bền lâu dài, bảo vệ không gian phòng tắm khỏi ảnh hưởng của độ ẩm Mặt đá nhân tạo chống xước và bám bẩn kích thước 1000x500x100mm Hoàn thiện bề mặt chống xước Thiết kế Tủ liền khối với 2 ngăn kéo và 1 cánh mở Chậu sứ chống bám bẩn và ố vàng Phụ kiện SUS304 cao cấp Gương LED bỉ Màu sắc: Be và xám – mặt đá màu tùy chọn theo yêu cầu. Chống nước và cháy, đảm bảo độ bền lâu dài, bảo vệ không gian phòng tắm khỏi ảnh hưởng của độ ẩm Mặt đá nhân tạo chống xước và bám bẩn kích thước 800x500x100mm Hoàn thiện bề mặt chống xước Thiết kế Tủ liền khối với 2 ngăn kéo và 1 cánh mở Chậu sứ chống bám bẩn và ố vàng Phụ kiện SUS304 cao cấp Gương LED bỉ Màu sắc: Be và xám – với mặt đá màu tùy chọn. Seajong Faucet Việt Nam tự tin là thương hiệu hoạt động sản xuất và kinh doanh sản phẩm Tủ lavabo PVC Foam cao cấp chính hãng. Nếu quý khách tin tưởng và có nhu cầu mua hàng chính hãng hãy liên hệ với chúng tôi để được hỗ trợ và tư vấn tận tình nhất.','["https://seajong.com/wp-content/uploads/2025/03/tu-lavabo-pvc-foam-cao-cap-seajong-sj-003m.webp"]','{"Tủ lavabo PVC Foam cao cấp SJ-TL0003 | Kích thước 100&#215;50 (cm)":"Tủ lavabo PVC Foam cao cấp SJ-TL0003 | Kích thước 80&#215;50 (cm)","Mã sản phẩm:":"SJ-TL0003","Kích thước (mm):":"800 x 500 & 1000 x 500 (mm)","Chất liệu:":"PVC Foam cao cấp","Phiên bản":"Mặt đá & Mặt sứ","Tiện ích":"Gương bỉ LED+ Sấy bo vành kim loại phủ titan","Màu sắc":"Xám & Be","Phụ kiện đi kèm:":"Bản lề, vít bằng SUS304. Day kéo piton 1nt nhập khẩu EU","Trọng lượng":"Tủ 15kg, Mặt đá 15kg","Xử lý bề mặt":"Làm nhẵn bằng keo bả chuyên dụng + Sơn xử lý bề mặt chống xước"}',11800000.0,1778664427000,1782619250511,'https://seajong.com/wp-content/uploads/2025/03/tu-lavabo-pvc-foam-cao-cap-seajong-sj-003m.webp');
INSERT INTO SeajongProduct VALUES(11181,'tu-lavabo-pvc-foam-cao-cap-sj-001m','https://seajong.com/tu-lavabo-pvc-foam-cao-cap-sj-001m/','Tủ lavabo PVC Foam cao cấp SJ-001M | 1000&#215;500 &#038; 800&#215;500 (mm)','Tủ lavabo cao cấp Seajong SJ-001M được làm từ PVC Foam cao cấp, chống nước và chống cháy, kết hợp mặt đá nhân tạo chống xước và bám bẩn. Tủ thiết kế liền khối với ngăn kéo và cánh mở tiện dụng, cùng với chậu sứ liền vành giúp tạo không gian phòng tắm hiện [&hellip;]','Tủ lavabo cao cấp Seajong SJ-001M được làm từ PVC Foam cao cấp, chống nước và chống cháy, kết hợp mặt đá nhân tạo chống xước và bám bẩn. Tủ thiết kế liền khối với ngăn kéo và cánh mở tiện dụng, cùng với chậu sứ liền vành giúp tạo không gian phòng tắm hiện đại và dễ dàng vệ sinh. Mục Lục Toggle Tính năng công nghệ 1. Tủ lavabo PVC Foam cao cấp SJ-001M | 1000&#215;500 (mm) 2. Tủ lavabo PVC Foam cao cấp SJ-001M | 800&#215;500 (mm) Thông số kỹ thuật 1. Tủ lavabo PVC Foam cao cấp SJ-001M | 1000&#215;500 (mm) 2. Tủ lavabo PVC Foam cao cấp SJ-001M | 800&#215;500 (mm) Tính năng công nghệ 1. Tủ lavabo PVC Foam cao cấp SJ-001M | 1000&#215;500 (mm) Chất liệu PVC Foam cao cấp: Chống nước và cháy, giúp bảo vệ tủ khỏi tác động của độ ẩm và đảm bảo độ bền lâu dài. Mặt đá nhân tạo chống xước và bám bẩn: Mặt đá 1000x500x100mm dễ dàng vệ sinh, chống ố vàng và giữ độ sáng bóng. Hoàn thiện bề mặt chống xước: Bề mặt được xử lý bằng keo bả chuyên dụng và sơn chống xước, giúp bảo vệ tủ khỏi các vết trầy xước. Tủ liền khối với 2 ngăn kéo và 1 cánh mở: Tạo không gian lưu trữ tối ưu và dễ dàng sử dụng. Chậu sứ chống bám bẩn và ố vàng: Chậu sứ 490x390mm có vành liền âm bàn, giúp giữ cho bề mặt luôn sạch sẽ và không bị ố vàng. Phụ kiện SUS304 cao cấp: Bản lề, vít và dây kéo piton nhập khẩu từ EU giúp tăng độ bền và tính thẩm mỹ của sản phẩm. Gương LED bỉ: Gương LED với hệ thống sấy và bo vành kim loại phủ titan, mang lại vẻ đẹp sang trọng cho không gian phòng tắm. Màu sắc: Có sẵn 2 màu lựa chọn: Trắng sữa và xám, mặt đá màu tùy chọn theo yêu cầu. 2. Tủ lavabo PVC Foam cao cấp SJ-001M | 800&#215;500 (mm) Chất liệu PVC Foam cao cấp: Chống nước và chống cháy, giúp bảo vệ tủ khỏi tác động của độ ẩm và đảm bảo độ bền lâu dài. Mặt đá nhân tạo chống xước và bám bẩn: Mặt đá 800x500x100mm dễ dàng vệ sinh, chống ố vàng và giữ độ sáng bóng. Hoàn thiện bề mặt chống xước: Bề mặt được xử lý bằng keo bả chuyên dụng và sơn chống xước, giúp bảo vệ tủ khỏi các vết trầy xước. Tủ liền khối với 2 ngăn kéo và 1 cán','["https://seajong.com/wp-content/uploads/2025/03/tu-lavabo-pvc-foam-cao-cap-seajong-sj-001m.webp"]','{"Mã sản phẩm:":"SJ-001M","Kích thước (mm):":"1000 x 500 | 800 x 500 (mm)"}',4200000.0,1778664382000,1782619250568,'https://seajong.com/wp-content/uploads/2025/03/tu-lavabo-pvc-foam-cao-cap-seajong-sj-001m.webp');
INSERT INTO SeajongProduct VALUES(11183,'tu-lavabo-pvc-foam-cao-cap-sj-tl0002','https://seajong.com/tu-lavabo-pvc-foam-cao-cap-sj-tl0002/','Tủ lavabo PVC Foam cao cấp SJ-TL0002','Tủ lavabo PVC Foam cao cấp SJ-TL0002 với chất liệu PVC Foam cao cấp, chống nước và cháy, cùng mặt đá nhân tạo chống xước và bám bẩn. Thiết kế tủ liền khối với ngăn kéo tiện lợi và chậu sứ liền vành, mang lại không gian phòng tắm hiện đại và bền bỉ. Sản phẩm [&hellip;]','Tủ lavabo PVC Foam cao cấp SJ-TL0002 với chất liệu PVC Foam cao cấp, chống nước và cháy, cùng mặt đá nhân tạo chống xước và bám bẩn. Thiết kế tủ liền khối với ngăn kéo tiện lợi và chậu sứ liền vành, mang lại không gian phòng tắm hiện đại và bền bỉ. Sản phẩm có hai màu sắc lựa chọn: trắng sữa và xám, thích hợp với mọi không gian. Tìm hiểu 2 mã sản phẩm bên dưới ngay. Tính năng công nghệ Tủ lavabo PVC Foam cao cấp SJ-TL0002 | Kích thước 100&#215;50 (cm) Tủ lavabo PVC Foam cao cấp SJ-TL0002 | Kích thước 80&#215;50 (cm) Chống nước, chống cháy, đảm bảo độ bền lâu dài. Mặt đá nhân tạo chống xước và bám bẩn 1000x500x100mm Hoàn thiện bề mặt chống xước Thiết kế Tủ liền khối với 2 ngăn kéo và 1 cánh mở Chậu sứ chống bám bẩn và ố vàng 490x390mm Phụ kiện SUS304 cao cấp Gương LED bỉ Màu sắc: Be và xám – mặt đá màu tùy chọn theo yêu cầu. Chống nước, chống cháy, đảm bảo độ bền lâu dài. Mặt đá nhân tạo chống xước và bám bẩn 800x500x100mm Hoàn thiện bề mặt chống xước Thiết kế Đóng tủ liền khối với 2 ngăn kéo và 1 cánh mở Chậu sứ chống bám bẩn và ố vàng 490x390mm Phụ kiện SUS304 cao cấp Gương bỉ LED Màu sắc: be và xám – mặt đá tùy chọn màu theo yêu cầu Từ thông tin chi tiết của sản phẩm như trên, nếu quý khách đang có nhu cầu mua Tủ lavabo PVC Foam cao cấp chính hãng, hãy liên hệ với chúng tôi để được hỗ trợ và tư vấn tận tình nhất.','["https://seajong.com/wp-content/uploads/2025/03/tu-lavabo-pvc-foam-cao-cap-seajong-sj-002g.webp"]','{"Mã sản phẩm:":"SJ-TL0002","Kích thước (mm):":"800 x 500 & 1000 x 500 (mm)","Chất liệu:":"PVC Foam cao cấp","Tiện ích":"Gương bỉ LED + Sấy bo vành kim loại phủ titan","Phụ kiện đi kèm:":"Bản lề, vít bằng SUS304. Day kéo piton 1nt nhập khẩu EU","Trọng lượng":"Tủ 15kg, Mặt đá 15kg","Xử lý bề mặt":"Làm nhẵn bằng keo bả chuyên dụng + Sơn xử lý bề mặt chống xước"}',9400000.0,1778664434000,1782619250566,'https://seajong.com/wp-content/uploads/2025/03/tu-lavabo-pvc-foam-cao-cap-seajong-sj-002g.webp');
INSERT INTO SeajongProduct VALUES(11185,'voi-bep-day-rut-cao-cap-sj-302c','https://seajong.com/voi-bep-day-rut-cao-cap-sj-302c/','Vòi bếp dây rút cao cấp Seajong SJ-302C','Vòi bếp dây rút cao cấp SJ-302C mang đến sự đột phá trong thiết kế với dây cấp nước silicon cao cấp, mềm dẻo và xoay linh hoạt 360 độ. Từng đường nét được chăm chút tỉ mỉ, kết hợp cùng lớp mạ Chrome sáng bóng, giúp không gian bếp trở nên sang trọng và [&hellip;]','Vòi bếp dây rút cao cấp SJ-302C mang đến sự đột phá trong thiết kế với dây cấp nước silicon cao cấp, mềm dẻo và xoay linh hoạt 360 độ. Từng đường nét được chăm chút tỉ mỉ, kết hợp cùng lớp mạ Chrome sáng bóng, giúp không gian bếp trở nên sang trọng và hiện đại. Tính năng công nghệ Dây cấp nước silicon cao cấp: Linh hoạt xoay 360 độ, giúp rửa chén bát và vệ sinh chậu bếp thuận tiện hơn. Ba chế độ phun nước tiện dụng: Tăng áp, xịt rửa và dòng chảy thông thường, tối ưu hóa trải nghiệm sử dụng. Lõi trộn SEDAL (Tây Ban Nha): Độ bền cao, tuổi thọ đóng mở lên đến 600.000 lần, đảm bảo sự ổn định và trơn tru trong quá trình sử dụng. Lớp mạ Chrome và PVD cao cấp: Được xử lý qua công nghệ hiện đại, giúp bề mặt sáng bóng, chống bám bẩn, đảm bảo độ bền theo thời gian. Thử nghiệm sương muối 72 giờ: Khẳng định khả năng chống ăn mòn vượt trội, giúp sản phẩm luôn giữ được vẻ đẹp hoàn hảo. Vòi bếp dây rút cao cấp SJ-302C không chỉ là thiết bị tiện ích mà còn là điểm nhấn tinh tế giúp gian bếp của bạn trở nên đẳng cấp hơn. Với thiết kế hiện đại và công nghệ tiên tiến, đây là sự lựa chọn lý tưởng để tối ưu trải nghiệm sử dụng hàng ngày. Nếu bạn đang có nhu cầu và tìm kiếm nơi mua hàng chính hãng, hãy liên hệ với chúng tôi để được hỗ trợ và tư vấn tận tình nhất. ⇒Xem thêm các mẫu vòi bếp khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-302c.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-sfv-302s-2.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-sfv-302s.webp"]','{"Mã sản phẩm:":"SJ-302C","Kích thước (mm):":"Cao: 350mm","Chất liệu:":"Đồng 61A, không chứa chì, an toàn cho nguồn nước.","Chiều dài dây rút":"800mm","Tiện ích":"Dây rút tiện lợi + Đầu phun nước 2 chế độ","Màu sắc":"Chrome","Trọng lượng":"1800 gram","Xử lý bề mặt":"Đánh bóng, mạ Chrome, niken","Lõi trộn":"SEDAL (Tây ban nha)"}',4500000.0,1781170964000,1782619250646,'https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-302c.webp');
INSERT INTO SeajongProduct VALUES(11190,'sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56','https://seajong.com/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56/','Sen cây phím đàn tắm đứng cao cấp SJ-SC56','Sen cây phím đàn tắm đứng cao cấp SJ-SC56 được chế tác từ chất liệu đồng nguyên chất kết hợp công nghệ mạ 5 lớp tiên tiến, vừa đảm bảo tính thẩm mỹ, vừa mang lại sự an toàn, bền bỉ và tiện nghi vượt trội trong quá trình sử dụng. Tính năng công nghệ Công [&hellip;]','Sen cây phím đàn tắm đứng cao cấp SJ-SC56 được chế tác từ chất liệu đồng nguyên chất kết hợp công nghệ mạ 5 lớp tiên tiến, vừa đảm bảo tính thẩm mỹ, vừa mang lại sự an toàn, bền bỉ và tiện nghi vượt trội trong quá trình sử dụng. Tính năng công nghệ Công nghệ Smart chống bỏng tuyệt đối với van nhiệt tự động chuẩn EN111 châu Âu, giúp duy trì nhiệt độ ổn định ở mức an toàn 38–40°C, ngăn ngừa tình trạng sốc nhiệt và bảo vệ hiệu quả cho trẻ nhỏ, người cao tuổi. Hệ thống màn hình kỹ thuật số hiển thị nhiệt độ và thời gian thực hoạt động nhờ tuabin thủy lực tạo điện năng từ dòng nước, không cần pin, vừa thân thiện môi trường vừa mang đến sự tiện lợi, giúp người dùng dễ dàng theo dõi và điều chỉnh nhiệt độ chính xác trong suốt quá trình sử dụng. Bộ bát sen trần và tay sen tắm đa chế độ được chế tác từ nhựa ABS mạ PVD cao cấp, chống ố vàng, không trầy xước, mang lại trải nghiệm tắm mưa thư giãn kết hợp tay sen 3 chế độ (phun thường, phun massage, phun kết hợp) đáp ứng mọi nhu cầu thư giãn và chăm sóc cơ thể. Dây sen và dây xịt EPDM cao cấp được bện ba lớp phủ PVD, dẻo dai, chống xoắn và chịu lực kéo tốt; ở phiên bản bọc inox SUS304, sản phẩm còn gia tăng độ bền, khả năng kháng trầy xước và vẻ đẹp thẩm mỹ tinh tế cho toàn bộ bộ sen. Toàn bộ sản phẩm được sản xuất từ vật liệu an toàn tuyệt đối cho sức khỏe, với hàm lượng chì chỉ 0,01%, thấp hơn 25 lần so với khuyến cáo của WHO, kết hợp cùng thân sen đúc từ đồng nguyên chất ≥ 61% nhập khẩu từ Ý giúp chống ăn mòn vượt trội và đảm bảo độ bền dài lâu. Lớp xử lý bề mặt hiện đại được mạ 5 lớp nikel kết hợp công nghệ PVD xám cao cấp, mang lại độ sáng bóng hoàn hảo, khả năng chống trầy xước, chống bong tróc và không đổi màu ngay cả trong môi trường ẩm ướt, đồng thời đạt độ hoàn thiện chuẩn châu Âu với độ nhám Ra ≤ 0.2 µm và độ bóng Gloss ≥ 85 GU. Liên hệ mua hàng chính hãng tại Seajong Nếu bạn đang có nhu cầu và tìm kiếm địa chỉ mua hàng sen cây phím đàn tắm đứng cao cấp chính hãng, hãy liên hệ với Seajong để được hỗ trợ và tư vấn tận','["https://seajong.com/wp-content/uploads/2025/10/SJ-SC56.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56-5.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56-4.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56-3.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56-2.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56-1.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-phim-dan-tam-dung-cao-cap-sj-sc56.webp"]','{"Mã sản phẩm:":"SJ-SC56","Kiểu dáng:":"Phím đàn","Kích thước (mm):":"Chiều cao toàn bộ: 1350mm","Chất liệu:":"Đồng 61% + SUS304 + Nhựa ABS + EPDM","Phiên bản":"4 Phím đàn","Công nghệ":"Chống bỏng tuyệt đối, đồng hồ KTS hiển thị nhiệt độ chuẩn xác","Tiện ích":"Tắm mưa, tắm xả, chức năng Smart hiển thị nhiệt độ và thời gian thực","Màu sắc":"Gray, Pearl White, Gold","Phụ kiện đi kèm:":"Thân vỏ + Thân ống thẳng, cong + Bát sen lớn, nhỏ + Dây sen + Chân sen + Giá đỡ trượt tay + Dây xịt lò xo + Đầu xịt + Vỏ hộp + Phụ tùng ốc lắp đặt","Trọng lượng":"Tổng thể: 7500 gram","Dây sen":"Dây sen sản xuất từ EPDM bện ba lớp phủ PVD cao cấp","Bát sen":"Bát sen trần, tay sen tắm bằng nhựa ABS mạ PVD cao cấp 3 chức năng","Lõi trộn":"SEDAL (Tây ban nha)","Điểm khác biệt":"Hàm lượng chì Pb =0,01% thấp hơn mức 0,25% do WHO khuyến cáo"}',15000000.0,1778211555000,1782619250342,NULL);
INSERT INTO SeajongProduct VALUES(11198,'sen-cay-tam-dung-cao-cap-sj-0072b-sr','https://seajong.com/sen-cay-tam-dung-cao-cap-sj-0072b-sr/','Sen cây tắm đứng Seajong SJ-SC072B-SR','Thiết kế tinh tế – hiện đại – bền bỉ , phù hợp phòng tắm cao cấp. Thân củ bằng đồng Italia 61% , chắc chắn và chịu áp lực nước tốt. Cần sen bằng inox SUS304 Posco Hàn Quốc , chống han gỉ, chống ăn mòn. Bề mặt mạ Chrome 5 lớp , sáng bóng, sang trọng và dễ vệ sinh. Van lõi Sedal Tây Ban Nha , vận hành êm, điều chỉnh nóng lạnh chính xác. Đúc áp lực thấp phân tách chì , hàm lượng chì kiểm soát ở mức 0,025% Pb . Công nghệ Wartesoft tạo dòng nước mềm mại, dễ chịu khi tắm. Tích hợp tắm mưa và tay sen l','Sen cây tắm đứng cao cấp Seajong SJ-SC072B-SR Sen cây tắm đứng cao cấp SEAJONG là dòng sản phẩm được thiết kế dành cho những không gian phòng tắm hiện đại, sang trọng và yêu cầu cao về độ bền, độ an toàn cũng như trải nghiệm sử dụng hằng ngày. Sản phẩm sở hữu kiểu dáng thanh lịch, bề mặt mạ Chrome sáng bóng, dễ vệ sinh và phù hợp với nhiều không gian như nhà phố, căn hộ cao cấp, biệt thự, showroom và khách sạn. Điểm nổi bật của sản phẩm nằm ở hệ vật liệu cao cấp. Thân củ được chế tác từ đồng Italia 61% , cho kết cấu chắc chắn, chịu áp lực nước tốt và hạn chế biến dạng trong quá trình sử dụng lâu dài. Cần sen cây sử dụng inox SUS304 Posco Hàn Quốc , giúp tăng khả năng chống han gỉ, chống ăn mòn và duy trì độ bền ổn định trong môi trường phòng tắm ẩm ướt. Bề mặt sản phẩm được xử lý bằng công nghệ mạ Chrome 5 lớp , tạo độ sáng bóng sang trọng, nâng cao khả năng chống oxy hóa, chống bong tróc và giúp sản phẩm giữ được vẻ đẹp bền lâu. Kết hợp với thiết kế tinh tế, sen cây SEAJONG không chỉ là thiết bị tắm rửa mà còn là điểm nhấn thẩm mỹ cho toàn bộ không gian phòng tắm. Về khả năng vận hành, sản phẩm sen cây Seajong được sử dụng van lõi Sedal Tây Ban Nha , cho thao tác đóng mở nhẹ, điều chỉnh nóng lạnh chính xác, hạn chế rò rỉ và tăng tuổi thọ sử dụng. Công nghệ đúc áp lực thấp phân tách chì giúp kiểm soát hàm lượng chì ở mức 0,025% Pb , an toàn hơn cho nguồn nước sinh hoạt và sức khỏe người dùng. Đặc biệt, sản phẩm ứng dụng công nghệ Wartesoft , giúp dòng nước phun ra mềm mại, đều và dễ chịu khi tiếp xúc với da. Chế độ tắm mưa kết hợp tay sen linh hoạt mang lại trải nghiệm thư giãn, tiện lợi và phù hợp với nhu cầu sử dụng của nhiều thành viên trong gia đình. Đây hoàn toàn là sản phẩm cao cấp tối ưu thay thế phù hợp cho sen cây inax, sen cây toto, sen cây viglacera, sen cây grohe, sen cây caesa, sen cây enic','["https://seajong.com/wp-content/uploads/2025/03/SJ-072C.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-tam-dung-cao-cap-sj-072c-a.webp","https://seajong.com/wp-content/uploads/2025/03/van-loi-gom-sedal-seajong-1.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-tam-dung-cao-cap-sj-072c-b.webp","https://seajong.com/wp-content/uploads/2025/03/SJ-072C-2.webp"]','{"Mã sản phẩm:":"SJ-SC0072B-SR","Kiểu dáng:":"Dáng tròn truyền thống","Kích thước (mm):":"1400mm","Bề mặt:":"Mạ chrome","Tiện ích":"Tắm mưa","Màu sắc":"mạ Chrome","Áp lực nước khuyến nghị":"0.05 ~ 1.2 Mpa","Cân nặng củ sen":"2800gr","Xử lý bề mặt":"Mạ Chrome 5 lớp","Lõi trộn":"SEDAL (Tây ban nha)","Điểm khác biệt":"0,025%Pb","Thời gian bảo hành":"5 năm"}',13500000.0,1782359729000,1782619250402,'https://seajong.com/wp-content/uploads/2025/03/SJ-072C.webp');
INSERT INTO SeajongProduct VALUES(11208,'sen-cay-tam-dung-cao-cap-sj-073c','https://seajong.com/sen-cay-tam-dung-cao-cap-sj-073c/','Sen cây tắm đứng Seajong SJ-SC0073B-SR','Sen cây tắm đứng cao cấp Seajong SJ-SC0073B-SR với chất liệu đồng mạ crom, PVC, và lõi trộn SEDAL mang lại chức năng cố định nhiệt độ, giúp bạn tận hưởng những giây phút tắm mưa hay tắm thường thư giãn. Khám phá chi tiết bên dưới ngay. Tính năng công nghệ Sen cây tắm đứng [&hellip;]','Sen cây tắm đứng cao cấp Seajong SJ-SC0073B-SR với chất liệu đồng mạ crom, PVC, và lõi trộn SEDAL mang lại chức năng cố định nhiệt độ, giúp bạn tận hưởng những giây phút tắm mưa hay tắm thường thư giãn. Khám phá chi tiết bên dưới ngay. Tính năng công nghệ Sen cây tắm đứng cao cấp Seajong SJ-SC0073B-SR Chất liệu cao cấp: Sản phẩm làm từ đồng mạ crom và PVC, mang lại độ bền vượt trội, chống ăn mòn và dễ dàng vệ sinh. Chức năng cố định nhiệt độ: Giúp duy trì nhiệt độ nước ổn định, mang lại sự thoải mái khi tắm. Tắm mưa và tắm thường: Cung cấp 2 chế độ tắm với các kiểu dòng nước khác nhau cho trải nghiệm tắm hoàn hảo. Lõi trộn SEDAL: Lõi trộn chất lượng từ Tây Ban Nha giúp điều chỉnh dòng nước chính xác và hiệu quả. Thiết kế linh hoạt: Ống thẳng dài 800mm và ống cong 600mm cho phép điều chỉnh chiều cao và lắp đặt dễ dàng trong không gian phòng tắm. Nếu bạn đang có nhu cầu và tìm kiếm nơi mua hàng chính hãng, hãy liên hệ với chúng tôi để được hỗ trợ và tư vấn tận tình nhất.','["https://seajong.com/wp-content/uploads/2025/03/SJ-073C.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-tam-dung-cao-cap-sj-073c.webp","https://seajong.com/wp-content/uploads/2025/03/SJ-073C-2.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-truyen-thong-tam-dung-SJ-SC0073B-SR-11.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-truyen-thong-tam-dung-SJ-SC0073B-SR-5.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-truyen-thong-tam-dung-SJ-SC0073B-SR-6.webp","https://seajong.com/wp-content/uploads/2025/03/sen-cay-truyen-thong-tam-dung-SJ-SC0073B-SR-12.webp"]','{"Mã sản phẩm:":"SJ-SC0073B-SR","Kích thước (mm):":"1350mm","Chất liệu:":"Đồng Italia 61%","Công nghệ":"Cố định nhiệt độ","Tiện ích":"Tắm mưa","Màu sắc":"Chrome","Trọng lượng":"2400gr","Xử lý bề mặt":"Chrome 5 lớp","Thời gian bảo hành":"5 năm"}',13100000.0,1782371406000,1782619250330,'https://seajong.com/wp-content/uploads/2025/03/SJ-073C.webp');
INSERT INTO SeajongProduct VALUES(11219,'voi-bep-day-rut-cao-cap-seajong-sj-vb009-sr','https://seajong.com/voi-bep-day-rut-cao-cap-seajong-sj-vb009-sr/','Vòi bếp dây rút cao cấp Seajong SJ-VB009-SR','Vòi bếp dây rút cao cấp Seajong SJ-VB009-SR của Saejong sở hữu thiết kế tỉ mỉ, tinh tế, mang lại sự sang trọng và hiện đại cho không gian bếp. Với công nghệ đổi mới và chất liệu cao cấp, hứa hẹn rằng SJ-VB009-SR sẽ mang đến trải nghiệm tuyệt vời và sự tiện nghi [&hellip;]','Vòi bếp dây rút cao cấp Seajong SJ-VB009-SR của Saejong sở hữu thiết kế tỉ mỉ, tinh tế, mang lại sự sang trọng và hiện đại cho không gian bếp. Với công nghệ đổi mới và chất liệu cao cấp, hứa hẹn rằng SJ-VB009-SR sẽ mang đến trải nghiệm tuyệt vời và sự tiện nghi tối đa cho căn bếp của bạn Tính năng công nghệ Thiết kế dây rút linh hoạt : Dây cấp nước silicon cao cấp có khả năng xoay 360º, giúp việc rửa chén dĩa và vệ sinh chậu bếp trở nên dễ dàng hơn bao giờ hết. Đầu phun đa chế độ : 3 chế độ nước tùy chỉnh gồm tăng áp, xịt rửa mạnh và dòng chảy mềm mại, phù hợp với nhiều nhu cầu sử dụng. Chất liệu cao cấp, bền bỉ : Chất liệu đồng hợp kim kết hợp với lớp mạ Chrome và Niken đảm bảo độ sáng đẹp và chống bám bẩn hiệu quả. Lỗi trộn nước cao cấp : Sử dụng van lõi trộn nước SEDAL (Tây Ban Nha), đáp ứng trên 600.000 lần đóng mở mà vẫn đảm bảo tính ổn định và bền bỉ. Xử lý bề mặt cao cấp : Mạ Chrome kết hợp mạ PVD giúp vòi bếp bền màu, chống oxy hóa, vượt qua kiểm định sương muối trong 72h liên tục. Màu sắc sang trọng : Tôn vinh không gian bếp với gam màu Chrome đẹp mắt, tinh tế. Hai dây cấp nước bền bỉ : Chịu nhiệt và áp lực cao, về ngoài bọc inox chống hoen gỉ. Vòi bếp dây rút cao cấp Seajong SJ-VB009-SR không chỉ là một vòi bếp, đó là sự kết hợp giữa công nghệ và thẩm mỹ, giúp người dùng có những trải nghiệm sử dụng tính tế nhất. Liên hệ ngay để sở hữu và nâng tầm không gian bếp nhà bạn với siêu phẩm này của Seajong. ⇒Xem thêm các mẫu vòi bếp khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/03/SJ-VB009-SR.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf009-3.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf009.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf009-4.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf009-2.webp"]','{"Mã sản phẩm:":"SJ-VB009-SR","Kích thước (mm):":"Chiều Cao: 420mm","Chất liệu:":"Đồng 61% - Chrome - nhựa ABS","Chiều dài dây rút":"800mm","Tiện ích":"Dây rút tiện lợi có đầu phun 3 chế độ","Trọng lượng":"1900 gram","Xử lý bề mặt":"Đánh bóng công nghệ cao, mạ Chrome, niken","Lõi trộn":"SEDAL (Tây ban nha)"}',7600000.0,1778731252000,1779982231615,'https://seajong.com/wp-content/uploads/2025/03/SJ-VB009-SR.webp');
INSERT INTO SeajongProduct VALUES(11227,'voi-bep-day-rut-sj-vb3045-sr','https://seajong.com/voi-bep-day-rut-sj-vb3045-sr/','Vòi bếp dây rút cao cấp Seajong SJ-VB3045-SR','Vòi bếp dây rút sj-vb3045-SR giải pháp nâng cấp trải nghiệm rửa cho căn bếp hiện đại Trong một căn bếp sử dụng hằng ngày, vòi bếp không chỉ cần đẹp mà còn phải bền, linh hoạt và an toàn cho nguồn nước sinh hoạt. Vòi bếp dây rút sj-vb3045-SR được Seajong phát triển theo [&hellip;]','Mục Lục Toggle Vòi bếp dây rút sj-vb3045-SR giải pháp nâng cấp trải nghiệm rửa cho căn bếp hiện đại 1. Vòi bếp dây rút linh hoạt cho mọi thao tác rửa 2. Vòi rửa bát dây rút với công nghệ đầu phun Wartesoft 3. Vòi bếp inox 304 bền bỉ từ vật liệu Posco Hàn Quốc 4. Vòi bếp nóng lạnh sử dụng van lõi Sedal Tây Ban Nha 5. Vòi rửa chén cao cấp đạt tiêu chuẩn chất lượng rõ ràng Vòi bếp dây rút sj-vb3045-SR giải pháp nâng cấp trải nghiệm rửa cho căn bếp hiện đại Trong một căn bếp sử dụng hằng ngày, vòi bếp không chỉ cần đẹp mà còn phải bền, linh hoạt và an toàn cho nguồn nước sinh hoạt. Vòi bếp dây rút sj-vb3045-SR được Seajong phát triển theo hướng đó: hiện đại về kiểu dáng, chắc chắn về vật liệu và tiện dụng trong từng thao tác rửa. Điểm đáng chú ý của Vòi bếp dây rút sj-vb3045-SR là phần thân sử dụng inox SUS304 của Posco Hàn Quốc, vật liệu có khả năng chống gỉ, chống ăn mòn tốt trong môi trường bếp thường xuyên tiếp xúc với nước, dầu mỡ và chất tẩy rửa. Thành phần không chứa chì giúp sản phẩm an toàn hơn cho người sử dụng, đặc biệt với các gia đình chú trọng sức khỏe và chất lượng nước sinh hoạt. 1. Vòi bếp dây rút linh hoạt cho mọi thao tác rửa Ưu thế lớn nhất của Vòi bếp dây rút sj-vb3045-SR nằm ở thiết kế dây rút linh hoạt. Người dùng có thể kéo đầu vòi để rửa nồi sâu, xả rau củ, tráng lòng chậu hoặc làm sạch các góc khuất quanh bồn rửa. Với các căn bếp hiện đại, đây là tính năng rất thực tế vì giúp giảm thời gian vệ sinh và hạn chế nước bắn ra ngoài. Cơ chế dây rút được thiết kế để thao tác mượt, thu hồi gọn, không gây vướng víu khi sử dụng hằng ngày. Nhờ đó, Vòi bếp dây rút sj-vb3045-SR phù hợp với cả gia đình nấu ăn thường xuyên lẫn các không gian bếp mở cần sự gọn gàng, sạch sẽ. 2. Vòi rửa bát dây rút với công nghệ đầu phun Wartesoft Một vòi rửa tốt không chỉ mạnh nước mà còn cần dòng chảy êm, đều và dễ kiểm soát. Vòi bếp dây rút sj-vb3045-SR sử dụng phụ kiện đầu phun ứng dụng công nghệ Wartesoft của Thụy Sĩ, giúp tạo bọt khí mịn, giảm bắn tóe và mang lại cảm giác','["https://seajong.com/wp-content/uploads/2025/03/ChatGPT-Image-12_03_41-12-thg-6-2026.png","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf3045c.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf3045c-3.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-sj-vb-3045-sr.png"]','{"Mã sản phẩm:":"SJ-VB3045-SR","Kiểu dáng:":"Vòi dây rút","Kích thước (mm):":"420mm","Chất liệu:":"INOX SUS304 Posc","Chiều dài dây rút":"800mm","Áp lực nước khuyến nghị":"0.05 ~ 1.2 Mpa","Trọng lượng":"1900 gram","Xử lý bề mặt":"Brushed Hairline","Lõi trộn":"SEDAL (Tây ban nha)","Điểm khác biệt":"0,025%Pb","Thời gian bảo hành":"10 năm"}',4300000.0,1781245904000,1782619250359,'https://seajong.com/wp-content/uploads/2025/03/SJ-VB3045-SR.webp');
INSERT INTO SeajongProduct VALUES(11233,'voi-bep-day-rut-sj-vb3046-sr','https://seajong.com/voi-bep-day-rut-sj-vb3046-sr/','Vòi bếp dây rút cao cấp Seajong SJ-VB3046-SR','Vòi bếp dây rút sj-vb3046-SR. Chuẩn mới cho căn bếp hiện đại, sạch và tiện nghi Trong một căn bếp cao cấp, vòi bếp không chỉ là thiết bị cấp nước mà còn là chi tiết quyết định trực tiếp đến trải nghiệm nấu nướng, rửa dọn và thẩm mỹ tổng thể. Vòi bếp dây [&hellip;]','Mục Lục Toggle Vòi bếp dây rút sj-vb3046-SR. Chuẩn mới cho căn bếp hiện đại, sạch và tiện nghi 1. Vòi bếp dây rút linh hoạt cho thao tác rửa hằng ngày 2. Vòi rửa bát dây rút bằng inox SUS304 Posco Hàn Quốc 3. Vòi bếp inox 304 với công nghệ đúc áp lực thấp 4. Vòi bếp nóng lạnh sử dụng van lõi Sedal Tây Ban Nha 5. Vòi rửa chén cao cấp với đầu phun Wartesoft Thụy Sĩ Vòi bếp dây rút sj-vb3046-SR. Chuẩn mới cho căn bếp hiện đại, sạch và tiện nghi Trong một căn bếp cao cấp, vòi bếp không chỉ là thiết bị cấp nước mà còn là chi tiết quyết định trực tiếp đến trải nghiệm nấu nướng, rửa dọn và thẩm mỹ tổng thể. Vòi bếp dây rút sj-vb3046-sr được Seajong phát triển dành cho những gia đình cần một mẫu vòi bền bỉ, an toàn, linh hoạt và phù hợp với nhịp sống hiện đại. Điểm mạnh đầu tiên của Vòi bếp dây rút sj-vb3046-sr nằm ở thiết kế dây rút thông minh. Người dùng có thể kéo đầu vòi để rửa nồi sâu, tráng rau củ, vệ sinh lòng chậu hoặc làm sạch các góc khuất quanh bồn rửa. Với các căn bếp sử dụng chậu lớn, bàn đảo hoặc không gian bếp mở, thiết kế này giúp thao tác nhanh hơn, gọn hơn và hạn chế nước bắn ra ngoài khu vực rửa. 1. Vòi bếp dây rút linh hoạt cho thao tác rửa hằng ngày Một chiếc vòi bếp dây rút chất lượng cần giải quyết được các nhu cầu rất thực tế: kéo ra nhẹ, thu về gọn, dòng nước ổn định và dễ kiểm soát. Vòi bếp dây rút sj-vb3046-sr được thiết kế để hỗ trợ người dùng trong nhiều tình huống, từ rửa bát đĩa, xả thực phẩm đến vệ sinh toàn bộ lòng chậu sau khi nấu ăn. Dây rút linh hoạt giúp người dùng không phải xoay nồi chảo nặng hoặc dùng thêm ca múc nước để tráng rửa. Đây là ưu điểm rất rõ của Vòi bếp dây rút sj-vb3046-sr so với các mẫu vòi cố định thông thường. 2. Vòi rửa bát dây rút bằng inox SUS304 Posco Hàn Quốc Vật liệu là nền tảng tạo nên độ bền của một sản phẩm vòi bếp. Vòi bếp dây rút sj-vb3046-sr sử dụng inox SUS304 của Posco Hàn Quốc, có khả năng chống gỉ, chống ăn mòn và phù hợp với môi trường bếp thường xuyên tiếp xúc với nước, dầu mỡ, muối và chất tẩy rửa. T','["https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-sj-vb3045-sr.png","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-seajong-1.png","https://seajong.com/wp-content/uploads/2025/03/voi-bep-rut-sj-vb3046-sr.png","https://seajong.com/wp-content/uploads/2025/03/voi-bet-day-rut-sj-vb3046-sr-3.png","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-sj-vb3046-sr-5.png","https://seajong.com/wp-content/uploads/2025/03/vb3046-sr-seajong.png","https://seajong.com/wp-content/uploads/2025/03/sj-vb3046-sr.png","https://seajong.com/wp-content/uploads/2025/03/sj-vb3046-sr-7.png","https://seajong.com/wp-content/uploads/2025/03/vb3046-sr-9.png","https://seajong.com/wp-content/uploads/2025/03/sj-vb3046-sr-10.png"]','{"Mã sản phẩm:":"SJ-VB3046-SR","Kích thước (mm):":"420mm","Chất liệu:":"Inox 304 Posco","Bề mặt:":"Chải Hairline","Chiều dài dây rút":"800mm","Tiện ích":"Dây rút tiện lợi với đầu phun 2 chế độ","Áp lực nước khuyến nghị":"0.05 ~ 1.2 Mpa","Trọng lượng":"1900 gram","Xử lý bề mặt":"Brushed Hairline","Lõi trộn":"SEDAL (Tây ban nha)","Điểm khác biệt":"0,01%Pb","Thời gian bảo hành":"5 năm"}',4500000.0,1781256509000,1782619250398,'https://seajong.com/wp-content/uploads/2025/03/SJ-VB3046-SR.webp');
INSERT INTO SeajongProduct VALUES(11244,'voi-bep-day-rut-cao-cap-seajong-sj-vb007p-sr','https://seajong.com/voi-bep-day-rut-cao-cap-seajong-sj-vb007p-sr/','Vòi bếp dây rút cao cấp Seajong SJ-VB007P-SR','Vòi bếp dây rút cao cấp SJ-VB007P-SR mang đến sự tiện nghi tối đa với thiết kế hiện đại, dây rút linh hoạt và đầu phun đa chế độ, giúp việc rửa thực phẩm và vệ sinh chậu bếp trở nên dễ dàng hơn bao giờ hết. Tính năng công nghệ Dây rút linh hoạt: [&hellip;]','Vòi bếp dây rút cao cấp SJ-VB007P-SR mang đến sự tiện nghi tối đa với thiết kế hiện đại, dây rút linh hoạt và đầu phun đa chế độ, giúp việc rửa thực phẩm và vệ sinh chậu bếp trở nên dễ dàng hơn bao giờ hết. Tính năng công nghệ Dây rút linh hoạt : Dây cấp nước silicon cao cấp có thể xoay 360 độ, giúp mở rộng phạm vi sử dụng, dễ dàng thao tác ở mọi góc độ. Ba chế độ phun nước : Tùy chỉnh linh hoạt giữa chế độ tăng áp, xịt rửa và tạo bọt, đáp ứng mọi nhu cầu sử dụng trong bếp. Chất liệu bền bỉ, an toàn : Thân vòi làm từ đồng cao cấp kết hợp với lớp mạ niken, PVD sáng bóng, bền đẹp và chống ăn mòn. Van trộn nước chất lượng cao : Sử dụng lõi van SEDAL từ Tây Ban Nha, có độ bền vượt trội với tuổi thọ lên đến 600.000 lần đóng mở. Bảo vệ sức khỏe : Chất liệu đồng chứa 61% không có hàm lượng chì, đảm bảo an toàn cho nguồn nước sinh hoạt. Xử lý bề mặt cao cấp : Công nghệ mạ PVD giúp tăng độ bền, chống trầy xước và giữ vẻ đẹp lâu dài. Đã thử nghiệm sương muối 72 giờ liên tục để kiểm chứng độ bền. Vòi bếp dây rút cao cấp SJ-VB007P-SR không chỉ giúp công việc bếp núc trở nên nhẹ nhàng hơn mà còn là điểm nhấn hiện đại, sang trọng cho không gian bếp. Đặt hàng ngay hôm nay để trải nghiệm sự khác biệt! ⇒Xem thêm các mẫu vòi bếp khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/03/SJ-VB007P-SR.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf007p.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf007p-2.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf007p-3.webp","https://seajong.com/wp-content/uploads/2025/03/voi-bep-day-rut-cao-cap-sj-kf007p-4.webp"]','{"Mã sản phẩm:":"SJ-VB007P-SR","Kích thước (mm):":"Chiều cao: 420mm","Phiên bản":"Dây rút","Chiều dài dây rút":"800mm","Tiện ích":"Dây rút tiện lợi với đầu phun 3 chế độ","Màu sắc":"màu Chrome","Trọng lượng":"1900 gram","Xử lý bề mặt":"Đánh bóng, Mạ niken và PVD","Lõi trộn":"SEDAL (Tây ban nha)"}',7200000.0,1779069341000,1782619250396,'https://seajong.com/wp-content/uploads/2025/03/SJ-VB007P-SR.webp');
INSERT INTO SeajongProduct VALUES(11656,'bon-cau-trung-men-su-nano-cao-cap-sj-662','https://seajong.com/bon-cau-trung-men-su-nano-cao-cap-sj-662/','Bồn cầu trứng men sứ Nano cao cấp Seajong SJ-662','Bồn cầu Seajong SJ-662 với thiết kế bo tròn mềm mại, tích hợp tay vịn khoa học và nắp đóng giảm chấn, mang lại trải nghiệm thoải mái và an toàn cho người sử dụng. Tính năng công nghệ của bồn cầu trứng men sứ Thiết kế tiện ích: Kiểu dáng trứng bo tròn kết [&hellip;]','Bồn cầu Seajong SJ-662 với thiết kế bo tròn mềm mại, tích hợp tay vịn khoa học và nắp đóng giảm chấn, mang lại trải nghiệm thoải mái và an toàn cho người sử dụng. Tính năng công nghệ của bồn cầu trứng men sứ Thiết kế tiện ích: Kiểu dáng trứng bo tròn kết hợp tay vịn được thiết kế khoa học, hỗ trợ người dùng dễ dàng ngồi xuống và đứng lên, đặc biệt hữu ích cho người cao tuổi và trẻ nhỏ. Nắp đóng giảm chấn: Nắp và bệ ngồi bằng nhựa UF chất lượng cao, tích hợp cơ chế đóng êm ái, giảm tiếng ồn và tăng tuổi thọ sản phẩm. Công nghệ xả đa điểm: Hệ thống xả mạnh mẽ với dung tích 5L (mỗi lần xả 4.8L), đảm bảo làm sạch hiệu quả và tiết kiệm nước. Chất liệu cao cấp: Thân bồn cầu bằng gốm sứ phủ men Nano Bạc kháng khuẩn, giúp ngăn ngừa vi khuẩn và giữ bề mặt luôn sáng bóng. Nếu bạn đang có nhu cầu và tìm kiếm nơi mua hàng bồn cầu trứng men sứ chính hãng, hãy liên hệ với chúng tôi để được hỗ trợ và tư vấn tận tình nhất. ⇒Xem thêm các mẫu bồn cầu khác của Seajong ngay⇒','["https://seajong.com/wp-content/uploads/2025/04/bon-cau-trung-men-su-nano-cao-cap-sj-662.webp","https://seajong.com/wp-content/uploads/2025/04/bon-cau-trung-men-su-nano-cao-cap-sj-662-4.webp"]','{"Mã sản phẩm:":"SJ-662","Chất liệu:":"Chất liệu thân: Gốm sứ phủ men Nano Bạc kháng khuẩn / Nút xả: Nhựa PP mạ bạc / Nắp và bệ ngồi: Nhựa UF bền, chịu lực tốt","Tiện ích":"Bồn cầu trứng bo tròn mềm mại, thiết kế tay vịn khoa học, nắp đóng giảm chấn","Kiểu xả":"Xả đa điểm, xả đẩy đáy","Lượng xả":"5L (1 lần xả 4.8L)","Tải trọng tối đa":"300kg"}',6950000.0,1778208718000,1782619250333,'https://seajong.com/wp-content/uploads/2025/04/bon-cau-trung-men-su-nano-cao-cap-sj-662.webp');
INSERT INTO SeajongProduct VALUES(11970,'bon-cau-thong-minh-seajong-sj-m9d','https://seajong.com/bon-cau-thong-minh-seajong-sj-m9d/','Bồn cầu thông minh Seajong SJ-M9D','Bồn cầu thông minh Seajong SJ-M9D là sản phẩm cao cấp, tích hợp công nghệ hiện đại, mang đến trải nghiệm vệ sinh tiện nghi và an toàn. Với thiết kế sang trọng, hệ thống xả mạnh mẽ cùng các tính năng thông minh, sản phẩm là lựa chọn lý tưởng cho không gian phòng [&hellip;]','Bồn cầu thông minh Seajong SJ-M9D là sản phẩm cao cấp, tích hợp công nghệ hiện đại, mang đến trải nghiệm vệ sinh tiện nghi và an toàn. Với thiết kế sang trọng, hệ thống xả mạnh mẽ cùng các tính năng thông minh, sản phẩm là lựa chọn lý tưởng cho không gian phòng tắm hiện đại. Tính năng công nghệ Cảm biến tự động: Mở nắp và xả nước bằng cảm biến đá chân, giúp sử dụng dễ dàng và vệ sinh hơn. Điều khiển linh hoạt: Thao tác tiện lợi qua remote hoặc nút xoay bên hông. Vòi xịt đa chế độ: Bao gồm rửa sau, rửa phụ nữ, rửa massage, chế độ bệ ngồi cho bé, và chức năng tự làm sạch vòi. Hệ thống xả trực tiếp siêu mạnh + xả phản lực: Loại bỏ hoàn toàn vết bẩn, tiết kiệm nước hiệu quả. Điều chỉnh áp lực nước và vị trí vòi rửa: Phù hợp với nhu cầu cá nhân, tăng cảm giác thoải mái. Chế độ sấy khô khí ấm: Có 4 mức nhiệt độ sấy (38°C – 45°C – 55°C), giúp khô ráo nhanh chóng. Màn hình LED hiển thị thông số nhiệt độ: Theo dõi và điều chỉnh dễ dàng. Đèn LED ban đêm: Hỗ trợ sử dụng trong điều kiện thiếu sáng. Tia UV khử khuẩn: Giữ bồn cầu sạch khuẩn, đảm bảo an toàn sức khỏe. Nắp đóng giảm chấn & lớp bọt chống bắn nước: Hạn chế tiếng ồn, tránh bắn nước ra ngoài. Thiết kế chống rò rỉ, chống cháy nổ: Đạt tiêu chuẩn chống nước IPX4, đảm bảo an toàn tuyệt đối. Hỗ trợ pin dự phòng & chức năng xả khi mất điện: Giúp duy trì hoạt động ngay cả khi mất điện','["https://seajong.com/wp-content/uploads/2025/05/SJ-M9D.webp"]','{"Mã sản phẩm:":"SJ-M9D","Kiểu dáng:":"Smart","Kích thước (mm):":"680 × 390 × 450 (mm)","Chất liệu:":"Gốm Sứ, phủ men Nano Bạc kháng khuẩn","Lượng xả":"5L","Chế độ xả":"Xả xoáy siêu mạnh kết hợp xả phản lực","Tải trọng tối đa":"300kg","Cảm biến đá chân":"Có","Remote điều khiển từ xa":"Có","Tâm hố":"90-114mm","Nhiệt độ bệ ngồi":"4 mức (Trung bình – 34°C – 37°C – 40°C)","Nhiệt độ sấy":"4 mức (Trung bình – 38°C – 45°C – 55°C)","Nguồn điện":"220V - 50Hz","Cảm biến":"Cảm biến lật, đá chân, xả"}',23400000.0,1778211397000,1782200023538,'https://seajong.com/wp-content/uploads/2025/05/SJ-M9D.webp');
INSERT INTO SeajongProduct VALUES(12007,'bon-cau-lien-khoi-men-su-sj-bc0189b','https://seajong.com/bon-cau-lien-khoi-men-su-sj-bc0189b/','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0189B','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0189B là mẫu bồn cầu liền khối cao cấp, sở hữu thiết kế gọn gàng, tinh tế, phù hợp với mọi phong cách phòng tắm hiện đại. Sản phẩm kết hợp công nghệ xả tiên tiến cùng lớp men Nano bạc kháng khuẩn, mang đến trải [&hellip;]','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0189B là mẫu bồn cầu liền khối cao cấp, sở hữu thiết kế gọn gàng, tinh tế, phù hợp với mọi phong cách phòng tắm hiện đại. Sản phẩm kết hợp công nghệ xả tiên tiến cùng lớp men Nano bạc kháng khuẩn, mang đến trải nghiệm tiện nghi, sang trọng và an toàn cho sức khỏe gia đình. Mục Lục Toggle Tính năng công nghệ Một số câu hỏi thường gặp về bồn cầu Seajong SJ-BC0189B Liên hệ mua hàng chính hãng tại Seajong Tính năng công nghệ Kiểu dáng liền khối tinh gọn cùng kích thước tiêu chuẩn 590x365x710mm, giúp tối ưu không gian, tạo điểm nhấn sang trọng trong không gian phòng tắm. Bề mặt phủ men Nano bạc kháng khuẩn ngăn ngừa vi khuẩn phát triển, chống bám bẩn, ngăn vết ố cho bề mặt bồn cầu luôn sáng bóng, dễ vệ sinh và an toàn cho sức khỏe người dùng. Thân bồn cầu gốm sứ cao cấp nung ở nhiệt độ 1320°C với công nghệ Vitrified, tạo nên cấu trúc đồng nhất, siêu bền, chống thấm nước tuyệt đối. Công nghệ xả kép Dual Flush 360°, lực xoáy toàn diện kết hợp xả đẩy mạnh mẽ, cuốn trôi chất thải chỉ trong một lần xả. Hai chế độ (3L – tiểu tiện, 6L – đại tiện) giúp tiết kiệm nước tối đa mà vẫn duy trì khả năng làm sạch vượt trội. Nắp xả UF cao cấp thiết kế đóng êm, hạn chế tối đa tiếng ồn, mang lại sự thoải mái và yên tĩnh khi sử dụng. Bộ xả nhập khẩu Tây Ban Nha có độ bền cao, lực xả mạnh mẽ, nâng cao khả năng tiết kiệm nước, gia tăng tuổi thọ sản phẩm. Một số câu hỏi thường gặp về bồn cầu Seajong SJ-BC0189B Bồn cầu Seajong SJ-BC0189B có tiết kiệm nước không? Có . Nhờ chế độ xả kép 3L/6L, sản phẩm giúp giảm lượng nước sử dụng mà vẫn đảm bảo hiệu quả cuốn trôi chất thải vượt trội. Bồn cầu Seajong SJ-BC0189B có bám bẩn và chống xước không? Có . Lớp men Nano bạc kháng khuẩn giúp hạn chế bám bẩn, chống trầy xước và giữ bề mặt luôn sáng bóng lâu dài. Lắp đặt bồn cầu Seajong SJ-BC0189B có phức tạp không? Không . Với thiết kế thông minh và phụ kiện chuẩn đi kèm, việc lắp đặt vô cùng đơn giản, bạn hoàn toàn có thể tự thực hiện lắp đặt hoặc nhờ thợ c','["https://seajong.com/wp-content/uploads/2025/05/SJ-BC0189B-1.webp","https://seajong.com/wp-content/uploads/2025/05/SJ-BC0189B-2.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-2.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-7.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-8.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-10.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-13.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-14.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0189B-15.webp"]','{"Mã sản phẩm:":"SJ-BC0189B","Kích thước (mm):":"590 x 365 x 710 (mm)","Chất liệu:":"Sứ phủ men nano kháng khuẩn","Công nghệ nung":"Áp dụng công nghệ Vitrified 1320°C đốt tuần hoàn","Tiện ích":"Bộ xả: Dual Flush của Tây Ban Nha","Kiểu xả":"Xả xoáy & Xả đẩy đáy","Lượng xả":"9L (xả tiểu 3L, xả đại 6L)","Tải trọng tối đa":"300kg","Tâm hố":"300mm"}',8900000.0,1779069584000,1782619250394,'https://seajong.com/wp-content/uploads/2025/05/SJ-BC0189B-1.webp');
INSERT INTO SeajongProduct VALUES(12015,'bon-cau-lien-khoi-men-su-sj-bc0198b','https://seajong.com/bon-cau-lien-khoi-men-su-sj-bc0198b/','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0198B','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0198B là dòng bồn cầu liền khối cao cấp với thiết kế thanh thoát, hiện đại, phù hợp hoàn hảo cho không gian phòng tắm sang trọng. Sản phẩm được trang bị công nghệ xả tiên tiến kết hợp lớp men Nano bạc kháng khuẩn, vừa [&hellip;]','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0198B là dòng bồn cầu liền khối cao cấp với thiết kế thanh thoát, hiện đại, phù hợp hoàn hảo cho không gian phòng tắm sang trọng. Sản phẩm được trang bị công nghệ xả tiên tiến kết hợp lớp men Nano bạc kháng khuẩn, vừa đảm bảo vệ sinh tối ưu vừa mang lại trải nghiệm sử dụng tiện nghi, an toàn cho sức khỏe. Mục Lục Toggle Tính năng công nghệ Một số câu hỏi thường gặp về bồn cầu Seajong SJ-BC0198B Liên hệ mua hàng chính hãng tại Seajong Tính năng công nghệ Công nghệ xả kép Dual Flush 360° kết hợp lực xoáy toàn diện và xả đẩy sạch, giúp loại bỏ chất thải nhanh chóng chỉ trong một lần xả. Hai chế độ riêng biệt (3L cho tiểu tiện, 6L cho đại tiện) mang đến hiệu quả tiết kiệm nước tối đa mà vẫn duy trì khả năng làm sạch vượt trội. Bề mặt phủ men Nano bạc kháng khuẩn giúp ngăn ngừa vi khuẩn phát triển, chống bám bẩn, ngăn vết giữ cho bồn cầu luôn sáng bóng, dễ vệ sinh và an toàn cho sức khỏe người dùng. Thân bồn cầu gốm sứ cao cấp nung ở nhiệt độ 1320°C với công nghệ Vitrified, tạo nên cấu trúc đồng nhất, siêu bền, chống thấm nước tuyệt đối. Nắp xả UF cao cấp thiết kế đóng êm, hạn chế tối đa tiếng ồn, mang lại sự thoải mái và yên tĩnh khi sử dụng. Bộ xả nhập khẩu Tây Ban Nha có độ bền cao, lực xả mạnh mẽ, vừa gia tăng tuổi thọ sản phẩm vừa nâng cao khả năng tiết kiệm nước. Kiểu dáng liền khối tinh gọn cùng kích thước tiêu chuẩn 650x430x630mm, giúp tiết kiệm diện tích, trở thành điểm nhấn sang trọng trong mọi không gian phòng tắm. Một số câu hỏi thường gặp về bồn cầu Seajong SJ-BC0198B Lắp đặt bồn cầu Seajong SJ-BC0198B có khó không? Hoàn toàn không . Với thiết kế thông minh và phụ kiện chuẩn đi kèm, việc lắp đặt vô cùng đơn giản, bạn có thể tự thực hiện hoặc nhờ thợ chuyên nghiệp để đảm bảo đúng kỹ thuật. Bồn cầu Seajong SJ-BC0198B có tiết kiệm nước không? Có . Với dung tích 3L/6L, bồn cầu SJ-BC0198B giúp tiết kiệm nước đáng kể mà vẫn duy trì hiệu quả làm sạch hoàn hảo. Bồn cầu Seajong SJ-BC0198B có bám bẩn và chống xước khôn','["https://seajong.com/wp-content/uploads/2025/05/SJ-BC0198B-3.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-2.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-4.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-7.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-8.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-9.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-11.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-14.webp","https://seajong.com/wp-content/uploads/2025/05/bon-cau-seajong-SJ-BC0198B-15.webp"]','{"Mã sản phẩm:":"SJ-BC0198B","Kích thước (mm):":"650 x 430 x 630mm","Chất liệu:":"Sứ phủ men nano kháng khuẩn","Công nghệ nung":"Áp dụng công nghệ Vitrified 1320°C đốt tuần hoàn","Tiện ích":"Bộ xả: Dual Flush của Tây Ban Nha","Màu sắc":"Trắng, Xám nhạt","Lượng xả":"9L (xả tiểu 3L, xả đại 6L)","Chế độ xả":"Xả xoáy 360 & xả đẩy đáy","Tải trọng tối đa":"300kg","Tâm hố":"300mm"}',10000000.0,1779070013000,1782619250320,'https://seajong.com/wp-content/uploads/2025/05/SJ-BC0198B-3.webp');
INSERT INTO SeajongProduct VALUES(12068,'bon-cau-lien-khoi-men-su-sj-bc0184b','https://seajong.com/bon-cau-lien-khoi-men-su-sj-bc0184b/','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0184B','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0184B là mẫu bồn cầu liền khối cao cấp được thiết kế tinh gọn với đường nét thanh thoát, hiện đại. Sản phẩm ứng dụng công nghệ xả tiên tiến kết hợp lớp men Nano bạc kháng khuẩn, vừa nâng cao trải nghiệm sử dụng vừa [&hellip;]','Bồn cầu liền khối men sứ kháng khuẩn Seajong SJ-BC0184B là mẫu bồn cầu liền khối cao cấp được thiết kế tinh gọn với đường nét thanh thoát, hiện đại. Sản phẩm ứng dụng công nghệ xả tiên tiến kết hợp lớp men Nano bạc kháng khuẩn, vừa nâng cao trải nghiệm sử dụng vừa đảm bảo an toàn cho sức khỏe. Với kiểu dáng sang trọng và tính năng vượt trội, bồn cầu Seajong SJ-BC0184B trở thành lựa chọn hoàn hảo cho những phòng tắm đề cao sự tiện nghi và tính thẩm mỹ. Mục Lục Toggle Tính năng công nghệ Một số câu hỏi thường gặp về bồn cầu Seajong SJ-BC0184B Liên hệ mua hàng chính hãng tại Seajong Tính năng công nghệ Công nghệ xả thẳng & xả đẩy đáy mạnh mẽ cho lực xả toàn diện giúp cuốn trôi chất thải nhanh chóng chỉ với một lần xả. Với dung tích xả 5L tiêu chuẩn, sản phẩm vừa đảm bảo hiệu quả làm sạch vừa tiết kiệm nước tối đa Bề mặt phủ men Nano bạc kháng khuẩn giúp ngăn ngừa vi khuẩn và nấm mốc, hạn chế bám bẩn, chống vết ố, giúp bồn cầu luôn sáng bóng, dễ vệ sinh và an toàn cho sức khỏe Thân bồn cầu từ gốm sứ cao cấp được nung ở nhiệt độ cao, tạo độ cứng chắc, bền bỉ và chịu tải trọng lên đến 300kg, đảm bảo độ an toàn và tuổi thọ lâu dài Nắp xả UF cao cấp với thiết kế đóng êm giúp hạn chế tiếng ồn, mang đến cảm giác thoải mái và yên tĩnh khi sử dụng Kiểu dáng liền khối tinh gọn, đường nét hài hòa và kích thước tiêu chuẩn 690x380x620mm, bồn cầu Seajong SJ-BC0184B vừa tiết kiệm diện tích vừa tạo điểm nhấn sang trọng cho không gian phòng tắm Một số câu hỏi thường gặp về bồn cầu Seajong SJ-BC0184B Vì khách hàng luôn đưa ra những thắc mắc để đảm bảo rằng mọi sản phẩm khi lựa chọn đểu đạt chuẩn và sử dụng được bền bỉ. Dưới đây Seajong sẽ tổng hợp một vài câu hỏi giúp bạn hiểu về sản phẩm hơn. Lắp đặt bồn cầu Seajong SJ-BC0184B có khó không? Không . Với thiết kế thông minh và phụ kiện chuẩn đi kèm, việc lắp đặt bồn cầu Seajong SJ-BC0184B rất đơn giản. Bạn hoàn toàn có thể tự lắp đặt hoặc nhờ thợ chuyên nghiệp để đảm bảo đúng kỹ thuật. Bồn cầu Seajong SJ-BC0184B có tiết kiệm nước không? ','["https://seajong.com/wp-content/uploads/2025/05/SJ-BC0184B-2.webp"]','{"Mã sản phẩm:":"SJ-BC0184B","Kích thước (mm):":"690 x 380 x 620mm","Chất liệu:":"Sứ phủ men nano","Kiểu xả":"Xả thẳng & xả đẩy đáy","Lượng xả":"5L","Tải trọng tối đa":"300kg","Tâm hố":"300mm","Chất liệu nắp":"UF, đóng êm không gây tiếng ồn"}',12950000.0,1778207976000,1782619250420,'https://seajong.com/wp-content/uploads/2025/05/SJ-BC0184B-2.webp');
