INSERT INTO SeajongProduct VALUES(16302,'ga-thoat-san-sus304-cao-cap-sj-g1032p','https://seajong.com/ga-thoat-san-sus304-cao-cap-sj-g1032p/','Ga thoát sàn SUS304 cao cấp SJ-G1032P','Ga thoát sàn SJ-G1032P là phiên bản nâng cấp với bề mặt mạ titan cao cấp, kết hợp thiết kế cắt đá âm sàn giúp “ẩn” hoàn toàn ga thoát nước, mang lại tổng thể liền mạch, sang trọng và đậm chất kiến trúc hiện đại. Ga thoát sàn SJ-G1032P với lớp phủ titan đen [&hellip;]','Ga thoát sàn SJ-G1032P là phiên bản nâng cấp với bề mặt mạ titan cao cấp, kết hợp thiết kế cắt đá âm sàn giúp “ẩn” hoàn toàn ga thoát nước, mang lại tổng thể liền mạch, sang trọng và đậm chất kiến trúc hiện đại. Ga thoát sàn SJ-G1032P với lớp phủ titan đen và thiết kế cắt đá cho phép đặt trực tiếp vật liệu sàn lên bề mặt nắp, giúp ga thoát sàn “biến mất” trong tổng thể. Đây là xu hướng thiết kế phổ biến trong các công trình cao cấp, nơi mọi chi tiết đều được tối ưu để đạt sự tinh gọn và đồng nhất. Ga thoát sàn SUS304 cao cấp SJ-G1032P- Tổng quan về sản phẩm','["https://seajong.com/wp-content/uploads/2025/11/SJ-G1032P.webp","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-4.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-6.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-7.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-11.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-12.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-13.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1032P-10.png"]','{"Mã sản phẩm:":"SJ-G1032P","Kiểu dáng:":"Cắt đá (tile insert)","Kích thước (mm):":"100*100*125 (mm)","Kích thước lỗ thoát:":"Ø50 / Ø60 / Ø76 mm","Chất liệu:":"Inox 304","Bề mặt:":"Titan đen cao cấp","Thời gian bảo hành":"10 Năm"}',780000.0,1779170633000,1782619232666,'https://seajong.com/wp-content/uploads/2025/11/SJ-G1032P.webp');
INSERT INTO SeajongProduct VALUES(16305,'ga-thoat-san-sus304-cao-cap-sj-g1231m','https://seajong.com/ga-thoat-san-sus304-cao-cap-sj-g1231m/','Ga thoát sàn SUS304 cao cấp SJ-G1231M','Ga thoát sàn SUS304 cao cấp SJ-1231M là giải pháp ngăn mùi và thoát nước đỉnh cao cho không gian hiện đại, sở hữu các thông số vượt trội: Chất liệu đẳng cấp: 100% Inox SUS304 cao cấp từ tập đoàn POSCO Hàn Quốc – Chống rỉ sét vĩnh viễn. Độ bền cơ khí: Tấm mặt siêu dày 3.0mm, dập nguyên khối bằng máy thủy lực 20.000 tấn và hàn Robot không dấu vết. Bề mặt tinh xảo: Xử lý chải xước Hairline bằng Robot tinh tế, chống trầy xước và bám bẩn. Công nghệ ngăn mùi: Cơ chế Bẫy nước (Water Trap) thông minh – ','Ga thoát sàn Seajong SJ-1231M không chỉ là một phụ kiện nhà tắm thông thường mà là một tác phẩm cơ khí chính xác. Với thiết kế hiện đại, tinh tế và kích thước chuẩn 120x120mm, sản phẩm là lựa chọn hàng đầu cho các không gian nhà tắm, khu vực giặt giũ hoặc ban công, nơi yêu cầu sự kết hợp hoàn hảo giữa thẩm mỹ và công năng thoát nước mạnh mẽ. Ga thoát sàn SUS304 cao cấp SJ-G1231M','["https://seajong.com/wp-content/uploads/2025/11/SJ-G1231M.webp","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M-1.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M-2.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M-3-1.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M-10.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M-6.png","https://seajong.com/wp-content/uploads/2025/11/Ga-thoat-san-SUS304-cao-cap-SJ-G1231M-9.png"]','{"Mã sản phẩm:":"SJ-G1231M","Kích thước (mm):":"120*120*125 (mm)","Kích thước lỗ thoát:":"Ø60/Ø76/Ø90mm","Độ dày (mm):":"3mm","Chất liệu:":"Inox SUS 304 Posco","Bề mặt:":"Chải Hairline","Chiều dài":"120mm","Chiề